const DECK_DATA = {"anatomy":[{"id":"a1","subject":"anatomy","topic":"Germ Layers","q":"Name the three primary germ layers of the embryo.","a":"Ectoderm, mesoderm and endoderm.","img":null,"pyq":false},{"id":"a2","subject":"anatomy","topic":"Germ Layers","q":"Which germ layer gives rise to the urogenital system?","a":"Intermediate mesoderm (kidneys, gonads, genital ducts).","img":null,"pyq":false},{"id":"a3","subject":"anatomy","topic":"Mesoderm","q":"What are the three subdivisions of mesoderm?","a":"Paraxial, intermediate and lateral plate mesoderm.","img":null,"pyq":false},{"id":"a4","subject":"anatomy","topic":"Somites","q":"Name the three somite derivatives and what each forms.","a":"Myotome (skeletal muscle), dermatome (dermis of back), sclerotome (axial skeleton).","img":null,"pyq":false},{"id":"a5","subject":"anatomy","topic":"Lateral Plate Mesoderm","q":"What splits lateral plate mesoderm into its two layers?","a":"The intra-embryonic coelom, forming somatopleuric and splanchnopleuric LPM.","img":null,"pyq":false},{"id":"a6","subject":"anatomy","topic":"Somatopleuric LPM","q":"What does somatopleuric lateral plate mesoderm form?","a":"Dermis of the front of the body and limbs, plus the appendicular skeleton.","img":null,"pyq":false},{"id":"a7","subject":"anatomy","topic":"Splanchnopleuric LPM","q":"What does splanchnopleuric lateral plate mesoderm form?","a":"Cardiac muscle and most smooth muscle.","img":null,"pyq":false},{"id":"a8","subject":"anatomy","topic":"Smooth Muscle Origin","q":"Which smooth muscles are derived from neural crest cells?","a":"Smooth muscle of the ascending aorta, pulmonary trunk, coronary arteries, and the ciliaris muscle.","img":null,"pyq":false},{"id":"a9","subject":"anatomy","topic":"Smooth Muscle Origin","q":"Which germ layer forms the sphincter and dilator pupillae?","a":"Neuroectoderm.","img":null,"pyq":false},{"id":"a10","subject":"anatomy","topic":"Smooth Muscle Origin","q":"Origin of myoepithelial smooth muscle of sweat and mammary glands?","a":"Ectoderm.","img":null,"pyq":false},{"id":"a11","subject":"anatomy","topic":"Neural Tube","q":"How is the neural tube induced to form?","a":"Ectoderm is stimulated (induced) by the underlying notochord.","img":null,"pyq":false},{"id":"a12","subject":"anatomy","topic":"Notochord","q":"Name the three adult remnants of the notochord.","a":"Apical ligament of the dens, nucleus pulposus, and the tectorial membrane.","img":null,"pyq":false},{"id":"a13","subject":"anatomy","topic":"Neural Tube","q":"List the CNS cells derived from the neural tube.","a":"Neurons, oligodendrocytes, astrocytes, ependymal cells, and retina.","img":null,"pyq":false},{"id":"a14","subject":"anatomy","topic":"Neuroglia","q":"Which cell myelinates axons in the CNS?","a":"Oligodendrocytes (Schwann cells do so in the PNS).","img":null,"pyq":false},{"id":"a15","subject":"anatomy","topic":"Neuroglia","q":"Which CNS cell contributes to the blood-brain barrier?","a":"Astrocytes.","img":null,"pyq":false},{"id":"a16","subject":"anatomy","topic":"Neuroglia","q":"Which cells line the cerebral ventricles?","a":"Ependymal cells.","img":null,"pyq":false},{"id":"a17","subject":"anatomy","topic":"Neural Crest","q":"Where are neural crest cells located?","a":"At the junction of the neural tube and surface ectoderm.","img":null,"pyq":false},{"id":"a18","subject":"anatomy","topic":"Neural Crest","q":"List the PNS derivatives of neural crest cells.","a":"All ganglia, enteric plexus, Schwann cells, adrenal medulla, parafollicular C-cells and melanocytes.","img":null,"pyq":false},{"id":"a19","subject":"anatomy","topic":"Neural Crest","q":"Give the head and neck derivatives of neural crest cells.","a":"Most skull bones, dentine (odontoblasts), pharyngeal arch cartilage, dermis of head/neck, conotruncal septum.","img":null,"pyq":false},{"id":"a20","subject":"anatomy","topic":"Adrenal Gland","q":"Embryological origin of the adrenal cortex vs medulla?","a":"Cortex from intermediate mesoderm; medulla from neural crest cells.","img":null,"pyq":false},{"id":"a21","subject":"anatomy","topic":"Intervertebral Disc","q":"Name the two parts of the intervertebral disc.","a":"Outer annulus fibrosus and central nucleus pulposus.","img":null,"pyq":false},{"id":"a22","subject":"anatomy","topic":"Diaphragm","q":"Which structure forms the central tendon of the diaphragm?","a":"The septum transversum.","img":null,"pyq":false},{"id":"a23","subject":"anatomy","topic":"Diaphragm","q":"The crura of the diaphragm develop from?","a":"The dorsal mesentery of the oesophagus.","img":null,"pyq":false},{"id":"a24","subject":"anatomy","topic":"Diaphragm","q":"Which membrane closes the pericardioperitoneal canal?","a":"The pleuroperitoneal membrane.","img":null,"pyq":false},{"id":"a25","subject":"anatomy","topic":"Diaphragm","q":"Cause, side and complication of congenital diaphragmatic hernia?","a":"Absent pleuroperitoneal membrane (Bochdalek); left > right; lung hypoplasia.","img":null,"pyq":false},{"id":"a26","subject":"anatomy","topic":"Diaphragm","q":"What is the Bochdalek foramen?","a":"A persistent pleuroperitoneal canal allowing herniation of abdominal viscera.","img":null,"pyq":false},{"id":"a27","subject":"anatomy","topic":"Pharyngeal Arch","q":"Describe the three-layer composition of a pharyngeal arch.","a":"Mesodermal core, lined externally by ectoderm and internally by endoderm.","img":null,"pyq":true},{"id":"a28","subject":"anatomy","topic":"Pharyngeal Cleft","q":"Which pharyngeal cleft persists and what does it form?","a":"Only the 1st cleft persists, forming the external auditory canal and outer tympanic membrane.","img":null,"pyq":false},{"id":"a29","subject":"anatomy","topic":"Cervical Sinus","q":"How does the cervical sinus form and what happens to it?","a":"From 2nd-arch ectoderm overgrowth; it normally obliterates clefts 2-4.","img":null,"pyq":false},{"id":"a30","subject":"anatomy","topic":"Branchial Cyst","q":"What is a branchial cyst?","a":"A persistent cervical sinus presenting as a swelling along the sternocleidomastoid.","img":null,"pyq":false},{"id":"a31","subject":"anatomy","topic":"Pharyngeal Pouch","q":"Derivatives of the 1st pharyngeal pouch?","a":"Tympanic cavity, auditory tube, mastoid antrum, and inner layer of the tympanic membrane.","img":null,"pyq":false},{"id":"a32","subject":"anatomy","topic":"Pharyngeal Pouch","q":"Derivative of the 2nd pharyngeal pouch?","a":"The palatine tonsil.","img":null,"pyq":false},{"id":"a33","subject":"anatomy","topic":"Pharyngeal Pouch","q":"Derivatives of the 3rd pharyngeal pouch?","a":"Thymus and the inferior parathyroid glands.","img":null,"pyq":false},{"id":"a34","subject":"anatomy","topic":"Pharyngeal Pouch","q":"Derivative of the 4th pharyngeal pouch?","a":"The superior parathyroid glands.","img":null,"pyq":false},{"id":"a35","subject":"anatomy","topic":"Pharyngeal Pouch","q":"What does the 5th pouch remnant form?","a":"The ultimobranchial body (origin of thyroid C-cells).","img":null,"pyq":false},{"id":"a36","subject":"anatomy","topic":"DiGeorge Syndrome","q":"Pouch defect, genetics and features of DiGeorge syndrome?","a":"Anomaly of 3rd > 4th pouch; 22q11 deletion; absent thymus and hypoparathyroidism.","img":null,"pyq":false},{"id":"a37","subject":"anatomy","topic":"Pharyngeal Arch","q":"First arch (Meckel's) cartilage derivatives?","a":"Malleus, incus and the mandible.","img":null,"pyq":true},{"id":"a38","subject":"anatomy","topic":"Pharyngeal Arch","q":"Second arch cartilage derivatives?","a":"Stapes (except footplate), styloid process, stylohyoid ligament, lesser cornu and upper hyoid body.","img":null,"pyq":true},{"id":"a39","subject":"anatomy","topic":"Pharyngeal Arch","q":"Origin of the stapes footplate?","a":"The otic capsule (not the 2nd arch).","img":null,"pyq":true},{"id":"a40","subject":"anatomy","topic":"Pharyngeal Arch","q":"Third arch cartilage derivatives?","a":"Greater cornu and lower part of the body of the hyoid.","img":null,"pyq":true},{"id":"a41","subject":"anatomy","topic":"Pharyngeal Arch","q":"Derivatives of the 4th and 6th arch cartilages?","a":"The laryngeal cartilages.","img":null,"pyq":true},{"id":"a42","subject":"anatomy","topic":"Aortic Arch Arteries","q":"Derivative of the 1st aortic arch artery?","a":"The maxillary artery.","img":null,"pyq":true},{"id":"a43","subject":"anatomy","topic":"Aortic Arch Arteries","q":"Derivative of the 3rd aortic arch artery?","a":"Common carotid and proximal internal carotid artery.","img":null,"pyq":true},{"id":"a44","subject":"anatomy","topic":"Aortic Arch Arteries","q":"Fate of the left vs right 4th aortic arch artery?","a":"Left forms the arch of the aorta; right forms the proximal right subclavian.","img":null,"pyq":true},{"id":"a45","subject":"anatomy","topic":"Aortic Arch Arteries","q":"Derivatives of the 6th aortic arch artery?","a":"Left: proximal pulmonary artery + ductus arteriosus; right: right pulmonary artery.","img":null,"pyq":true},{"id":"a46","subject":"anatomy","topic":"Recurrent Laryngeal N.","q":"Why is the left recurrent laryngeal nerve longer?","a":"It hooks under the 6th arch derivative (ligamentum arteriosum/arch of aorta), taking a longer course.","img":null,"pyq":true},{"id":"a47","subject":"anatomy","topic":"Recurrent Laryngeal N.","q":"Around what does the right recurrent laryngeal nerve hook?","a":"The right subclavian artery (right 4th arch).","img":null,"pyq":true},{"id":"a48","subject":"anatomy","topic":"Dysphagia Lusoria","q":"What causes dysphagia lusoria?","a":"An aberrant right subclavian artery from obliteration of the right 4th arch with a persistent caudal right dorsal aorta.","img":null,"pyq":true},{"id":"a49","subject":"anatomy","topic":"Venous Development","q":"The SVC is derived from which embryonic veins?","a":"Right anterior cardinal vein plus the right common cardinal vein.","img":null,"pyq":true},{"id":"a50","subject":"anatomy","topic":"Venous Development","q":"Origin of the azygos vein?","a":"Right supracardinal vein joined to the right posterior cardinal vein.","img":null,"pyq":true},{"id":"a51","subject":"anatomy","topic":"Venous Development","q":"The gonadal veins arise from which embryonic vein?","a":"The caudal part of the subcardinal vein.","img":null,"pyq":true},{"id":"a52","subject":"anatomy","topic":"Mesogastrium","q":"List the derivatives of the ventral mesogastrium.","a":"Falciform, coronary and triangular ligaments, and the lesser omentum.","img":null,"pyq":true},{"id":"a53","subject":"anatomy","topic":"Mesogastrium","q":"List the derivatives of the dorsal mesogastrium.","a":"Gastrophrenic, gastrosplenic and lienorenal ligaments, and the greater omentum.","img":null,"pyq":true},{"id":"a54","subject":"anatomy","topic":"Gut Rotation","q":"Features of non-rotation of the midgut?","a":"Small intestine lies on the right, large intestine on the left.","img":null,"pyq":true},{"id":"a55","subject":"anatomy","topic":"Gut Rotation","q":"What is seen in mixed rotation of the gut?","a":"A subpyloric caecum held by Ladd bands compressing the duodenum.","img":null,"pyq":true},{"id":"a56","subject":"anatomy","topic":"Gut Rotation","q":"Result of incomplete midgut rotation?","a":"A subhepatic caecum.","img":null,"pyq":true},{"id":"a57","subject":"anatomy","topic":"Abdominal Wall Defects","q":"Omphalocele vs gastroschisis - key difference?","a":"Omphalocele: failure of physiological hernia reduction, covered sac, multiple anomalies. Gastroschisis: lateral folding defect, no covering, usually right of umbilicus.","img":null,"pyq":true},{"id":"a58","subject":"anatomy","topic":"Genital Ducts","q":"What does the genital ridge form?","a":"The gonads - testes in males, ovaries in females.","img":null,"pyq":true},{"id":"a59","subject":"anatomy","topic":"Genital Ducts","q":"Male derivatives of the mesonephric (Wolffian) duct?","a":"Epididymis, vas deferens, seminal vesicle, ejaculatory duct, and trigone.","img":null,"pyq":true},{"id":"a60","subject":"anatomy","topic":"Genital Ducts","q":"Female derivatives of the paramesonephric (Mullerian) duct?","a":"Fallopian tubes, uterus and the upper vagina.","img":null,"pyq":true},{"id":"a61","subject":"anatomy","topic":"Genital Ducts","q":"What is Gartner's duct?","a":"A mesonephric duct remnant in the female, found in the broad ligament.","img":null,"pyq":true},{"id":"a62","subject":"anatomy","topic":"Genital Ducts","q":"Name two paramesonephric remnants in the male.","a":"Appendix of the testis and the prostatic utricle.","img":null,"pyq":true},{"id":"a63","subject":"anatomy","topic":"Diaphragm Openings","q":"Level and contents of the vena caval opening?","a":"T8, in the central tendon; transmits the IVC and right phrenic nerve.","img":null,"pyq":true},{"id":"a64","subject":"anatomy","topic":"Diaphragm Openings","q":"Level and contents of the oesophageal opening?","a":"T10, in the right crus; oesophagus, both vagi, and oesophageal branch of left gastric artery.","img":null,"pyq":true},{"id":"a65","subject":"anatomy","topic":"Diaphragm Openings","q":"Level and contents of the aortic opening?","a":"T12, between the crura; aorta, azygos vein and thoracic duct.","img":null,"pyq":true},{"id":"a66","subject":"anatomy","topic":"Diaphragm Openings","q":"What passes through the foramen of Morgagni?","a":"Superior epigastric vessels.","img":null,"pyq":true},{"id":"a67","subject":"anatomy","topic":"Diaphragm Openings","q":"What lies behind the medial arcuate ligament?","a":"The sympathetic chain.","img":null,"pyq":true},{"id":"a68","subject":"anatomy","topic":"Intercostal Space","q":"Order of the intercostal neurovascular bundle from above down?","a":"Vein, Artery, Nerve (VAN) in the costal groove.","img":null,"pyq":false},{"id":"a69","subject":"anatomy","topic":"Intercostal Space","q":"Where is a pleural tap needle inserted and why?","a":"At the upper border of the lower rib, to avoid the neurovascular bundle.","img":null,"pyq":false},{"id":"a70","subject":"anatomy","topic":"Intercostal Space","q":"Where is an intercostal nerve block given?","a":"At the lower border of the upper rib.","img":null,"pyq":false},{"id":"a71","subject":"anatomy","topic":"Intercostal Nerves","q":"Which intercostal nerves contribute to the upper limb?","a":"T1 and T2.","img":null,"pyq":false},{"id":"a72","subject":"anatomy","topic":"Intercostal Arteries","q":"Source of posterior intercostal arteries of the 1st-2nd spaces?","a":"Costocervical trunk of the subclavian artery (superior intercostal artery).","img":null,"pyq":false},{"id":"a73","subject":"anatomy","topic":"Intercostal Arteries","q":"Source of the lower posterior intercostal arteries?","a":"Directly from the thoracic aorta.","img":null,"pyq":false},{"id":"a74","subject":"anatomy","topic":"Internal Thoracic A.","q":"Into what does the internal thoracic artery terminate?","a":"Superior epigastric and musculophrenic arteries at the 6th space.","img":null,"pyq":false},{"id":"a75","subject":"anatomy","topic":"Coarctation","q":"Mechanism of rib notching in coarctation of the aorta?","a":"Reversed flow through enlarged intercostal arteries (anterior to posterior) erodes the rib.","img":null,"pyq":false},{"id":"a76","subject":"anatomy","topic":"Bronchopulmonary Segment","q":"Define a bronchopulmonary segment.","a":"The portion of lung aerated by a single tertiary (segmental) bronchus.","img":null,"pyq":false},{"id":"a77","subject":"anatomy","topic":"Bronchopulmonary Segment","q":"Number of bronchopulmonary segments in each lung?","a":"Right lung 10, left lung 9.","img":null,"pyq":false},{"id":"a78","subject":"anatomy","topic":"Lungs","q":"Why is the right main bronchus more prone to aspiration?","a":"It is shorter, wider and more vertical.","img":null,"pyq":false},{"id":"a79","subject":"anatomy","topic":"Lungs","q":"Which segment is least vascular and a common TB site?","a":"The apical segment of the upper lobe.","img":null,"pyq":false},{"id":"a80","subject":"anatomy","topic":"Lungs","q":"Where do pulmonary veins run within the lung?","a":"Intersegmental (between segments), carrying oxygenated blood.","img":null,"pyq":false},{"id":"a81","subject":"anatomy","topic":"Pericardial Sinus","q":"Surgical importance of the transverse pericardial sinus?","a":"Allows clamping/ligation of the ascending aorta and pulmonary trunk.","img":null,"pyq":false},{"id":"a82","subject":"anatomy","topic":"Pericardial Sinus","q":"Location and significance of the oblique sinus?","a":"A cul-de-sac behind the left atrium allowing it to expand without compressing the oesophagus.","img":null,"pyq":false},{"id":"a83","subject":"anatomy","topic":"Right Atrium","q":"What does the crista terminalis separate?","a":"The rough anterior wall (musculi pectinati) from the smooth posterior wall.","img":null,"pyq":false},{"id":"a84","subject":"anatomy","topic":"Right Atrium","q":"What lies within the triangle of Koch?","a":"The atrioventricular (AV) node.","img":null,"pyq":false},{"id":"a85","subject":"anatomy","topic":"Right Atrium","q":"Where is the fossa ovalis located?","a":"In the interatrial septum.","img":null,"pyq":false},{"id":"a86","subject":"anatomy","topic":"Right Ventricle","q":"What does the supraventricular crest separate?","a":"The rough inflow part from the smooth outflow part (infundibulum).","img":null,"pyq":false},{"id":"a87","subject":"anatomy","topic":"Right Ventricle","q":"Function of the chordae tendineae?","a":"They prevent backflow (prolapse) of the valve cusps during systole.","img":null,"pyq":false},{"id":"a88","subject":"anatomy","topic":"Coronary Dominance","q":"What determines coronary dominance?","a":"The artery giving rise to the posterior interventricular artery - RCA = right dominant.","img":null,"pyq":true},{"id":"a89","subject":"anatomy","topic":"Conduction Supply","q":"Blood supply to the SA and AV nodes?","a":"The right coronary artery (also supplies the bundle of His).","img":null,"pyq":true},{"id":"a90","subject":"anatomy","topic":"Conduction Supply","q":"Which artery supplies the bundle branches?","a":"The left coronary artery.","img":null,"pyq":true},{"id":"a91","subject":"anatomy","topic":"Cardiac Veins","q":"Which veins drain into the coronary sinus?","a":"Great, middle and small cardiac veins, oblique vein of the left atrium and posterior vein of the LV.","img":null,"pyq":true},{"id":"a92","subject":"anatomy","topic":"Cardiac Veins","q":"Where do the anterior cardiac veins drain?","a":"Directly into the right atrium (not the coronary sinus).","img":null,"pyq":true},{"id":"a93","subject":"anatomy","topic":"Cardiac Veins","q":"Which artery accompanies the middle cardiac vein?","a":"The posterior interventricular artery.","img":null,"pyq":true},{"id":"a94","subject":"anatomy","topic":"Inguinal Canal","q":"What forms the anterior wall of the inguinal canal?","a":"External oblique aponeurosis, reinforced laterally by internal oblique.","img":null,"pyq":true},{"id":"a95","subject":"anatomy","topic":"Inguinal Canal","q":"What forms the posterior wall of the inguinal canal?","a":"Fascia transversalis and the conjoint tendon.","img":null,"pyq":true},{"id":"a96","subject":"anatomy","topic":"Inguinal Canal","q":"What forms the roof of the inguinal canal?","a":"Arched fibres of internal oblique and transversus abdominis.","img":null,"pyq":true},{"id":"a97","subject":"anatomy","topic":"Inguinal Canal","q":"What forms the floor of the inguinal canal?","a":"Inguinal and lacunar ligaments.","img":null,"pyq":true},{"id":"a98","subject":"anatomy","topic":"Inguinal Canal","q":"The deep inguinal ring is an opening in which layer?","a":"The fascia transversalis.","img":null,"pyq":true},{"id":"a99","subject":"anatomy","topic":"Inguinal Canal","q":"The superficial inguinal ring is an opening in which layer?","a":"The external oblique aponeurosis.","img":null,"pyq":true},{"id":"a100","subject":"anatomy","topic":"Peritoneal Folds","q":"What does the falciform ligament contain?","a":"The ligamentum teres - remnant of the left umbilical vein.","img":null,"pyq":true},{"id":"a101","subject":"anatomy","topic":"Peritoneal Folds","q":"Contents of the lienorenal (splenorenal) ligament?","a":"Splenic artery and tail of the pancreas.","img":null,"pyq":true},{"id":"a102","subject":"anatomy","topic":"Peritoneal Folds","q":"Contents of the gastrosplenic ligament?","a":"Short gastric and left gastroepiploic arteries.","img":null,"pyq":true},{"id":"a103","subject":"anatomy","topic":"Lesser Omentum","q":"What lies in the free margin of the lesser omentum?","a":"The portal triad - hepatic artery, bile duct and portal vein.","img":null,"pyq":false},{"id":"a104","subject":"anatomy","topic":"Epiploic Foramen","q":"What does the epiploic foramen (Winslow) connect?","a":"The greater and lesser peritoneal sacs.","img":null,"pyq":false},{"id":"a105","subject":"anatomy","topic":"Epiploic Foramen","q":"Anterior and posterior boundaries of the epiploic foramen?","a":"Anterior: portal triad. Posterior: inferior vena cava.","img":null,"pyq":false},{"id":"a106","subject":"anatomy","topic":"Epiploic Foramen","q":"Roof and floor of the epiploic foramen?","a":"Roof: caudate lobe of liver. Floor: 1st part of duodenum.","img":null,"pyq":false},{"id":"a107","subject":"anatomy","topic":"Peritoneal Cavity","q":"Most dependent peritoneal recess in the supine position?","a":"The hepatorenal pouch of Morrison.","img":null,"pyq":false},{"id":"a108","subject":"anatomy","topic":"Peritoneal Cavity","q":"Most dependent recess when upright in females?","a":"The rectouterine pouch of Douglas.","img":null,"pyq":false},{"id":"a109","subject":"anatomy","topic":"Phrenicocolic Ligament","q":"Function of the phrenicocolic ligament in splenomegaly?","a":"It directs the enlarging spleen toward the right iliac fossa.","img":null,"pyq":false},{"id":"a110","subject":"anatomy","topic":"Pelvic Diaphragm","q":"Components of the pelvic diaphragm?","a":"Levator ani (pubococcygeus, iliococcygeus) and ischiococcygeus.","img":null,"pyq":false},{"id":"a111","subject":"anatomy","topic":"Levator Ani","q":"Which part of levator ani maintains the anorectal angle?","a":"Puborectalis - the muscle of continence.","img":null,"pyq":false},{"id":"a112","subject":"anatomy","topic":"Perineal Body","q":"Which paired muscles attach to the perineal body?","a":"Superficial and deep transverse perinei, bulbospongiosus and levator ani.","img":null,"pyq":false},{"id":"a113","subject":"anatomy","topic":"Perineal Body","q":"Which muscle is NOT attached to the perineal body?","a":"Ischiocavernosus.","img":null,"pyq":false},{"id":"a114","subject":"anatomy","topic":"Perineal Pouch","q":"Contents of the deep perineal pouch?","a":"Membranous urethra, external urethral sphincter and the bulbourethral (Cowper's) gland in males.","img":null,"pyq":false},{"id":"a115","subject":"anatomy","topic":"Perineal Pouch","q":"Contents of the superficial perineal pouch?","a":"Bulb and crus of penis with their muscles, transverse perinei and Bartholin's gland (females).","img":null,"pyq":false},{"id":"a116","subject":"anatomy","topic":"Urethral Injury","q":"Where does urine extravasate in a bulbar urethral injury?","a":"Into the superficial perineal pouch, then scrotum, abdominal wall and thigh.","img":null,"pyq":false},{"id":"a117","subject":"anatomy","topic":"Ischiorectal Fossa","q":"Contents of the ischiorectal fossa?","a":"Fat, inferior rectal nerves and vessels, and the pudendal canal.","img":null,"pyq":false},{"id":"a118","subject":"anatomy","topic":"Pudendal Canal","q":"Contents of the pudendal (Alcock's) canal?","a":"Pudendal nerve and internal pudendal vessels.","img":null,"pyq":false},{"id":"a119","subject":"anatomy","topic":"Ischiorectal Fossa","q":"What is a horseshoe abscess?","a":"Spread of infection between both ischiorectal fossae via their posterior communication.","img":null,"pyq":false},{"id":"a120","subject":"anatomy","topic":"Cranial Nerve Columns","q":"Which muscles does the GSE column supply?","a":"Extraocular muscles and tongue muscles (CN III, IV, VI, XII).","img":null,"pyq":true},{"id":"a121","subject":"anatomy","topic":"Cranial Nerve Columns","q":"What does the SVE column supply?","a":"Pharyngeal arch muscles (CN V, VII, IX, X, XI).","img":null,"pyq":true},{"id":"a122","subject":"anatomy","topic":"Cranial Nerve Columns","q":"Which cranial nerves carry parasympathetic (GVE) fibres?","a":"III, VII, IX and X.","img":null,"pyq":true},{"id":"a123","subject":"anatomy","topic":"Parasympathetic Ganglia","q":"Edinger-Westphal nucleus relays through which ganglion and supplies what?","a":"Ciliary ganglion; supplies sphincter pupillae and ciliaris muscle.","img":null,"pyq":true},{"id":"a124","subject":"anatomy","topic":"Parasympathetic Ganglia","q":"Superior salivatory nucleus (VII) relays through which ganglia?","a":"Pterygopalatine (lacrimal gland) and submandibular (submandibular/sublingual glands).","img":null,"pyq":true},{"id":"a125","subject":"anatomy","topic":"Parasympathetic Ganglia","q":"Inferior salivatory nucleus (IX) relays through which ganglion?","a":"The otic ganglion, supplying the parotid gland.","img":null,"pyq":true},{"id":"a126","subject":"anatomy","topic":"Trigeminal Nuclei","q":"Function of the mesencephalic trigeminal nucleus?","a":"Proprioception and the jaw-jerk reflex; only CNS site with pseudounipolar neurons.","img":null,"pyq":true},{"id":"a127","subject":"anatomy","topic":"Trigeminal Nuclei","q":"Function of the spinal trigeminal nucleus?","a":"Pain and temperature sensation from the face.","img":null,"pyq":true},{"id":"a128","subject":"anatomy","topic":"Autonomic Outflow","q":"Outflow of the parasympathetic vs sympathetic system?","a":"Parasympathetic: craniosacral (III, VII, IX, X; S2-S4). Sympathetic: thoracolumbar (T1-L2).","img":null,"pyq":false},{"id":"a129","subject":"anatomy","topic":"Nerve Lesions","q":"Direction of uvular deviation in a vagus (X) lesion?","a":"The uvula deviates away from (contralateral to) the lesion.","img":null,"pyq":false},{"id":"a130","subject":"anatomy","topic":"Nerve Lesions","q":"Direction of tongue deviation in a hypoglossal (XII) lesion?","a":"The tongue deviates toward (ipsilateral to) the lesion on protrusion.","img":null,"pyq":false},{"id":"a131","subject":"anatomy","topic":"Deep Cervical Fascia","q":"Name the layers of deep cervical fascia.","a":"Investing, pretracheal, prevertebral layers and the carotid sheath.","img":null,"pyq":false},{"id":"a132","subject":"anatomy","topic":"Deep Cervical Fascia","q":"Which layer encloses the thyroid gland?","a":"The pretracheal fascia.","img":null,"pyq":false},{"id":"a133","subject":"anatomy","topic":"Danger Space","q":"Where is the danger space of the neck and why is it dangerous?","a":"Between the alar and prevertebral fascia; it opens inferiorly to the posterior mediastinum.","img":null,"pyq":false},{"id":"a134","subject":"anatomy","topic":"Carotid Sheath","q":"Contents of the carotid sheath?","a":"Common and internal carotid arteries, internal jugular vein and the vagus nerve.","img":null,"pyq":false},{"id":"a135","subject":"anatomy","topic":"Carotid Sheath","q":"Anterior and posterior relations of the carotid sheath?","a":"Anterior: ansa cervicalis. Posterior: sympathetic chain.","img":null,"pyq":false},{"id":"a136","subject":"anatomy","topic":"Cavernous Sinus","q":"Which structures lie in the lateral wall of the cavernous sinus?","a":"CN III, IV, V1 and V2.","img":null,"pyq":false},{"id":"a137","subject":"anatomy","topic":"Cavernous Sinus","q":"Which nerve is affected first in cavernous sinus thrombosis?","a":"CN VI (abducent), which runs free within the sinus with the ICA.","img":null,"pyq":false},{"id":"a138","subject":"anatomy","topic":"Cavernous Sinus","q":"What is a carotico-cavernous fistula and its hallmark sign?","a":"ICA rupture into the sinus causing pulsatile proptosis.","img":null,"pyq":false},{"id":"a139","subject":"anatomy","topic":"Mastication","q":"Name the four muscles of mastication and their common insertion.","a":"Temporalis, masseter, medial and lateral pterygoid - all insert on the mandible.","img":null,"pyq":true},{"id":"a140","subject":"anatomy","topic":"Mastication","q":"Which muscle opens the jaw (protraction and depression)?","a":"The lateral pterygoid.","img":null,"pyq":true},{"id":"a141","subject":"anatomy","topic":"Mastication","q":"The TMJ articular disc is an extension of which tendon?","a":"The lateral pterygoid tendon.","img":null,"pyq":true},{"id":"a142","subject":"anatomy","topic":"Submandibular Region","q":"Which nerve is most commonly injured in submandibular duct surgery?","a":"The lingual nerve.","img":null,"pyq":true},{"id":"a143","subject":"anatomy","topic":"Posterior Triangle","q":"Root value and course of the great auricular nerve?","a":"C2-C3; it ascends with the external jugular vein to supply the ear lobule and parotid skin.","img":null,"pyq":true},{"id":"a144","subject":"anatomy","topic":"Frey's Syndrome","q":"What causes Frey's syndrome?","a":"Misdirected regeneration of the auriculotemporal nerve communicating with the great auricular nerve.","img":null,"pyq":true},{"id":"a145","subject":"anatomy","topic":"Accessory Nerve","q":"Muscles supplied by the spinal accessory nerve?","a":"Sternocleidomastoid and trapezius (SCM is spared in posterior triangle injury).","img":null,"pyq":false},{"id":"a146","subject":"anatomy","topic":"Skull Foramina","q":"Which bones bound the foramen lacerum?","a":"Sphenoid, apex of petrous temporal and basilar occipital bones.","img":null,"pyq":true},{"id":"a147","subject":"anatomy","topic":"Skull Foramina","q":"Does the ICA pass through the foramen lacerum?","a":"No - it crosses over the foramen; the Vidian nerve passes through it.","img":null,"pyq":true},{"id":"a148","subject":"anatomy","topic":"Skull Foramina","q":"Which structures pass through the jugular foramen?","a":"CN IX, X, XI plus the sigmoid and inferior petrosal sinuses.","img":null,"pyq":true},{"id":"a149","subject":"anatomy","topic":"Skull Foramina","q":"Which is the longest intradural cranial nerve?","a":"CN VI (abducent).","img":null,"pyq":true},{"id":"a150","subject":"anatomy","topic":"Skull Foramina","q":"CN VII and VIII pass through which opening?","a":"The internal acoustic meatus.","img":null,"pyq":true},{"id":"a151","subject":"anatomy","topic":"Pterion","q":"Which four bones meet at the pterion?","a":"Frontal, parietal, greater wing of sphenoid and squamous temporal.","img":null,"pyq":true},{"id":"a152","subject":"anatomy","topic":"Pterion","q":"Clinical consequence of a pterion fracture?","a":"Rupture of the anterior division of the middle meningeal artery causing an extradural haemorrhage.","img":null,"pyq":true},{"id":"a153","subject":"anatomy","topic":"Dorsal Column","q":"Function of the fasciculus gracilis vs cuneatus?","a":"Gracilis carries lower-limb, cuneatus carries upper-limb fine touch and conscious proprioception.","img":null,"pyq":false},{"id":"a154","subject":"anatomy","topic":"Spinal Tracts","q":"Function of the lateral spinothalamic tract?","a":"Pain and temperature.","img":null,"pyq":false},{"id":"a155","subject":"anatomy","topic":"Spinal Tracts","q":"Function of the anterior spinothalamic tract?","a":"Crude touch and pressure.","img":null,"pyq":false},{"id":"a156","subject":"anatomy","topic":"Spinal Tracts","q":"At what point do spinothalamic tracts decussate?","a":"At or near their level of entry into the spinal cord.","img":null,"pyq":false},{"id":"a157","subject":"anatomy","topic":"Spinal Tracts","q":"Do the spinocerebellar tracts cross? What do they carry?","a":"They remain largely ipsilateral and carry unconscious proprioception.","img":null,"pyq":false},{"id":"a158","subject":"anatomy","topic":"Brown-Sequard","q":"Sensory findings in Brown-Sequard syndrome?","a":"Ipsilateral loss of proprioception/fine touch; contralateral loss of pain/temperature below the lesion.","img":null,"pyq":false},{"id":"a159","subject":"anatomy","topic":"Corticospinal Tract","q":"Which CST supplies limb vs axial muscles?","a":"Lateral CST supplies limbs; anterior CST supplies axial muscles.","img":null,"pyq":false},{"id":"a160","subject":"anatomy","topic":"Corticospinal Tract","q":"Where does the pyramidal tract decussate?","a":"In the lower medulla (pyramidal decussation).","img":null,"pyq":false},{"id":"a161","subject":"anatomy","topic":"Brainstem CN Exit","q":"Which cranial nerve emerges from the interpeduncular fossa?","a":"CN III (oculomotor).","img":null,"pyq":true},{"id":"a162","subject":"anatomy","topic":"Brainstem CN Exit","q":"Which cranial nerve exits the dorsal aspect of the brainstem?","a":"CN IV (trochlear).","img":null,"pyq":true},{"id":"a163","subject":"anatomy","topic":"Brainstem CN Exit","q":"Which cranial nerve emerges between the pyramid and the olive?","a":"CN XII (hypoglossal).","img":null,"pyq":true},{"id":"a164","subject":"anatomy","topic":"Facial Colliculus","q":"What forms the facial colliculus?","a":"The internal genu of the facial nerve looping around the abducent nucleus.","img":null,"pyq":false},{"id":"a165","subject":"anatomy","topic":"Colliculi","q":"Superior vs inferior colliculus - function and connection?","a":"Superior: visual reflexes, connects to LGB. Inferior: auditory, connects to MGB.","img":null,"pyq":false},{"id":"a166","subject":"anatomy","topic":"Auditory Pathway","q":"Mnemonic for the auditory pathway?","a":"E-COLI-MA: Eighth nerve, Cochlear nucleus, Olivary nucleus, Lateral lemniscus, Inferior colliculus, MGB, Auditory cortex.","img":null,"pyq":false},{"id":"a167","subject":"anatomy","topic":"Lemnisci","q":"Deficit from a lateral lemniscus lesion?","a":"Contralateral hearing loss.","img":null,"pyq":false},{"id":"a168","subject":"anatomy","topic":"Lemnisci","q":"Deficit from a medial lemniscus lesion?","a":"Contralateral loss of touch, vibration, proprioception and stereognosis.","img":null,"pyq":false},{"id":"a169","subject":"anatomy","topic":"Medullary Syndromes","q":"Features of medial medullary syndrome?","a":"Ipsilateral tongue paralysis with contralateral loss of proprioception and vibration.","img":null,"pyq":true},{"id":"a170","subject":"anatomy","topic":"Medullary Syndromes","q":"Features of lateral medullary syndrome?","a":"Dysphagia/dysarthria (IX, X, XI) with contralateral loss of pain and temperature.","img":null,"pyq":true},{"id":"a171","subject":"anatomy","topic":"Cerebellum","q":"Name the deep cerebellar nuclei from medial to lateral.","a":"Fastigial, globose, emboliform, dentate (the dentate is largest).","img":null,"pyq":true},{"id":"a172","subject":"anatomy","topic":"Cerebellum","q":"Where do climbing vs mossy fibres terminate?","a":"Climbing fibres in the molecular layer; mossy fibres in the granular layer.","img":null,"pyq":true},{"id":"a173","subject":"anatomy","topic":"Cerebellum","q":"Which is the only output (and only inhibitory) cell of the cerebellar cortex?","a":"The Purkinje cell.","img":null,"pyq":true},{"id":"a174","subject":"anatomy","topic":"Cerebellar Peduncles","q":"What does the superior cerebellar peduncle mainly carry?","a":"Efferents - dentatothalamic and dentatorubrothalamic tracts.","img":null,"pyq":true},{"id":"a175","subject":"anatomy","topic":"Internal Capsule","q":"Which tract occupies the genu of the internal capsule?","a":"The corticonuclear tract (UMN of cranial nerves).","img":null,"pyq":true},{"id":"a176","subject":"anatomy","topic":"Internal Capsule","q":"Blood supply to the genu and posterior limb of the internal capsule?","a":"Charcot's artery, a branch of the middle cerebral artery.","img":null,"pyq":true},{"id":"a177","subject":"anatomy","topic":"Cortical Blood Supply","q":"Deficit produced by an anterior cerebral artery stroke?","a":"Contralateral lower-limb paralysis and urinary incontinence.","img":null,"pyq":true},{"id":"a178","subject":"anatomy","topic":"Cortical Blood Supply","q":"Which artery supplies Broca's and Wernicke's areas?","a":"The middle cerebral artery.","img":null,"pyq":true},{"id":"a179","subject":"anatomy","topic":"Cortical Blood Supply","q":"Which artery supplies the visual cortex?","a":"The posterior cerebral artery.","img":null,"pyq":true},{"id":"a180","subject":"anatomy","topic":"Thalamus","q":"Inputs to the VPL nucleus of the thalamus?","a":"Medial and spinal lemnisci (sensation from the body).","img":null,"pyq":false},{"id":"a181","subject":"anatomy","topic":"Thalamus","q":"Inputs to the VPM nucleus of the thalamus?","a":"Trigeminal lemniscus (face) and nucleus tractus solitarius (taste).","img":null,"pyq":false},{"id":"a182","subject":"anatomy","topic":"Brachial Plexus","q":"Root value of the brachial plexus?","a":"C5, C6, C7, C8 and T1.","img":null,"pyq":false},{"id":"a183","subject":"anatomy","topic":"Brachial Plexus","q":"From which cords is the median nerve formed?","a":"The lateral and medial cords.","img":null,"pyq":false},{"id":"a184","subject":"anatomy","topic":"Brachial Plexus","q":"Which nerve arises from the posterior cord (terminal)?","a":"The radial nerve (with axillary).","img":null,"pyq":false},{"id":"a185","subject":"anatomy","topic":"Erb's Palsy","q":"Root value and deformity of Erb's palsy?","a":"C5-C6 (upper trunk); the waiter's tip - adducted shoulder, extended elbow, pronated forearm.","img":null,"pyq":true},{"id":"a186","subject":"anatomy","topic":"Klumpke's Palsy","q":"Root value and features of Klumpke's palsy?","a":"C8-T1 (lower trunk); claw hand with Horner's syndrome.","img":null,"pyq":true},{"id":"a187","subject":"anatomy","topic":"Clavipectoral Fascia","q":"Which muscles does the clavipectoral fascia enclose?","a":"Pectoralis minor and subclavius.","img":null,"pyq":false},{"id":"a188","subject":"anatomy","topic":"Clavipectoral Fascia","q":"Which structures pierce the clavipectoral fascia?","a":"Cephalic vein, thoraco-acromial trunk, lateral pectoral nerve and lymphatics.","img":null,"pyq":false},{"id":"a189","subject":"anatomy","topic":"Rotator Cuff","q":"Name the four rotator cuff muscles.","a":"Supraspinatus, infraspinatus, teres minor and subscapularis (SITS).","img":null,"pyq":false},{"id":"a190","subject":"anatomy","topic":"Shoulder Movements","q":"Which muscle initiates the first 15 degrees of abduction?","a":"Supraspinatus.","img":null,"pyq":false},{"id":"a191","subject":"anatomy","topic":"Scapular Muscles","q":"Nerve supply and effect of injury to serratus anterior?","a":"Long thoracic nerve; injury causes winging of the scapula.","img":null,"pyq":false},{"id":"a192","subject":"anatomy","topic":"Scapular Muscles","q":"Which nerve supplies the rhomboids and levator scapulae?","a":"The dorsal scapular nerve (C5).","img":null,"pyq":false},{"id":"a193","subject":"anatomy","topic":"Cubital Fossa","q":"Medial and lateral boundaries of the cubital fossa?","a":"Medial: pronator teres. Lateral: brachioradialis.","img":null,"pyq":true},{"id":"a194","subject":"anatomy","topic":"Cubital Fossa","q":"Contents of the cubital fossa from medial to lateral?","a":"Median nerve, brachial artery, biceps tendon, radial nerve (MBBS).","img":null,"pyq":true},{"id":"a195","subject":"anatomy","topic":"Hand Muscles","q":"Nerve supply to the thenar muscles?","a":"Median nerve (except adductor pollicis, supplied by the ulnar nerve).","img":null,"pyq":true},{"id":"a196","subject":"anatomy","topic":"Hand Muscles","q":"Nerve supply to the hypothenar muscles?","a":"The ulnar nerve.","img":null,"pyq":true},{"id":"a197","subject":"anatomy","topic":"Thumb Movements","q":"Which nerve controls opposition, adduction and extension of the thumb?","a":"Opposition - median; adduction - ulnar; extension - radial.","img":null,"pyq":false},{"id":"a198","subject":"anatomy","topic":"Lumbricals","q":"Action and nerve supply of the lumbricals?","a":"Flex MCP and extend IP joints; lateral two are median, medial two are ulnar.","img":null,"pyq":true},{"id":"a199","subject":"anatomy","topic":"Interossei","q":"Action of palmar vs dorsal interossei?","a":"PAD - palmar adduct; DAB - dorsal abduct; both supplied by the ulnar nerve.","img":null,"pyq":true},{"id":"a200","subject":"anatomy","topic":"Interossei","q":"Clinical tests for palmar and dorsal interossei?","a":"Palmar - card test; dorsal - Egawa test.","img":null,"pyq":true},{"id":"a201","subject":"anatomy","topic":"Radial Nerve","q":"Origin and root value of the radial nerve?","a":"Posterior cord of the brachial plexus; C5-T1.","img":null,"pyq":true},{"id":"a202","subject":"anatomy","topic":"Radial Nerve","q":"Features of Saturday-night palsy (radial groove injury)?","a":"Wrist drop and finger drop, with the triceps spared.","img":null,"pyq":true},{"id":"a203","subject":"anatomy","topic":"Radial Nerve","q":"Features of a posterior interosseous nerve injury?","a":"Finger drop without wrist drop and no sensory loss.","img":null,"pyq":true},{"id":"a204","subject":"anatomy","topic":"Radial Nerve","q":"Sensory area of the superficial radial nerve?","a":"The lateral three and a half of the dorsum of the hand.","img":null,"pyq":true},{"id":"a205","subject":"anatomy","topic":"Median Nerve","q":"Why is palm sensation preserved in carpal tunnel syndrome?","a":"The palmar cutaneous branch runs superficial to the flexor retinaculum and is spared.","img":null,"pyq":true},{"id":"a206","subject":"anatomy","topic":"Median Nerve","q":"Deformity of a high median nerve injury?","a":"Pointing index finger / hand of benediction, with ape-thumb deformity.","img":null,"pyq":true},{"id":"a207","subject":"anatomy","topic":"Ulnar Nerve","q":"Root value and cord of origin of the ulnar nerve?","a":"C8-T1 (with C7); from the medial cord.","img":null,"pyq":true},{"id":"a208","subject":"anatomy","topic":"Ulnar Nerve","q":"Why is the ulnar claw incomplete?","a":"The medial two lumbricals are ulnar but the lateral two (median) keep partial MCP function.","img":null,"pyq":true},{"id":"a209","subject":"anatomy","topic":"Ulnar Nerve","q":"Explain the ulnar paradox.","a":"A higher (proximal) lesion gives a less prominent claw because FDP is also paralysed.","img":null,"pyq":true},{"id":"a210","subject":"anatomy","topic":"Ulnar Nerve","q":"What does Froment's sign indicate?","a":"Adductor pollicis weakness - thumb flexes via FPL when holding paper/a book.","img":null,"pyq":true},{"id":"a211","subject":"anatomy","topic":"Epicondyle Fracture","q":"Which nerve is most commonly injured in a medial epicondyle fracture?","a":"The ulnar nerve.","img":null,"pyq":true},{"id":"a212","subject":"anatomy","topic":"Lumbar Plexus","q":"Root value of the lumbar plexus?","a":"L1-L4.","img":null,"pyq":false},{"id":"a213","subject":"anatomy","topic":"Meralgia Paresthetica","q":"Cause and features of meralgia paresthetica?","a":"Compression of the lateral cutaneous nerve of the thigh; numbness/tingling over the lateral thigh.","img":null,"pyq":true},{"id":"a214","subject":"anatomy","topic":"Genitofemoral Nerve","q":"Peculiarity of the genitofemoral nerve and psoas?","a":"It pierces psoas major without supplying it, violating Hilton's law.","img":null,"pyq":false},{"id":"a215","subject":"anatomy","topic":"Cremasteric Reflex","q":"Afferent and efferent limbs of the cremasteric reflex?","a":"Afferent: femoral branch; efferent: genital branch of the genitofemoral nerve.","img":null,"pyq":false},{"id":"a216","subject":"anatomy","topic":"Iliotibial Band","q":"Origin and insertion of the iliotibial band?","a":"From the iliac crest tubercle to the lateral tibial condyle (Gerdy's tubercle).","img":null,"pyq":false},{"id":"a217","subject":"anatomy","topic":"Iliotibial Band","q":"Which muscles insert into the iliotibial band?","a":"Tensor fasciae latae and gluteus maximus.","img":null,"pyq":false},{"id":"a218","subject":"anatomy","topic":"Femoral Triangle","q":"Boundaries of the femoral triangle?","a":"Base: inguinal ligament; medial: adductor longus; lateral: sartorius.","img":null,"pyq":false},{"id":"a219","subject":"anatomy","topic":"Femoral Triangle","q":"Muscles forming the floor of the femoral triangle?","a":"Iliacus, psoas major, pectineus and adductor longus.","img":null,"pyq":false},{"id":"a220","subject":"anatomy","topic":"Femoral Sheath","q":"Contents of the femoral sheath from lateral to medial?","a":"Femoral artery, femoral vein and the femoral canal (lymph node of Cloquet).","img":null,"pyq":false},{"id":"a221","subject":"anatomy","topic":"Femoral Nerve","q":"Is the femoral nerve inside the femoral sheath?","a":"No - it lies outside (lateral to) the sheath.","img":null,"pyq":true},{"id":"a222","subject":"anatomy","topic":"Femoral Nerve","q":"Root value of the femoral nerve?","a":"L2-L4 (dorsal divisions).","img":null,"pyq":true},{"id":"a223","subject":"anatomy","topic":"Saphenous Nerve","q":"Which nerve is at risk in great saphenous vein grafting?","a":"The saphenous nerve - the longest cutaneous nerve, supplying the medial leg and foot.","img":null,"pyq":true},{"id":"a224","subject":"anatomy","topic":"Adductor Compartment","q":"Nerve supply of the medial (adductor) compartment of the thigh?","a":"The obturator nerve (ventral divisions of L2-L4).","img":null,"pyq":false},{"id":"a225","subject":"anatomy","topic":"Adductor Magnus","q":"Why is adductor magnus called a hybrid muscle?","a":"It has dual nerve supply - obturator and sciatic (tibial part).","img":null,"pyq":false},{"id":"a226","subject":"anatomy","topic":"Pudendal Nerve","q":"Consequence of pudendal nerve injury at the ischial spine?","a":"Weakness of perineal muscles and impaired continence.","img":null,"pyq":false},{"id":"a227","subject":"anatomy","topic":"Gluteal Nerves","q":"Muscles supplied by the superior vs inferior gluteal nerve?","a":"Superior: gluteus medius, minimus and TFL. Inferior: gluteus maximus.","img":null,"pyq":true},{"id":"a228","subject":"anatomy","topic":"Trendelenburg Sign","q":"Cause and finding of a positive Trendelenburg sign?","a":"Superior gluteal nerve or glut medius/minimus weakness; the contralateral pelvis drops.","img":null,"pyq":true},{"id":"a229","subject":"anatomy","topic":"Popliteal Fossa","q":"Boundaries of the popliteal fossa?","a":"Superolateral: biceps femoris; superomedial: semimembranosus/tendinosus; inferior: gastrocnemius heads.","img":null,"pyq":false},{"id":"a230","subject":"anatomy","topic":"Popliteal Fossa","q":"Contents of the popliteal fossa from deep to superficial?","a":"Popliteal artery (deepest), popliteal vein, tibial and common peroneal nerves.","img":null,"pyq":false},{"id":"a231","subject":"anatomy","topic":"Hamstrings","q":"Name the hamstring muscles.","a":"Semitendinosus, semimembranosus, long head of biceps femoris and the hamstring part of adductor magnus.","img":null,"pyq":false},{"id":"a232","subject":"anatomy","topic":"Foot Arches","q":"Bones of the medial longitudinal arch?","a":"Talus, navicular, three cuneiforms, medial calcaneus and the medial three metatarsals.","img":null,"pyq":false},{"id":"a233","subject":"anatomy","topic":"Foot Arches","q":"Bones of the lateral longitudinal arch?","a":"Calcaneus, cuboid and the lateral two metatarsals.","img":null,"pyq":false},{"id":"a234","subject":"anatomy","topic":"Spring Ligament","q":"Function of the spring (plantar calcaneonavicular) ligament and effect of its tear?","a":"Supports the head of the talus; tearing causes flat foot.","img":null,"pyq":false},{"id":"a235","subject":"anatomy","topic":"Ankle Ligaments","q":"Function of the deltoid ligament?","a":"It is the strong medial ligament that prevents excessive eversion.","img":null,"pyq":false},{"id":"a236","subject":"anatomy","topic":"Ankle Ligaments","q":"Which ligament is most commonly torn in an inversion ankle sprain?","a":"The anterior talofibular ligament.","img":null,"pyq":false},{"id":"a237","subject":"anatomy","topic":"Lisfranc Ligament","q":"What does the Lisfranc ligament connect?","a":"The medial cuneiform to the base of the 2nd metatarsal.","img":null,"pyq":false},{"id":"a238","subject":"anatomy","topic":"Sole of Foot","q":"Dominant nerve supplying the intrinsic foot muscles?","a":"The lateral plantar nerve (analogous to the ulnar nerve in the hand).","img":null,"pyq":false},{"id":"a239","subject":"anatomy","topic":"Sciatic Nerve","q":"Root value of the sciatic nerve?","a":"L4, L5, S1, S2, S3.","img":null,"pyq":true},{"id":"a240","subject":"anatomy","topic":"Sciatic Nerve","q":"Into which two nerves does the sciatic nerve divide and where?","a":"Tibial and common peroneal nerves, usually at the apex of the popliteal fossa.","img":null,"pyq":true},{"id":"a241","subject":"anatomy","topic":"Common Peroneal N.","q":"Result of a common peroneal nerve injury at the fibular neck?","a":"Foot drop with loss of dorsiflexion and eversion - an equinovarus, high-stepping gait.","img":null,"pyq":true},{"id":"a242","subject":"anatomy","topic":"Peroneal Nerves","q":"Functions of the deep vs superficial peroneal nerve?","a":"Deep: dorsiflexors and 1st web space skin. Superficial: evertors and most dorsal foot skin.","img":null,"pyq":true},{"id":"a243","subject":"anatomy","topic":"Tibial Nerve","q":"Main muscle group supplied by the tibial nerve?","a":"The plantar flexors of the leg.","img":null,"pyq":true},{"id":"a244","subject":"anatomy","topic":"Sural Nerve","q":"Which nerve is injured in short saphenous vein grafting?","a":"The sural nerve, supplying the lateral border of the foot.","img":null,"pyq":true},{"id":"a245","subject":"anatomy","topic":"Aphasia","q":"Differentiate Broca's, Wernicke's and conduction aphasia.","a":"Broca's: non-fluent, comprehension intact (areas 44/45, MCA). Wernicke's: fluent but meaningless, poor comprehension (area 22). Conduction: poor repetition (arcuate fasciculus lesion).","img":null,"pyq":true},{"id":"a246","subject":"anatomy","topic":"Brodmann's Areas","q":"Match key Brodmann areas to function.","a":"4 primary motor; 3,1,2 primary sensory; 17 primary visual; 41,42 auditory; 44,45 Broca's; 22 Wernicke's.","img":null,"pyq":true},{"id":"a247","subject":"anatomy","topic":"External Ear Nerve Supply","q":"Nerve supply of the auricle.","a":"Auriculotemporal (V3) and great auricular (C2-3) supply most of it; lesser occipital the upper medial surface; auricular branch of vagus (Arnold's) and facial supply the concha/EAC.","img":null,"pyq":true},{"id":"a248","subject":"anatomy","topic":"Facial Nerve - Bell's Palsy","q":"How does Bell's palsy differ from an UMN facial lesion?","a":"Bell's palsy is LMN: the whole half of the face including the forehead is paralysed. An UMN lesion spares the forehead (bilateral cortical input).","img":null,"pyq":true},{"id":"a249","subject":"anatomy","topic":"First Rib","q":"Name the key features of the first rib.","a":"Scalene tubercle (scalenus anterior insertion) with grooves for the subclavian vein in front and subclavian artery behind; attachment for the suprapleural membrane.","img":null,"pyq":true},{"id":"a250","subject":"anatomy","topic":"Fontanelles","q":"Anterior vs posterior fontanelle - shape and closure?","a":"Anterior: diamond-shaped, closes by ~18 months. Posterior: triangular, closes by ~2-3 months.","img":null,"pyq":true},{"id":"a251","subject":"anatomy","topic":"Larynx - Muscles","q":"Which laryngeal muscle is the only abductor, and what is the lone tensor?","a":"Posterior cricoarytenoid is the only abductor of the vocal cords; cricothyroid (external laryngeal nerve) is the tensor. All other intrinsic muscles are supplied by the recurrent laryngeal nerve.","img":null,"pyq":true},{"id":"a252","subject":"anatomy","topic":"Larynx - Membranes","q":"Name the two fibroelastic membranes of the larynx.","a":"Quadrangular membrane above (free lower edge = vestibular ligament) and the cricovocal membrane/conus elasticus below (free upper edge = vocal ligament).","img":null,"pyq":true},{"id":"a253","subject":"anatomy","topic":"Leprosy - Thickened Nerves","q":"Which peripheral nerves are commonly thickened in leprosy?","a":"Ulnar, common peroneal, great auricular, posterior tibial, superficial radial and supraorbital nerves.","img":null,"pyq":true},{"id":"a254","subject":"anatomy","topic":"Pelvis Diameters","q":"Define the obstetric and true conjugate of the pelvic inlet.","a":"True (anatomical) conjugate: sacral promontory to upper pubic symphysis (~11 cm). Obstetric conjugate: promontory to the most posterior point of symphysis - the smallest AP diameter (~10.5 cm).","img":null,"pyq":true},{"id":"a255","subject":"anatomy","topic":"Types of Joints","q":"Classify joints structurally.","a":"Fibrous (suture, syndesmosis, gomphosis), cartilaginous (primary synchondrosis, secondary symphysis) and synovial joints.","img":null,"pyq":true},{"id":"a256","subject":"anatomy","topic":"Hard Palate","q":"Bones and nerve supply of the hard palate?","a":"Palatine process of the maxilla plus the horizontal plate of the palatine bone; supplied by the greater palatine and nasopalatine nerves (V2).","img":null,"pyq":true},{"id":"a257","subject":"anatomy","topic":"Corpus Callosum","q":"Name the parts and major fibre bundles of the corpus callosum.","a":"Parts: rostrum, genu, body, splenium. Fibres: forceps minor (genu to frontal), forceps major (splenium to occipital) and the tapetum.","img":null,"pyq":true},{"id":"a258","subject":"anatomy","topic":"Oblique Muscle Derivatives","q":"Derivatives of the external and internal oblique aponeuroses?","a":"External oblique: inguinal & lacunar ligaments, superficial ring, external spermatic fascia. Internal oblique: cremaster muscle/fascia and (with transversus) the conjoint tendon.","img":null,"pyq":true},{"id":"a259","subject":"anatomy","topic":"Dermatomes","q":"Give the classic dermatome landmarks.","a":"Nipple T4, xiphisternum T6, umbilicus T10, inguinal region L1; thumb C6, middle finger C7, little finger C8; great toe L5, little toe/sole S1.","img":null,"pyq":true},{"id":"a260","subject":"anatomy","topic":"Calot's Triangle","q":"Boundaries and content of the cystohepatic (Calot's) triangle.","a":"Bounded by the cystic duct, common hepatic duct and inferior surface of the liver; contains the cystic artery (a branch of the right hepatic artery).","img":null,"pyq":true},{"id":"a261","subject":"anatomy","topic":"Couinaud Segments","q":"How is the liver divided by the Couinaud system?","a":"Into 8 functionally independent segments, each with its own vascular inflow, outflow and biliary drainage; the caudate lobe is segment I and drains directly to the IVC.","img":null,"pyq":true},{"id":"a262","subject":"anatomy","topic":"Muscles of Forearm","q":"Nerve supply of the forearm compartments.","a":"Anterior (flexor) compartment is supplied by the median nerve, except FCU and the medial half of FDP (ulnar). The posterior (extensor) compartment is supplied by the radial nerve.","img":null,"pyq":true},{"id":"a263","subject":"anatomy","topic":"Prostate Anatomy","q":"Clinical zones of the prostate?","a":"Peripheral zone (commonest site of carcinoma), transition zone (site of benign hyperplasia) and central zone; the urethra and ejaculatory ducts pass through it.","img":null,"pyq":true},{"id":"a264","subject":"anatomy","topic":"Vertebral Column","q":"Composition and curvatures of the vertebral column.","a":"33 vertebrae - 7 cervical, 12 thoracic, 5 lumbar, 5 fused sacral, 4 coccygeal; primary kyphotic (thoracic, sacral) and secondary lordotic (cervical, lumbar) curves.","img":null,"pyq":true},{"id":"a265","subject":"anatomy","topic":"Anatomical Snuff Box","q":"Boundaries, floor and contents of the snuff box?","a":"Boundaries: EPL medially, APL and EPB laterally. Floor: scaphoid and trapezium. Contents: radial artery. Tenderness suggests a scaphoid fracture.","img":null,"pyq":true},{"id":"a266","subject":"anatomy","topic":"Biceps Brachii","q":"Origin and nerve supply of biceps brachii?","a":"Long head from the supraglenoid tubercle, short head from the coracoid process; a powerful supinator and elbow flexor supplied by the musculocutaneous nerve.","img":null,"pyq":true},{"id":"a267","subject":"anatomy","topic":"Cell Cycle","q":"Phases and key checkpoints of the cell cycle?","a":"G1, S (DNA synthesis), G2 and M (mitosis); regulated at the G1/S (restriction) and G2/M checkpoints by cyclins and CDKs.","img":null,"pyq":true},{"id":"a268","subject":"anatomy","topic":"Fallopian Tube & Ovary","q":"Parts of the fallopian tube and ovarian ligaments?","a":"Tube: infundibulum, ampulla (site of fertilisation), isthmus, intramural part. Ovary is held by the suspensory ligament (ovarian vessels) and the ligament of the ovary.","img":null,"pyq":true},{"id":"a269","subject":"anatomy","topic":"Fetal Circulation","q":"Name the three fetal shunts and their adult remnants.","a":"Ductus venosus (to ligamentum venosum), foramen ovale (to fossa ovalis) and ductus arteriosus (to ligamentum arteriosum).","img":null,"pyq":true},{"id":"a270","subject":"anatomy","topic":"Pancreas Anatomy","q":"Parts, ducts and key relation of the pancreas?","a":"Head with uncinate process, neck, body and tail (tail lies in the lienorenal ligament); main duct of Wirsung and accessory duct of Santorini drain into the duodenum.","img":null,"pyq":true},{"id":"a271","subject":"anatomy","topic":"Spaces & Fossae of UL","q":"Contents of the quadrangular and triangular spaces?","a":"Quadrangular space: axillary nerve and posterior circumflex humeral vessels. Triangular space: circumflex scapular vessels. Triangular interval: radial nerve and profunda brachii.","img":null,"pyq":true},{"id":"a272","subject":"anatomy","topic":"Stomach Anatomy","q":"Parts and arterial supply of the stomach?","a":"Parts: cardia, fundus, body, pyloric antrum and pylorus. Supplied by the left/right gastric, left/right gastroepiploic and short gastric arteries - all from the coeliac trunk.","img":null,"pyq":true},{"id":"a273","subject":"anatomy","topic":"Thyroid Gland","q":"Isthmus level and arterial supply of the thyroid?","a":"Isthmus overlies the 2nd-4th tracheal rings. Supplied by the superior thyroid (close to external laryngeal nerve) and inferior thyroid (close to recurrent laryngeal nerve) arteries.","img":null,"pyq":true},{"id":"a274","subject":"anatomy","topic":"Types of Cartilage","q":"Name the three types of cartilage with examples.","a":"Hyaline (articular surfaces, costal), elastic (epiglottis, external ear) and fibrocartilage (intervertebral discs, menisci, pubic symphysis).","img":null,"pyq":true},{"id":"a275","subject":"anatomy","topic":"Circle of Willis","q":"Vessels forming the circle of Willis and commonest aneurysm site?","a":"Anterior cerebral, anterior communicating, internal carotid, posterior communicating, posterior cerebral arteries and the basilar; the anterior communicating artery is the commonest aneurysm site.","img":null,"pyq":true},{"id":"a276","subject":"anatomy","topic":"Glossopharyngeal Nerve","q":"Key functions of the glossopharyngeal (IX) nerve?","a":"Motor to stylopharyngeus, secretomotor to the parotid (via the otic ganglion), taste and sensation from the posterior third of the tongue, and carotid sinus/body afferents; exits via the jugular foramen.","img":null,"pyq":true},{"id":"a277","subject":"anatomy","topic":"Salivary Glands","q":"Autonomic supply of the major salivary glands?","a":"Parotid: IX via the otic ganglion (auriculotemporal nerve). Submandibular and sublingual: VII via the chorda tympani and submandibular ganglion.","img":null,"pyq":true},{"id":"a278","subject":"anatomy","topic":"Tongue Papillae","q":"Name the lingual papillae and which lacks taste buds.","a":"Filiform (most numerous, no taste buds), fungiform, circumvallate (just anterior to the sulcus terminalis) and foliate papillae.","img":null,"pyq":true},{"id":"a279","subject":"anatomy","topic":"Parotid Gland","q":"Which nerve gives secretomotor supply to the parotid, and which nerve merely traverses it?","a":"Secretomotor (parasympathetic) fibres come from IX via the otic ganglion and auriculotemporal nerve; the facial nerve passes through the gland but does not supply it.","img":null,"pyq":true},{"id":"a280","subject":"anatomy","topic":"Porto-systemic Anastomoses","q":"List the main sites of porto-systemic anastomosis.","a":"Lower oesophagus (varices), anal canal (haemorrhoids), paraumbilical region (caput medusae), retroperitoneal and the bare area of the liver.","img":null,"pyq":true},{"id":"a281","subject":"anatomy","topic":"Umbilical Artery","q":"Fate of the umbilical arteries after birth?","a":"The distal parts obliterate to form the medial umbilical ligaments; the proximal parts persist as the superior vesical arteries (from the internal iliac).","img":null,"pyq":true},{"id":"a282","subject":"anatomy","topic":"Urogenital Tract Histology","q":"Epithelium lining the urinary tract?","a":"Transitional epithelium (urothelium) lines the renal calyces, ureter and bladder; it allows distension. The urethra transitions to stratified/columnar then squamous epithelium distally.","img":null,"pyq":true},{"id":"a283","subject":"anatomy","topic":"Trochlear Nerve","q":"Unique features of the trochlear (CN IV) nerve?","a":"It is the only cranial nerve to exit dorsally, has the longest intracranial course, and decussates; it supplies the superior oblique. Palsy causes vertical diplopia and a compensatory head tilt.","img":null,"pyq":true},{"id":"a284","subject":"anatomy","topic":"Trigeminal Nerve","q":"Exit foramina of the three trigeminal divisions?","a":"V1 ophthalmic - superior orbital fissure; V2 maxillary - foramen rotundum; V3 mandibular - foramen ovale (carries motor fibres to the muscles of mastication).","img":null,"pyq":true},{"id":"a285","subject":"anatomy","topic":"Mesentery - Embryology","q":"From which structures do the dorsal and ventral mesenteries arise?","a":"Both are double peritoneal folds suspending the gut; the ventral mesentery (only in the foregut) gives the lesser omentum and falciform ligament, while the dorsal mesentery gives the greater omentum and other ligaments.","img":null,"pyq":true}],"pathology":[{"id":"p1","subject":"pathology","topic":"Multiple Myeloma","q":"Defining cell and key lab findings in multiple myeloma?","a":"Malignant plasma-cell proliferation; serum M-spike (usually IgG) and urinary Bence-Jones (light-chain) proteins.","img":null,"pyq":true},{"id":"p2","subject":"pathology","topic":"Multiple Myeloma","q":"Clinical tetrad of multiple myeloma (CRAB)?","a":"HyperCalcaemia, Renal failure, Anaemia and Bone lytic lesions (punched-out skull); rouleaux on smear.","img":null,"pyq":true},{"id":"p3","subject":"pathology","topic":"Multiple Myeloma","q":"Marrow finding diagnostic of multiple myeloma?","a":"More than 10% clonal plasma cells; flame cells and Russell bodies may be seen.","img":null,"pyq":true},{"id":"p4","subject":"pathology","topic":"Non-Hodgkin Lymphoma","q":"How does NHL typically behave compared with Hodgkin lymphoma?","a":"Mostly B-cell, often disseminated and extranodal at presentation, with non-contiguous (skip) spread and no Reed-Sternberg cells.","img":null,"pyq":true},{"id":"p5","subject":"pathology","topic":"Hodgkin Lymphoma","q":"Diagnostic cell of Hodgkin lymphoma and its markers?","a":"The Reed-Sternberg cell - a binucleate owl-eye cell that is CD15+ and CD30+.","img":null,"pyq":true},{"id":"p6","subject":"pathology","topic":"Hodgkin Lymphoma","q":"Subtypes of Hodgkin lymphoma and their notes?","a":"Nodular sclerosis (commonest, lacunar cells), mixed cellularity (EBV-linked), lymphocyte-rich (best prognosis), lymphocyte-depleted (worst).","img":null,"pyq":true},{"id":"p7","subject":"pathology","topic":"Hodgkin Lymphoma","q":"Staging system and B-symptoms of Hodgkin lymphoma?","a":"Ann Arbor staging; B symptoms are fever, drenching night sweats and weight loss (Pel-Ebstein fever).","img":null,"pyq":true},{"id":"p8","subject":"pathology","topic":"Burkitt's Lymphoma","q":"Genetics and classic histology of Burkitt's lymphoma?","a":"t(8;14) activating c-MYC; 'starry-sky' appearance from tingible-body macrophages; the fastest-growing human tumour.","img":null,"pyq":true},{"id":"p9","subject":"pathology","topic":"Burkitt's Lymphoma","q":"Three clinical forms of Burkitt's lymphoma?","a":"Endemic (African, jaw, EBV-associated), sporadic (abdominal) and immunodeficiency-associated.","img":null,"pyq":true},{"id":"p10","subject":"pathology","topic":"Follicular Lymphoma","q":"Genetics and markers of follicular lymphoma?","a":"t(14;18) overexpressing BCL2 (anti-apoptotic); indolent course; CD10+ and BCL2+.","img":null,"pyq":true},{"id":"p11","subject":"pathology","topic":"Acute Myeloid Leukaemia","q":"Hallmark cytology of AML, especially the M3 subtype?","a":"Auer rods that are myeloperoxidase-positive; APL (M3) shows faggot cells, carries t(15;17) and is treated with ATRA.","img":null,"pyq":true},{"id":"p12","subject":"pathology","topic":"Acute Myeloid Leukaemia","q":"Marrow blast threshold and a key complication of APL?","a":"More than 20% marrow blasts; acute promyelocytic leukaemia is prone to DIC.","img":null,"pyq":true},{"id":"p13","subject":"pathology","topic":"Chronic Myeloid Leukaemia","q":"Defining genetic lesion of CML?","a":"t(9;22) Philadelphia chromosome producing the BCR-ABL fusion tyrosine kinase; low LAP score.","img":null,"pyq":true},{"id":"p14","subject":"pathology","topic":"Chronic Myeloid Leukaemia","q":"Blood picture and treatment of CML?","a":"Marked leucocytosis with basophilia and splenomegaly; treated with tyrosine-kinase inhibitors such as imatinib; may enter blast crisis.","img":null,"pyq":true},{"id":"p15","subject":"pathology","topic":"Chronic Lymphocytic Leukaemia","q":"Smear hallmark and immunophenotype of CLL?","a":"Smudge (basket) cells; CD5+ and CD23+ mature B cells in older adults; SLL is its tissue counterpart.","img":null,"pyq":true},{"id":"p16","subject":"pathology","topic":"Chronic Lymphocytic Leukaemia","q":"A classic complication of CLL?","a":"Warm autoimmune haemolytic anaemia.","img":null,"pyq":true},{"id":"p17","subject":"pathology","topic":"Aplastic Anaemia","q":"Defining marrow finding in aplastic anaemia?","a":"Pancytopenia with a hypocellular, fatty marrow giving a dry tap; caused by drugs, radiation or viruses.","img":null,"pyq":true},{"id":"p18","subject":"pathology","topic":"Sickle Cell Anaemia","q":"Underlying mutation in sickle cell anaemia?","a":"A point mutation substituting valine for glutamate in the beta-globin chain (HbS); autosomal recessive.","img":null,"pyq":true},{"id":"p19","subject":"pathology","topic":"Sickle Cell Anaemia","q":"Key clinical and smear features of sickle cell disease?","a":"Vaso-occlusive pain crises and autosplenectomy (Howell-Jolly bodies); sickle and target cells on the smear.","img":null,"pyq":true},{"id":"p20","subject":"pathology","topic":"Sickle Cell Anaemia","q":"What confirms the diagnosis and what protective benefit exists?","a":"Haemoglobin electrophoresis is diagnostic; the trait protects against falciparum malaria.","img":null,"pyq":true},{"id":"p21","subject":"pathology","topic":"Thalassaemia","q":"Basic defect and blood picture in thalassaemia?","a":"Reduced globin-chain synthesis giving a microcytic hypochromic anaemia with target cells.","img":null,"pyq":true},{"id":"p22","subject":"pathology","topic":"Thalassaemia","q":"Features of beta-thalassaemia major?","a":"Cooley's anaemia - transfusion-dependent, crew-cut skull X-ray, hepatosplenomegaly and raised HbF/HbA2.","img":null,"pyq":true},{"id":"p23","subject":"pathology","topic":"Hereditary Spherocytosis","q":"Molecular defect and diagnostic test for HS?","a":"Spectrin/ankyrin cytoskeletal defect producing spherocytes with raised MCHC; positive osmotic fragility test.","img":null,"pyq":true},{"id":"p24","subject":"pathology","topic":"Hereditary Spherocytosis","q":"Type of haemolysis and curative treatment in HS?","a":"Extravascular haemolysis with jaundice and pigment gallstones; splenectomy is curative.","img":null,"pyq":true},{"id":"p25","subject":"pathology","topic":"Iron Deficiency Anaemia","q":"Iron studies in iron deficiency anaemia?","a":"Low ferritin and serum iron with a high TIBC; microcytic hypochromic cells and pencil cells on smear.","img":null,"pyq":true},{"id":"p26","subject":"pathology","topic":"Iron Deficiency Anaemia","q":"Clinical signs of iron deficiency anaemia?","a":"Koilonychia, pica and the Plummer-Vinson syndrome (oesophageal web with dysphagia).","img":null,"pyq":true},{"id":"p27","subject":"pathology","topic":"Megaloblastic Anaemia","q":"Cause and blood findings in megaloblastic anaemia?","a":"B12 or folate deficiency causing macrocytosis with hypersegmented neutrophils and marrow megaloblasts.","img":null,"pyq":true},{"id":"p28","subject":"pathology","topic":"Megaloblastic Anaemia","q":"Distinguishing feature of B12 deficiency?","a":"Neurological subacute combined degeneration; pernicious anaemia is due to anti-intrinsic-factor antibodies.","img":null,"pyq":true},{"id":"p29","subject":"pathology","topic":"Paroxysmal Nocturnal Haemoglobinuria","q":"Mechanism of PNH?","a":"Acquired PIGA mutation removes the GPI anchor (loss of CD55/CD59), causing complement-mediated intravascular haemolysis, morning haemoglobinuria and thrombosis.","img":null,"pyq":true},{"id":"p30","subject":"pathology","topic":"Haemophilia","q":"Defect and lab profile of haemophilia A?","a":"Factor VIII deficiency, X-linked recessive; prolonged aPTT with normal PT, causing haemarthrosis.","img":null,"pyq":true},{"id":"p31","subject":"pathology","topic":"Haemophilia","q":"Which factor is deficient in haemophilia B?","a":"Factor IX (Christmas disease).","img":null,"pyq":true},{"id":"p32","subject":"pathology","topic":"von Willebrand Disease","q":"Why is von Willebrand disease the commonest inherited bleeding disorder's prototype?","a":"Defective platelet adhesion from deficient vWF; prolonged bleeding time and aPTT; abnormal ristocetin test; usually autosomal dominant.","img":null,"pyq":true},{"id":"p33","subject":"pathology","topic":"Transfusion Complications","q":"Common immediate transfusion reactions?","a":"Acute haemolytic (ABO mismatch), febrile non-haemolytic (commonest), allergic/anaphylactic and TRALI.","img":null,"pyq":true},{"id":"p34","subject":"pathology","topic":"Transfusion Complications","q":"Metabolic complications of massive transfusion?","a":"Hypocalcaemia (citrate), hyperkalaemia and hypothermia.","img":null,"pyq":true},{"id":"p35","subject":"pathology","topic":"Haematological Parameters","q":"Normal red-cell indices and a key exception?","a":"MCV 80-100 fL and MCHC 33-37 g/dL; MCHC is raised in hereditary spherocytosis; reticulocyte count reflects marrow response.","img":null,"pyq":true},{"id":"p36","subject":"pathology","topic":"Langerhans Cell Histiocytosis","q":"Diagnostic ultrastructure and markers of LCH?","a":"Birbeck (tennis-racket) granules; cells are CD1a+, S100+ and Langerin (CD207)+.","img":null,"pyq":true},{"id":"p37","subject":"pathology","topic":"Langerhans Cell Histiocytosis","q":"Clinical forms of Langerhans cell histiocytosis?","a":"Eosinophilic granuloma (localised), Hand-Schuller-Christian and the aggressive Letterer-Siwe disease.","img":null,"pyq":true},{"id":"p38","subject":"pathology","topic":"Thymoma","q":"Key associations of thymoma?","a":"An anterior mediastinal mass linked to myasthenia gravis, pure red-cell aplasia and hypogammaglobulinaemia.","img":null,"pyq":true},{"id":"p39","subject":"pathology","topic":"Carcinogenesis","q":"Stages and major classes of carcinogens?","a":"Multistep initiation, promotion and progression; chemical (e.g. aflatoxin), physical (radiation) and viral carcinogens.","img":null,"pyq":true},{"id":"p40","subject":"pathology","topic":"Carcinogenesis","q":"Two classic chemical carcinogen associations?","a":"Aflatoxin (p53 mutation) causes hepatocellular carcinoma; vinyl chloride causes hepatic angiosarcoma.","img":null,"pyq":true},{"id":"p41","subject":"pathology","topic":"Oncogenes","q":"How do oncogenes drive cancer, with examples?","a":"They are gain-of-function genes - RAS, MYC, HER2/neu (breast), BCL2 (anti-apoptotic) and ABL.","img":null,"pyq":true},{"id":"p42","subject":"pathology","topic":"Oncogenes","q":"Contrast with tumour-suppressor genes?","a":"Tumour suppressors are loss-of-function (two-hit) genes: p53 (guardian of the genome), RB, APC and BRCA.","img":null,"pyq":true},{"id":"p43","subject":"pathology","topic":"Cell Adaptations","q":"Name the main reversible cellular adaptations.","a":"Hyperplasia, hypertrophy, atrophy and metaplasia (e.g. Barrett's oesophagus).","img":null,"pyq":true},{"id":"p44","subject":"pathology","topic":"Cell Injury","q":"Reversible vs irreversible cell injury?","a":"Reversible: cell swelling and fatty change. Irreversible: severe mitochondrial damage, membrane defects and massive calcium influx.","img":null,"pyq":true},{"id":"p45","subject":"pathology","topic":"Cell Injury","q":"Commonest cause of cell injury?","a":"Hypoxia/ischaemia.","img":null,"pyq":true},{"id":"p46","subject":"pathology","topic":"Necrosis","q":"Match necrosis types to classic settings.","a":"Coagulative (MI), liquefactive (brain, abscess), caseous (TB), fat (pancreatitis) and fibrinoid (vessel walls).","img":null,"pyq":true},{"id":"p47","subject":"pathology","topic":"Acute Inflammation","q":"Two components of the acute inflammatory response?","a":"Vascular changes (vasodilation, increased permeability) and a cellular response dominated by neutrophils.","img":null,"pyq":true},{"id":"p48","subject":"pathology","topic":"Acute Inflammation","q":"Key chemical mediators of acute inflammation?","a":"Histamine, prostaglandins, leukotrienes, bradykinin and complement anaphylatoxins C3a/C5a.","img":null,"pyq":true},{"id":"p49","subject":"pathology","topic":"CD Markers","q":"Match key CD markers to their cells.","a":"CD4 (helper T), CD8 (cytotoxic T), CD19/20 (B cells), CD15/CD30 (Reed-Sternberg), CD1a (Langerhans).","img":null,"pyq":true},{"id":"p50","subject":"pathology","topic":"CD Markers","q":"Therapeutically/clinically useful CD markers?","a":"CD20 is the rituximab target, CD117/c-KIT marks GIST, and CD56 marks NK cells.","img":null,"pyq":true},{"id":"p51","subject":"pathology","topic":"Complement System","q":"Three activation pathways of complement and their convergence?","a":"Classical (antigen-antibody/C1), alternative and lectin pathways converge on C3, forming the C5-9 membrane attack complex; C3a/C5a are anaphylatoxins.","img":null,"pyq":true},{"id":"p52","subject":"pathology","topic":"Germ Cell Tumours","q":"Tumour markers across germ-cell tumours?","a":"Yolk-sac tumour raises AFP (Schiller-Duval bodies), choriocarcinoma raises beta-hCG, seminoma may raise placental ALP.","img":null,"pyq":true},{"id":"p53","subject":"pathology","topic":"Occupational Lung Disease","q":"Name the major pneumoconioses.","a":"Coal-worker's (anthracosis), silicosis and asbestosis.","img":null,"pyq":true},{"id":"p54","subject":"pathology","topic":"Occupational Lung Disease","q":"Hallmarks of asbestosis?","a":"Ferruginous bodies and pleural plaques, with risk of both mesothelioma and bronchogenic carcinoma.","img":null,"pyq":true},{"id":"p55","subject":"pathology","topic":"Occupational Lung Disease","q":"Why is silicosis important beyond fibrosis?","a":"Silicotic nodules with eggshell calcification and a markedly increased susceptibility to tuberculosis.","img":null,"pyq":true},{"id":"p56","subject":"pathology","topic":"Lung Carcinoma","q":"Key features of small-cell lung carcinoma?","a":"Central, neuroendocrine origin, strongly smoking-related, with paraneoplastic SIADH and ectopic ACTH.","img":null,"pyq":true},{"id":"p57","subject":"pathology","topic":"Lung Carcinoma","q":"Distinguish the non-small-cell subtypes.","a":"Squamous (central, cavitating, PTHrP hypercalcaemia), adenocarcinoma (peripheral, commonest in non-smokers) and large-cell.","img":null,"pyq":true},{"id":"p58","subject":"pathology","topic":"Lung Carcinoma","q":"Two classic lung-cancer syndromes?","a":"Pancoast tumour causing Horner's syndrome, and superior vena cava syndrome.","img":null,"pyq":true},{"id":"p59","subject":"pathology","topic":"Miliary Tuberculosis","q":"What characterises miliary tuberculosis?","a":"Haematogenous dissemination producing millet-seed caseating granulomas with Langhans giant cells.","img":null,"pyq":true},{"id":"p60","subject":"pathology","topic":"Pap Smear","q":"Purpose and key finding of a Pap smear?","a":"Cervical cancer screening detecting dysplasia (CIN); koilocytes indicate HPV infection.","img":null,"pyq":true},{"id":"p61","subject":"pathology","topic":"Pap Smear","q":"Which HPV types and cancer link?","a":"HPV 16 and 18 drive cervical squamous carcinoma; vaccination is preventive.","img":null,"pyq":true},{"id":"p62","subject":"pathology","topic":"Post-streptococcal GN","q":"Immunology and biopsy findings of PSGN?","a":"A nephritic syndrome after Group A strep; subepithelial humps on EM, lumpy-bumpy IgG/C3 on IF, and low serum C3.","img":null,"pyq":true},{"id":"p63","subject":"pathology","topic":"Post-streptococcal GN","q":"Clinical picture of post-streptococcal glomerulonephritis?","a":"Children with haematuria, RBC casts, hypertension and periorbital oedema.","img":null,"pyq":true},{"id":"p64","subject":"pathology","topic":"Nephrotic Syndrome","q":"Defining features of nephrotic syndrome?","a":"Proteinuria over 3.5 g/day, hypoalbuminaemia, oedema, hyperlipidaemia and lipiduria (oval fat bodies).","img":null,"pyq":true},{"id":"p65","subject":"pathology","topic":"Nephrotic Syndrome","q":"Common causes by age?","a":"Minimal change disease in children; FSGS, membranous nephropathy and diabetic nephropathy in adults.","img":null,"pyq":true},{"id":"p66","subject":"pathology","topic":"Minimal Change Disease","q":"Hallmark of minimal change disease?","a":"Commonest nephrotic syndrome in children; effacement of podocyte foot processes on EM with normal light microscopy; steroid-responsive.","img":null,"pyq":true},{"id":"p67","subject":"pathology","topic":"Cystitis","q":"Common cause and special form of cystitis?","a":"Usually E. coli, giving dysuria and frequency; haemorrhagic cystitis follows cyclophosphamide or adenovirus.","img":null,"pyq":true},{"id":"p68","subject":"pathology","topic":"Bladder Carcinoma","q":"Commonest type and risk factors for bladder cancer?","a":"Urothelial (transitional cell) carcinoma presenting with painless haematuria; risks include smoking and aniline dyes.","img":null,"pyq":true},{"id":"p69","subject":"pathology","topic":"Bladder Carcinoma","q":"Which infection causes squamous bladder cancer?","a":"Schistosoma haematobium.","img":null,"pyq":true},{"id":"p70","subject":"pathology","topic":"Renal Cell Carcinoma","q":"Commonest subtype and genetics of RCC?","a":"Clear-cell carcinoma arising from the proximal tubule, linked to the VHL gene on chromosome 3p.","img":null,"pyq":true},{"id":"p71","subject":"pathology","topic":"Renal Cell Carcinoma","q":"Classic presentation of renal cell carcinoma?","a":"Triad of haematuria, flank pain and a mass; renal-vein invasion can cause a left varicocele; paraneoplastic EPO/PTHrP.","img":null,"pyq":true},{"id":"p72","subject":"pathology","topic":"Hashimoto's Thyroiditis","q":"Antibodies and histology of Hashimoto's thyroiditis?","a":"Anti-TPO and anti-thyroglobulin antibodies; lymphocytic infiltrate with germinal centres and Hurthle cells.","img":null,"pyq":true},{"id":"p73","subject":"pathology","topic":"Hashimoto's Thyroiditis","q":"A long-term risk of Hashimoto's thyroiditis?","a":"B-cell (MALT) lymphoma of the thyroid.","img":null,"pyq":true},{"id":"p74","subject":"pathology","topic":"Thyroid Carcinoma","q":"Features of papillary thyroid carcinoma?","a":"Commonest type; Orphan-Annie-eye nuclei, nuclear grooves and psammoma bodies; lymphatic spread and good prognosis.","img":null,"pyq":true},{"id":"p75","subject":"pathology","topic":"Thyroid Carcinoma","q":"Contrast follicular and medullary thyroid carcinoma.","a":"Follicular spreads haematogenously with capsular invasion; medullary arises from C cells, secretes calcitonin with amyloid, and is linked to MEN2.","img":null,"pyq":true},{"id":"p76","subject":"pathology","topic":"Thyroid Carcinoma","q":"Worst-prognosis thyroid cancer?","a":"Anaplastic carcinoma in the elderly - highly aggressive.","img":null,"pyq":true},{"id":"p77","subject":"pathology","topic":"Turner Syndrome","q":"Karyotype and key features of Turner syndrome?","a":"45,X0 with short stature, webbed neck (cystic hygroma), streak ovaries, coarctation and primary amenorrhoea.","img":null,"pyq":true},{"id":"p78","subject":"pathology","topic":"Turner Syndrome","q":"Commonest mechanism and a renal association?","a":"Loss of an X (often paternal) through nondisjunction; horseshoe kidney is associated.","img":null,"pyq":true},{"id":"p79","subject":"pathology","topic":"Fragile X Syndrome","q":"Genetics and phenotype of fragile X syndrome?","a":"CGG trinucleotide-repeat expansion in FMR1; commonest inherited intellectual disability with macro-orchidism, long face and large ears.","img":null,"pyq":true},{"id":"p80","subject":"pathology","topic":"Down Syndrome","q":"Genetics and features of Down syndrome?","a":"Trisomy 21 (usually maternal nondisjunction); flat facies, single palmar crease and AV septal defect.","img":null,"pyq":true},{"id":"p81","subject":"pathology","topic":"Down Syndrome","q":"Important associations of Down syndrome?","a":"Increased risk of ALL/AML, early Alzheimer's and duodenal atresia; low maternal serum AFP.","img":null,"pyq":true},{"id":"p82","subject":"pathology","topic":"Huntington's Disease","q":"Genetics and pathology of Huntington's disease?","a":"CAG repeat expansion in HTT on chromosome 4, autosomal dominant with anticipation; caudate atrophy causing chorea and dementia.","img":null,"pyq":true},{"id":"p83","subject":"pathology","topic":"Hirschsprung's Disease","q":"Defect and presentation of Hirschsprung's disease?","a":"Absent ganglion cells (failed neural-crest migration) in the rectosigmoid; linked to RET; failure to pass meconium.","img":null,"pyq":true},{"id":"p84","subject":"pathology","topic":"Gastric Carcinoma","q":"Two histological types of gastric carcinoma?","a":"Intestinal type (H. pylori, intestinal metaplasia) and diffuse type (signet-ring cells, linitis plastica).","img":null,"pyq":true},{"id":"p85","subject":"pathology","topic":"Gastric Carcinoma","q":"Classic metastatic signs of gastric cancer?","a":"Virchow's node, Krukenberg tumour (ovary) and the Sister Mary Joseph nodule.","img":null,"pyq":true},{"id":"p86","subject":"pathology","topic":"Pancreatic Carcinoma","q":"Features and markers of pancreatic carcinoma?","a":"Ductal adenocarcinoma (usually head); marker CA 19-9; Courvoisier sign and Trousseau migratory thrombophlebitis; KRAS mutation.","img":null,"pyq":true},{"id":"p87","subject":"pathology","topic":"Rheumatic Fever","q":"Pathology hallmark of rheumatic fever?","a":"Aschoff bodies with Anitschkow cells following Group A strep, classically affecting the mitral valve.","img":null,"pyq":true},{"id":"p88","subject":"pathology","topic":"Rheumatic Fever","q":"Diagnosis and chronic sequela of rheumatic fever?","a":"Jones criteria (molecular mimicry); recurrence leads to mitral stenosis.","img":null,"pyq":true},{"id":"p89","subject":"pathology","topic":"Infective Endocarditis","q":"Acute vs subacute infective endocarditis organisms?","a":"Acute - Staph aureus; subacute - Strep viridans; IV drug users get tricuspid involvement.","img":null,"pyq":true},{"id":"p90","subject":"pathology","topic":"Infective Endocarditis","q":"Peripheral signs and diagnostic criteria of IE?","a":"Roth spots, Janeway lesions, Osler nodes and splinter haemorrhages; diagnosed by the Duke criteria.","img":null,"pyq":true},{"id":"p91","subject":"pathology","topic":"Kawasaki Disease","q":"Features and treatment of Kawasaki disease?","a":"Medium-vessel vasculitis in children: fever, conjunctivitis, rash, strawberry tongue and cervical nodes; risks coronary aneurysms; treated with IVIG and aspirin.","img":null,"pyq":true},{"id":"p92","subject":"pathology","topic":"Dilated Cardiomyopathy","q":"Pathology and causes of dilated cardiomyopathy?","a":"Dilated ventricles with systolic dysfunction (eccentric hypertrophy); causes include alcohol, coxsackie myocarditis, peripartum state and doxorubicin.","img":null,"pyq":true},{"id":"p93","subject":"pathology","topic":"Hemochromatosis","q":"Defect and clinical triad of hereditary haemochromatosis?","a":"HFE-gene iron overload causing 'bronze diabetes', cirrhosis, cardiomyopathy and arthropathy; raised ferritin and transferrin saturation.","img":null,"pyq":true},{"id":"p94","subject":"pathology","topic":"Hemochromatosis","q":"Useful stain and key risk in haemochromatosis?","a":"Prussian-blue stain shows iron; there is a high risk of hepatocellular carcinoma.","img":null,"pyq":true},{"id":"p95","subject":"pathology","topic":"Peripheral Smear","q":"Smallest and largest normal white blood cells?","a":"Lymphocyte is the smallest (round nucleus, scant cytoplasm); monocyte is the largest (reniform nucleus).","img":null,"pyq":false},{"id":"p96","subject":"pathology","topic":"Bone Marrow Examination","q":"Preferred marrow aspiration sites in adults vs children?","a":"Adults: posterior iliac crest (PSIS) > sternum. Children: tibia.","img":null,"pyq":false},{"id":"p97","subject":"pathology","topic":"Dry Tap","q":"Causes of a 'dry tap' on marrow aspiration?","a":"Aplastic anaemia, myelofibrosis, hairy-cell leukaemia and marrow infiltration (granuloma/metastasis).","img":null,"pyq":false},{"id":"p98","subject":"pathology","topic":"Acute Lymphoblastic Leukaemia","q":"Markers and prognosis of ALL?","a":"TdT+ blasts; B-ALL (CD19,20,22,CALLA) and T-ALL (CD2,3,5,7); commonest childhood leukaemia; t(12;21) is favourable.","img":null,"pyq":false},{"id":"p99","subject":"pathology","topic":"Hairy Cell Leukaemia","q":"Hallmarks of hairy cell leukaemia?","a":"B-cell neoplasm with hairy cytoplasmic projections; TRAP-positive; dry tap; massive splenomegaly; BRAF mutation.","img":null,"pyq":false},{"id":"p100","subject":"pathology","topic":"Leukemoid Reaction","q":"Leukemoid reaction vs CML?","a":"Both show high WBC, but a leukemoid reaction has a HIGH LAP score while CML has a LOW LAP score and the Philadelphia chromosome.","img":null,"pyq":false},{"id":"p101","subject":"pathology","topic":"Myelofibrosis","q":"Smear hallmark of primary myelofibrosis?","a":"Teardrop cells (dacrocytes) with a leucoerythroblastic picture; marrow fibrosis; JAK2 mutation.","img":null,"pyq":false},{"id":"p102","subject":"pathology","topic":"Polycythaemia Vera","q":"Defining mutation and features of polycythaemia vera?","a":"JAK2 V617F; raised red-cell mass with LOW erythropoietin; aquagenic pruritus and thrombosis.","img":null,"pyq":false},{"id":"p103","subject":"pathology","topic":"Myelodysplastic Syndrome","q":"What characterises myelodysplastic syndrome?","a":"Ineffective haematopoiesis with cytopenias and ring sideroblasts; risk of transformation to AML.","img":null,"pyq":false},{"id":"p104","subject":"pathology","topic":"G6PD Deficiency","q":"Smear findings and triggers in G6PD deficiency?","a":"Bite cells and Heinz bodies; X-linked; haemolysis triggered by infections, fava beans and oxidant drugs.","img":null,"pyq":false},{"id":"p105","subject":"pathology","topic":"Autoimmune Haemolytic Anaemia","q":"Warm vs cold autoimmune haemolytic anaemia?","a":"Warm AIHA is IgG-mediated (extravascular, spherocytes); cold AIHA is IgM-mediated (agglutination; Mycoplasma, EBV).","img":null,"pyq":false},{"id":"p106","subject":"pathology","topic":"Microangiopathic Haemolysis","q":"Hallmark cell of microangiopathic haemolytic anaemia?","a":"Schistocytes (helmet cells) - seen in DIC, TTP and HUS.","img":null,"pyq":false},{"id":"p107","subject":"pathology","topic":"Anaemia of Chronic Disease","q":"Iron profile in anaemia of chronic disease?","a":"Low serum iron and TIBC with a HIGH ferritin; hepcidin traps iron in stores.","img":null,"pyq":false},{"id":"p108","subject":"pathology","topic":"Sideroblastic Anaemia","q":"Defining marrow finding in sideroblastic anaemia?","a":"Ring sideroblasts (iron-laden mitochondria around the nucleus) on Prussian-blue stain.","img":null,"pyq":false},{"id":"p109","subject":"pathology","topic":"Blood Groups","q":"Basis of the ABO and Rh systems?","a":"ABO antigens with naturally occurring isohaemagglutinins; Rh(D) status matters for transfusion and pregnancy.","img":null,"pyq":false},{"id":"p110","subject":"pathology","topic":"Haemolytic Disease of Newborn","q":"Mechanism of Rh haemolytic disease of the newborn?","a":"Maternal anti-D IgG crosses the placenta in a sensitised Rh-negative mother with an Rh-positive fetus; prevented by anti-D.","img":null,"pyq":false},{"id":"p111","subject":"pathology","topic":"Disseminated Intravascular Coagulation","q":"Lab picture of DIC?","a":"Low platelets and fibrinogen, prolonged PT/aPTT, raised D-dimer, with schistocytes; triggers include sepsis and malignancy.","img":null,"pyq":false},{"id":"p112","subject":"pathology","topic":"Immune Thrombocytopenia","q":"Features of immune thrombocytopenic purpura?","a":"Anti-platelet antibodies causing isolated thrombocytopenia with normal/raised marrow megakaryocytes; petechiae.","img":null,"pyq":false},{"id":"p113","subject":"pathology","topic":"Thrombotic Thrombocytopenic Purpura","q":"Defect and pentad of TTP?","a":"ADAMTS13 deficiency; fever, microangiopathic haemolysis, thrombocytopenia, renal and neurological signs.","img":null,"pyq":false},{"id":"p114","subject":"pathology","topic":"Coagulation Tests","q":"What do PT and aPTT assess?","a":"PT/INR tests the extrinsic pathway (VII, warfarin); aPTT tests the intrinsic pathway (VIII, IX, heparin).","img":null,"pyq":false},{"id":"p115","subject":"pathology","topic":"Platelet Function Disorders","q":"Bernard-Soulier vs Glanzmann thrombasthenia?","a":"Bernard-Soulier: GpIb defect (adhesion). Glanzmann: GpIIb/IIIa defect (aggregation).","img":null,"pyq":false},{"id":"p116","subject":"pathology","topic":"Reticulocyte Count","q":"What does the reticulocyte count indicate?","a":"Marrow red-cell production: high in haemolysis or blood loss, low in marrow failure.","img":null,"pyq":false},{"id":"p117","subject":"pathology","topic":"Anticoagulant Monitoring","q":"Monitoring and reversal of heparin vs warfarin?","a":"Heparin: aPTT, reversed by protamine. Warfarin: PT/INR, reversed by vitamin K.","img":null,"pyq":false},{"id":"p118","subject":"pathology","topic":"Leukaemia Overview","q":"Acute vs chronic leukaemia?","a":"Acute: blasts predominate, rapid (ALL, AML). Chronic: more mature cells, indolent (CML, CLL).","img":null,"pyq":false},{"id":"p119","subject":"pathology","topic":"Apoptosis","q":"Two pathways of apoptosis?","a":"Intrinsic (mitochondrial, Bcl-2, cytochrome c) and extrinsic (death-receptor, Fas/TNF); both activate caspases.","img":null,"pyq":false},{"id":"p120","subject":"pathology","topic":"Apoptosis vs Necrosis","q":"Key differences between apoptosis and necrosis?","a":"Apoptosis: programmed, energy-dependent, single cells, no inflammation. Necrosis: passive, groups of cells, incites inflammation.","img":null,"pyq":false},{"id":"p121","subject":"pathology","topic":"Free Radical Injury","q":"How do free radicals injure cells, and what scavenges them?","a":"Lipid peroxidation and DNA/protein damage; scavenged by superoxide dismutase, catalase, glutathione and vitamins A/C/E.","img":null,"pyq":false},{"id":"p122","subject":"pathology","topic":"Intracellular Accumulations","q":"Common intracellular pigments and their meaning?","a":"Lipofuscin (wear-and-tear), haemosiderin (iron overload), melanin and bilirubin.","img":null,"pyq":false},{"id":"p123","subject":"pathology","topic":"Pathologic Calcification","q":"Dystrophic vs metastatic calcification?","a":"Dystrophic occurs in damaged tissue with normal calcium; metastatic occurs in normal tissue with hypercalcaemia.","img":null,"pyq":false},{"id":"p124","subject":"pathology","topic":"Amyloidosis","q":"Diagnosis and main types of amyloidosis?","a":"Congo-red stain gives apple-green birefringence; AL (light chains, myeloma) and AA (chronic inflammation).","img":null,"pyq":false},{"id":"p125","subject":"pathology","topic":"Chronic Inflammation","q":"Cells and hallmark of chronic inflammation?","a":"Macrophages, lymphocytes and plasma cells, with granuloma formation in granulomatous types.","img":null,"pyq":false},{"id":"p126","subject":"pathology","topic":"Granuloma","q":"Caseating vs non-caseating granulomas?","a":"Caseating: TB, fungal. Non-caseating: sarcoidosis, Crohn's, foreign-body reaction.","img":null,"pyq":false},{"id":"p127","subject":"pathology","topic":"Wound Healing","q":"Healing by primary vs secondary intention?","a":"Primary: clean apposed wound, minimal scar. Secondary: gaping wound with granulation tissue and contraction.","img":null,"pyq":false},{"id":"p128","subject":"pathology","topic":"Cell Regeneration","q":"Classify cells by regenerative capacity.","a":"Labile (gut, skin), stable (liver, kidney) and permanent (neurons, cardiac muscle).","img":null,"pyq":false},{"id":"p129","subject":"pathology","topic":"Neoplasia Nomenclature","q":"Benign vs malignant tumour naming?","a":"Benign uses '-oma'; malignant epithelial = carcinoma, malignant mesenchymal = sarcoma.","img":null,"pyq":false},{"id":"p130","subject":"pathology","topic":"Grading vs Staging","q":"Difference between grading and staging of tumours?","a":"Grade reflects differentiation; stage (TNM) reflects size, nodal and metastatic spread - stage predicts prognosis best.","img":null,"pyq":false},{"id":"p131","subject":"pathology","topic":"Tumour Markers","q":"Match common tumour markers to cancers.","a":"AFP (liver, yolk sac), CEA (colorectal), PSA (prostate), CA-125 (ovary), CA 19-9 (pancreas), beta-hCG (trophoblastic).","img":null,"pyq":false},{"id":"p132","subject":"pathology","topic":"Paraneoplastic Syndromes","q":"Classic paraneoplastic associations?","a":"Small-cell lung: SIADH, ectopic ACTH, Lambert-Eaton; squamous/renal: PTHrP hypercalcaemia.","img":null,"pyq":false},{"id":"p133","subject":"pathology","topic":"Metastasis","q":"Routes of tumour spread?","a":"Lymphatic (carcinomas), haematogenous (sarcomas) and transcoelomic seeding.","img":null,"pyq":false},{"id":"p134","subject":"pathology","topic":"Hallmarks of Cancer","q":"Name key hallmarks of cancer.","a":"Growth-signal self-sufficiency, evading apoptosis, limitless replication (telomerase), angiogenesis, invasion and metastasis.","img":null,"pyq":false},{"id":"p135","subject":"pathology","topic":"Hypersensitivity","q":"Classify the four hypersensitivity reactions.","a":"Type I (IgE, anaphylaxis), II (cytotoxic antibody), III (immune complex), IV (delayed, T-cell).","img":null,"pyq":false},{"id":"p136","subject":"pathology","topic":"Type III Hypersensitivity","q":"Examples of immune-complex (type III) reactions?","a":"SLE, post-streptococcal GN, serum sickness and the Arthus reaction.","img":null,"pyq":false},{"id":"p137","subject":"pathology","topic":"Systemic Lupus Erythematosus","q":"Key antibodies in SLE?","a":"ANA (sensitive screen), anti-dsDNA and anti-Smith (specific); antiphospholipid antibodies cause thrombosis.","img":null,"pyq":false},{"id":"p138","subject":"pathology","topic":"Primary Immunodeficiency","q":"Match immunodeficiencies to their defects.","a":"Bruton (BTK, no B cells), DiGeorge (no thymus/T cells), SCID, chronic granulomatous disease (NADPH oxidase).","img":null,"pyq":false},{"id":"p139","subject":"pathology","topic":"Transplant Rejection","q":"Types of graft rejection by timing?","a":"Hyperacute (minutes, preformed antibody), acute (weeks, T-cell), chronic (months-years, fibrosis).","img":null,"pyq":false},{"id":"p140","subject":"pathology","topic":"Innate vs Adaptive Immunity","q":"Distinguish innate and adaptive immunity.","a":"Innate: rapid, non-specific (neutrophils, complement, NK). Adaptive: slower, specific, with memory (T and B cells).","img":null,"pyq":false},{"id":"p141","subject":"pathology","topic":"Mendelian Inheritance","q":"Autosomal dominant vs recessive features?","a":"Dominant: vertical transmission, often structural proteins. Recessive: consanguinity, often enzyme deficiencies.","img":null,"pyq":false},{"id":"p142","subject":"pathology","topic":"Genomic Imprinting","q":"Prader-Willi vs Angelman syndrome?","a":"Both involve 15q: Prader-Willi from paternal deletion, Angelman from maternal deletion.","img":null,"pyq":false},{"id":"p143","subject":"pathology","topic":"Trinucleotide Repeat Disorders","q":"Name trinucleotide-repeat diseases.","a":"Huntington (CAG), fragile X (CGG), myotonic dystrophy (CTG), Friedreich ataxia (GAA); they show anticipation.","img":null,"pyq":false},{"id":"p144","subject":"pathology","topic":"Atherosclerosis","q":"Pathogenesis and common sites of atherosclerosis?","a":"Endothelial injury with lipid-laden fibrofatty plaques; commonest in abdominal aorta, coronary and carotid arteries.","img":null,"pyq":false},{"id":"p145","subject":"pathology","topic":"Myocardial Infarction","q":"Time course of histological changes after MI?","a":"Contraction bands (hours), neutrophils (1-3 days), macrophages (3-7 days), granulation tissue (1-2 weeks), scar (months).","img":null,"pyq":false},{"id":"p146","subject":"pathology","topic":"Cardiac Biomarkers","q":"Most specific biomarker for myocardial infarction?","a":"Cardiac troponin I/T - rises in 3-4 h, peaks at 24 h, stays raised 7-10 days.","img":null,"pyq":false},{"id":"p147","subject":"pathology","topic":"Vasculitis Classification","q":"Classify vasculitis by vessel size.","a":"Large (Takayasu, giant-cell), medium (PAN, Kawasaki, Buerger), small (GPA, microscopic polyangiitis, EGPA, HSP).","img":null,"pyq":false},{"id":"p148","subject":"pathology","topic":"Giant Cell Arteritis","q":"Features of giant-cell (temporal) arteritis?","a":"Elderly with headache, jaw claudication and visual loss; high ESR; treat urgently with steroids to prevent blindness.","img":null,"pyq":false},{"id":"p149","subject":"pathology","topic":"Polyarteritis Nodosa","q":"Associations of polyarteritis nodosa?","a":"Medium-vessel necrotizing vasculitis linked to hepatitis B; spares the lungs; 'rosary-bead' aneurysms.","img":null,"pyq":false},{"id":"p150","subject":"pathology","topic":"Aortic Aneurysm","q":"Abdominal aortic aneurysm - cause and rupture risk?","a":"Atherosclerosis-related; rupture risk rises sharply above 5.5 cm; syphilis classically causes thoracic aneurysm.","img":null,"pyq":false},{"id":"p151","subject":"pathology","topic":"Hypertensive Heart Disease","q":"Cardiac effect of chronic hypertension?","a":"Concentric left-ventricular hypertrophy progressing to heart failure.","img":null,"pyq":false},{"id":"p152","subject":"pathology","topic":"Valvular Heart Disease","q":"Commonest valve lesion and a key rheumatic lesion?","a":"Calcific aortic stenosis in the elderly; rheumatic disease classically causes mitral stenosis.","img":null,"pyq":false},{"id":"p153","subject":"pathology","topic":"Hypertrophic Cardiomyopathy","q":"Pathology of hypertrophic cardiomyopathy?","a":"Asymmetric septal hypertrophy with myofibre disarray; sarcomere mutations; sudden death in young athletes.","img":null,"pyq":false},{"id":"p154","subject":"pathology","topic":"Restrictive Cardiomyopathy","q":"Causes of restrictive cardiomyopathy?","a":"Amyloidosis, sarcoidosis, haemochromatosis, endomyocardial fibrosis - stiff ventricles with impaired filling.","img":null,"pyq":false},{"id":"p155","subject":"pathology","topic":"Cardiac Myxoma","q":"Commonest primary cardiac tumour?","a":"Left-atrial myxoma causing 'ball-valve' obstruction; gelatinous with scattered stellate cells.","img":null,"pyq":false},{"id":"p156","subject":"pathology","topic":"Alzheimer Disease","q":"Pathological hallmarks of Alzheimer disease?","a":"Beta-amyloid senile plaques and neurofibrillary tangles of hyperphosphorylated tau; cortical atrophy.","img":null,"pyq":false},{"id":"p157","subject":"pathology","topic":"Parkinson Disease","q":"Pathology of Parkinson disease?","a":"Loss of substantia nigra dopaminergic neurons with Lewy bodies (alpha-synuclein).","img":null,"pyq":false},{"id":"p158","subject":"pathology","topic":"Multiple Sclerosis","q":"Features of multiple sclerosis?","a":"Autoimmune CNS demyelination; periventricular plaques; oligoclonal IgG bands in CSF.","img":null,"pyq":false},{"id":"p159","subject":"pathology","topic":"Glioblastoma","q":"Commonest primary malignant brain tumour?","a":"Glioblastoma multiforme - GFAP-positive astrocytoma with necrosis and pseudopalisading.","img":null,"pyq":false},{"id":"p160","subject":"pathology","topic":"Meningioma","q":"Features of meningioma?","a":"Benign extra-axial tumour from arachnoid cells; whorls and psammoma bodies; commoner in women.","img":null,"pyq":false},{"id":"p161","subject":"pathology","topic":"Stroke Pathology","q":"Ischaemic vs haemorrhagic stroke?","a":"Ischaemic shows liquefactive necrosis; haemorrhagic often from hypertension (basal ganglia) or aneurysm rupture.","img":null,"pyq":false},{"id":"p162","subject":"pathology","topic":"Skin Carcinoma","q":"Basal-cell vs squamous-cell carcinoma of skin?","a":"BCC: pearly nodule with telangiectasia, rarely metastasises. SCC: keratin pearls, can metastasise, from actinic keratosis.","img":null,"pyq":false},{"id":"p163","subject":"pathology","topic":"Melanoma","q":"Prognostic factor and warning signs of melanoma?","a":"Breslow depth is the key prognostic factor; ABCDE warning signs.","img":null,"pyq":false},{"id":"p164","subject":"pathology","topic":"Bullous Skin Disease","q":"Pemphigus vulgaris vs bullous pemphigoid?","a":"Pemphigus: intraepidermal, anti-desmoglein, Nikolsky-positive, fish-net IF. Pemphigoid: subepidermal, anti-hemidesmosome, tense bullae.","img":null,"pyq":false},{"id":"p165","subject":"pathology","topic":"COPD","q":"Emphysema vs chronic bronchitis?","a":"Emphysema: alveolar destruction ('pink puffer'). Chronic bronchitis: productive cough >=3 months over 2 years ('blue bloater').","img":null,"pyq":false},{"id":"p166","subject":"pathology","topic":"Bronchial Asthma","q":"Pathology of bronchial asthma?","a":"Type I hypersensitivity bronchospasm; Curschmann spirals and Charcot-Leyden crystals in sputum.","img":null,"pyq":false},{"id":"p167","subject":"pathology","topic":"Pneumonia","q":"Stages of lobar pneumonia?","a":"Congestion, red hepatisation, grey hepatisation and resolution; commonest organism Strep pneumoniae.","img":null,"pyq":false},{"id":"p168","subject":"pathology","topic":"ARDS","q":"Pathology of acute respiratory distress syndrome?","a":"Diffuse alveolar damage with hyaline membranes and refractory hypoxaemia.","img":null,"pyq":false},{"id":"p169","subject":"pathology","topic":"Pulmonary Embolism","q":"Source and effect of pulmonary embolism?","a":"Usually deep-vein thrombi; saddle emboli cause sudden death; infarction if circulation is already compromised.","img":null,"pyq":false},{"id":"p170","subject":"pathology","topic":"Sarcoidosis","q":"Hallmarks of sarcoidosis?","a":"Non-caseating granulomas, bilateral hilar lymphadenopathy, raised ACE and hypercalcaemia; asteroid/Schaumann bodies.","img":null,"pyq":false},{"id":"p171","subject":"pathology","topic":"Mesothelioma","q":"Cause and marker of mesothelioma?","a":"Asbestos exposure; calretinin-positive pleural malignancy.","img":null,"pyq":false},{"id":"p172","subject":"pathology","topic":"Peptic Ulcer Disease","q":"Main causes of peptic ulcer disease?","a":"Helicobacter pylori and NSAIDs; duodenal ulcers commoner and benign, gastric ulcers may be malignant.","img":null,"pyq":false},{"id":"p173","subject":"pathology","topic":"Oesophageal Carcinoma","q":"Squamous vs adenocarcinoma of the oesophagus?","a":"Squamous (upper/middle, smoking/alcohol) vs adenocarcinoma (lower, from Barrett's metaplasia).","img":null,"pyq":false},{"id":"p174","subject":"pathology","topic":"Inflammatory Bowel Disease","q":"Crohn disease vs ulcerative colitis?","a":"Crohn: skip lesions, transmural, granulomas, anywhere. UC: continuous mucosal disease from the rectum, crypt abscesses.","img":null,"pyq":false},{"id":"p175","subject":"pathology","topic":"Colorectal Carcinoma","q":"Adenoma-carcinoma sequence and follow-up marker?","a":"APC, then KRAS, then p53 mutations; right-sided bleeds/anaemia, left-sided obstruction; CEA for follow-up.","img":null,"pyq":false},{"id":"p176","subject":"pathology","topic":"Cirrhosis","q":"Defining features of cirrhosis?","a":"Diffuse fibrosis with regenerative nodules, leading to portal hypertension and liver failure.","img":null,"pyq":false},{"id":"p177","subject":"pathology","topic":"Viral Hepatitis Serology","q":"Interpret key hepatitis B markers.","a":"HBsAg = infection; anti-HBs = immunity; HBeAg = high infectivity; IgM anti-HBc = acute/window.","img":null,"pyq":false},{"id":"p178","subject":"pathology","topic":"Wilson Disease","q":"Features of Wilson disease?","a":"Copper accumulation; low ceruloplasmin; Kayser-Fleischer rings; hepatolenticular degeneration.","img":null,"pyq":false},{"id":"p179","subject":"pathology","topic":"Alpha-1 Antitrypsin Deficiency","q":"Effects of alpha-1 antitrypsin deficiency?","a":"Panacinar emphysema in young non-smokers and liver cirrhosis with PAS-positive globules.","img":null,"pyq":false},{"id":"p180","subject":"pathology","topic":"Acute Pancreatitis","q":"Causes and marker of acute pancreatitis?","a":"Gallstones and alcohol; raised lipase/amylase; fat necrosis with saponification.","img":null,"pyq":false},{"id":"p181","subject":"pathology","topic":"Hepatocellular Carcinoma","q":"Risk factors and marker for HCC?","a":"Cirrhosis, hepatitis B/C and aflatoxin; raised alpha-fetoprotein.","img":null,"pyq":false},{"id":"p182","subject":"pathology","topic":"Jaundice","q":"Classify jaundice by bilirubin type.","a":"Prehepatic (unconjugated, haemolysis), hepatic (mixed), post-hepatic (conjugated, obstruction with pale stools/dark urine).","img":null,"pyq":false},{"id":"p183","subject":"pathology","topic":"Portal Hypertension","q":"Consequences of portal hypertension?","a":"Oesophageal varices, caput medusae, splenomegaly, ascites and haemorrhoids.","img":null,"pyq":false},{"id":"p184","subject":"pathology","topic":"Diabetes Mellitus","q":"Type 1 vs type 2 diabetes pathology?","a":"Type 1: autoimmune beta-cell destruction. Type 2: insulin resistance with islet amyloid.","img":null,"pyq":false},{"id":"p185","subject":"pathology","topic":"Diabetic Complications","q":"Microvascular complications of diabetes?","a":"Retinopathy, nephropathy (Kimmelstiel-Wilson nodules) and neuropathy, from non-enzymatic glycation.","img":null,"pyq":false},{"id":"p186","subject":"pathology","topic":"Cushing Syndrome","q":"Causes of Cushing syndrome?","a":"Exogenous steroids (commonest), pituitary adenoma (Cushing disease), adrenal tumour, ectopic ACTH.","img":null,"pyq":false},{"id":"p187","subject":"pathology","topic":"Phaeochromocytoma","q":"Rule of 10s for phaeochromocytoma?","a":"10% bilateral, malignant, extra-adrenal, familial; raised urinary metanephrines.","img":null,"pyq":false},{"id":"p188","subject":"pathology","topic":"MEN Syndromes","q":"Components of MEN 1, 2A and 2B?","a":"MEN1: parathyroid, pancreas, pituitary. MEN2A: medullary thyroid, phaeo, parathyroid. MEN2B: medullary thyroid, phaeo, mucosal neuromas (RET).","img":null,"pyq":false},{"id":"p189","subject":"pathology","topic":"Pituitary Adenoma","q":"Commonest functioning pituitary adenoma?","a":"Prolactinoma - galactorrhoea, amenorrhoea and bitemporal hemianopia.","img":null,"pyq":false},{"id":"p190","subject":"pathology","topic":"Osteoporosis","q":"Defining feature of osteoporosis?","a":"Reduced bone mass with normal mineralisation; fragility fractures; normal calcium and phosphate.","img":null,"pyq":false},{"id":"p191","subject":"pathology","topic":"Osteosarcoma","q":"Features of osteosarcoma?","a":"Commonest primary bone malignancy in the young; metaphysis of long bones; Codman triangle and sunburst on X-ray.","img":null,"pyq":false},{"id":"p192","subject":"pathology","topic":"Giant Cell Tumour of Bone","q":"Hallmark of giant-cell tumour of bone?","a":"'Soap-bubble' lytic lesion at the epiphysis with osteoclast-like giant cells.","img":null,"pyq":false},{"id":"p193","subject":"pathology","topic":"Gout","q":"Crystal findings in gout?","a":"Monosodium urate crystals - needle-shaped, negatively birefringent; tophi; first MTP joint (podagra).","img":null,"pyq":false},{"id":"p194","subject":"pathology","topic":"Rheumatoid Arthritis","q":"Pathology of rheumatoid arthritis?","a":"Autoimmune synovial pannus; anti-CCP and rheumatoid factor; symmetrical small-joint disease.","img":null,"pyq":false},{"id":"p195","subject":"pathology","topic":"Paget Disease of Bone","q":"Features of Paget disease of bone?","a":"Disordered remodelling with a mosaic pattern; very high ALP; risk of osteosarcoma.","img":null,"pyq":false},{"id":"p196","subject":"pathology","topic":"Breast Carcinoma","q":"Receptors guiding breast-cancer therapy?","a":"ER, PR and HER2 status; triple-negative has the worst prognosis; invasive ductal carcinoma is commonest.","img":null,"pyq":false},{"id":"p197","subject":"pathology","topic":"Fibroadenoma","q":"Commonest benign breast tumour?","a":"Fibroadenoma - a mobile, well-circumscribed 'breast mouse' in young women.","img":null,"pyq":false},{"id":"p198","subject":"pathology","topic":"Benign Prostatic Hyperplasia","q":"Zone affected in BPH vs prostate cancer?","a":"BPH affects the transition zone (obstruction); carcinoma arises in the peripheral zone.","img":null,"pyq":false},{"id":"p199","subject":"pathology","topic":"Prostate Carcinoma","q":"Grading and marker of prostate cancer?","a":"Gleason grading; PSA for screening/follow-up; osteoblastic bony metastases.","img":null,"pyq":false},{"id":"p200","subject":"pathology","topic":"Ovarian Tumours","q":"Marker and a classic metastatic ovarian tumour?","a":"CA-125 for surface epithelial tumours; Krukenberg tumour is metastatic gastric signet-ring cells.","img":null,"pyq":false},{"id":"p201","subject":"pathology","topic":"Endometrial Carcinoma","q":"Risk factors for endometrial carcinoma?","a":"Unopposed oestrogen - obesity, nulliparity, late menopause, PCOS; postmenopausal bleeding.","img":null,"pyq":false},{"id":"p202","subject":"pathology","topic":"Hydatidiform Mole","q":"Complete vs partial hydatidiform mole?","a":"Complete: 46XX all-paternal, no fetus, very high hCG, 'snowstorm', higher malignant risk. Partial: triploid with fetal parts.","img":null,"pyq":false},{"id":"p203","subject":"pathology","topic":"IgA Nephropathy","q":"Commonest primary glomerulonephritis worldwide?","a":"IgA nephropathy (Berger disease) - mesangial IgA; haematuria shortly after a respiratory infection.","img":null,"pyq":false},{"id":"p204","subject":"pathology","topic":"Acute Tubular Necrosis","q":"Commonest cause of intrinsic acute kidney injury?","a":"Acute tubular necrosis (ischaemic or nephrotoxic); muddy-brown granular casts.","img":null,"pyq":false},{"id":"p205","subject":"pathology","topic":"Pyelonephritis","q":"Features of acute pyelonephritis?","a":"Ascending E. coli infection; flank pain, fever, WBC casts; vesicoureteric reflux predisposes.","img":null,"pyq":false},{"id":"p206","subject":"pathology","topic":"Wilms Tumour","q":"Commonest childhood renal malignancy?","a":"Wilms tumour (nephroblastoma); WT1 gene; triphasic histology; abdominal mass in a child.","img":null,"pyq":false},{"id":"p207","subject":"pathology","topic":"Polycystic Kidney Disease","q":"Adult polycystic kidney disease - genetics and associations?","a":"Autosomal dominant (PKD1/PKD2); bilateral cysts, hypertension, berry aneurysms and hepatic cysts.","img":null,"pyq":false},{"id":"p208","subject":"pathology","topic":"Testicular Tumours","q":"Commonest testicular tumour?","a":"Seminoma - radiosensitive, may raise placental ALP, good prognosis.","img":null,"pyq":false}],"pharmacology":[{"id":"ph1","subject":"pharmacology","topic":"Drug Classification","q":"What is an orphan drug?","a":"A drug developed specifically for the treatment of rare diseases.","img":null,"pyq":false},{"id":"ph2","subject":"pharmacology","topic":"Drug Classification","q":"What defines an essential drug?","a":"One that satisfies the majority population's healthcare needs; it is a single molecule, safe, easily available and affordable — not necessarily a fixed-dose combination.","img":null,"pyq":false},{"id":"ph3","subject":"pharmacology","topic":"Drug Classification","q":"Prescription drugs belong to which schedule?","a":"Schedule H; they can only be dispensed against a valid prescription.","img":null,"pyq":false},{"id":"ph4","subject":"pharmacology","topic":"Drug Classification","q":"Distinguish a spurious drug from an adulterated drug.","a":"Spurious: fails to produce adequate response due to deficiency in the drug itself. Adulterated: contains an additional unwanted component.","img":null,"pyq":false},{"id":"ph5","subject":"pharmacology","topic":"Rational Drug Use","q":"State the components of rational drug use.","a":"Right drug, right disease and patient, right dose, right duration, right route, right dispensation and monitoring. (Right price is NOT included.)","img":null,"pyq":false},{"id":"ph6","subject":"pharmacology","topic":"Pharmacokinetics: Absorption","q":"What is the commonest mechanism of drug absorption?","a":"Passive diffusion, which is maximal in the unionised/non-polar (lipid-soluble) state.","img":null,"pyq":false},{"id":"ph7","subject":"pharmacology","topic":"Pharmacokinetics: Absorption","q":"Acidic drugs are best absorbed in which compartment, and why?","a":"In the acidic gastric environment (HCl), because acidity keeps acidic drugs in their unionised, lipid-soluble form.","img":null,"pyq":false},{"id":"ph8","subject":"pharmacology","topic":"Pharmacokinetics: Absorption","q":"Which intestinal segment is responsible for maximum drug absorption?","a":"The duodenum (small intestine), owing to its large surface area.","img":null,"pyq":false},{"id":"ph9","subject":"pharmacology","topic":"Pharmacokinetics: Absorption","q":"Which class of drugs shows poor oral absorption and why?","a":"Proteins and large molecules (peptides ending in -tide, enzymes ending in -ase, and monoclonal antibodies ending in -mab), because they are too large for passive diffusion.","img":null,"pyq":false},{"id":"ph10","subject":"pharmacology","topic":"Pharmacokinetics: Absorption","q":"What is the purpose of enteric-coated tablets?","a":"To protect acid-labile drugs (e.g., PPIs) from gastric acid and to prevent gastric irritation (e.g., aspirin).","img":null,"pyq":false},{"id":"ph11","subject":"pharmacology","topic":"Pharmacokinetics: Absorption","q":"For which type of drugs are sustained-release formulations used?","a":"Drugs with a short half-life (less than 4 hours), to extend their duration of action.","img":null,"pyq":false},{"id":"ph12","subject":"pharmacology","topic":"Pharmacokinetics: Absorption","q":"Define bioavailability (BA).","a":"The fraction of an unchanged drug that reaches the systemic circulation; ranges from 0 (0%) to 1 (100%). Only IV administration gives 100% BA.","img":null,"pyq":false},{"id":"ph13","subject":"pharmacology","topic":"Pharmacokinetics: Absorption","q":"What does AUC (area under the curve) represent?","a":"Bioavailability — the total drug exposure over time.","img":null,"pyq":false},{"id":"ph14","subject":"pharmacology","topic":"Pharmacokinetics: Absorption","q":"What is Tmax, and what does it measure?","a":"The time taken to reach maximum plasma concentration (Cmax); it is a marker of the rate of absorption.","img":null,"pyq":false},{"id":"ph15","subject":"pharmacology","topic":"Pharmacokinetics: Absorption","q":"What is P-glycoprotein (Pgp/MDR-1)?","a":"A membrane efflux pump on intestinal epithelial cells that pumps drugs out of enterocytes, reducing absorption and bioavailability.","img":null,"pyq":false},{"id":"ph16","subject":"pharmacology","topic":"Pharmacokinetics: Absorption","q":"Give examples of Pgp inhibitors (mnemonic VACINE).","a":"Verapamil, Amiodarone, Cyclosporine, Itraconazole, Nifedipine, Erythromycin/Clarithromycin, Quinidine.","img":null,"pyq":false},{"id":"ph17","subject":"pharmacology","topic":"Pharmacokinetics: Distribution","q":"What is apparent volume of distribution (aVD)?","a":"aVD = Dose / Initial plasma concentration. It represents how widely a drug is distributed in the body.","img":null,"pyq":false},{"id":"ph18","subject":"pharmacology","topic":"Pharmacokinetics: Distribution","q":"What factors increase the apparent volume of distribution?","a":"High lipid solubility, greater adipose tissue (obesity), and low plasma protein binding.","img":null,"pyq":false},{"id":"ph19","subject":"pharmacology","topic":"Pharmacokinetics: Distribution","q":"Which plasma protein binds acidic drugs, and which binds basic drugs?","a":"Albumin binds acidic drugs; alpha-1-acid glycoprotein binds basic drugs.","img":null,"pyq":false},{"id":"ph20","subject":"pharmacology","topic":"Pharmacokinetics: Distribution","q":"What determines the loading dose of a drug?","a":"Loading dose = aVD × target plasma concentration.","img":null,"pyq":false},{"id":"ph21","subject":"pharmacology","topic":"Pharmacokinetics: Distribution","q":"Dialysis is ineffective against drugs with high VD — give examples (mnemonic BAD-DOC).","a":"Benzodiazepines, beta-blockers, Amphetamine, Digoxin, (–), Opioids, Organophosphates, Calcium-channel blockers.","img":null,"pyq":false},{"id":"ph22","subject":"pharmacology","topic":"Pharmacokinetics: Metabolism","q":"What is the most common Phase I reaction, and what enzyme catalyses it?","a":"Oxidation, catalysed by CYP450 enzymes (most commonly CYP3A4).","img":null,"pyq":false},{"id":"ph23","subject":"pharmacology","topic":"Pharmacokinetics: Metabolism","q":"What is the most common Phase II reaction?","a":"Glucuronidation, catalysed by glucuronyl transferase.","img":null,"pyq":false},{"id":"ph24","subject":"pharmacology","topic":"Pharmacokinetics: Metabolism","q":"What is the clinical consequence of enzyme induction vs. enzyme inhibition?","a":"Induction → drug failure (faster metabolism). Inhibition → drug toxicity (slower metabolism).","img":null,"pyq":false},{"id":"ph25","subject":"pharmacology","topic":"Pharmacokinetics: Metabolism","q":"Name classic enzyme inducers (mnemonic GRAB Priyanka Chopra).","a":"Griseofulvin, Rifampicin, Alcohol (chronic), Benzopyrene, Phenytoin/Primidone/Phenobarbital, Carbamazepine, Cigarette smoking.","img":null,"pyq":false},{"id":"ph26","subject":"pharmacology","topic":"Pharmacokinetics: Metabolism","q":"Name classic enzyme inhibitors (mnemonic QuICK VEG Dish).","a":"Quinidine, Isoniazid/protease inhibitors, Cimetidine/Chloramphenicol/Ciprofloxacin, Ketoconazole/Itraconazole/Fluconazole, Valproate, Erythromycin/Clarithromycin, Grape juice, DEC/Delavirdine/Disulfiram.","img":null,"pyq":false},{"id":"ph27","subject":"pharmacology","topic":"Pharmacokinetics: Metabolism","q":"Give the mnemonic for drugs metabolised by plasma esterase.","a":"Plasma Esterase Can Readily Metabolise Short Acting drugs: Procaine/Cocaine, Esmolol, Clevidipine, Remifentanil/Remimazolam, Mivacurium, Succinylcholine, Acetylcholine.","img":null,"pyq":false},{"id":"ph28","subject":"pharmacology","topic":"Pharmacokinetics: Excretion","q":"Which organ is responsible for the majority of drug excretion?","a":"The kidney.","img":null,"pyq":false},{"id":"ph29","subject":"pharmacology","topic":"Pharmacokinetics: Excretion","q":"For renal excretion, drugs should be in which state?","a":"Water-soluble, ionised, and polar — and the urine pH should differ from the drug's pKa.","img":null,"pyq":false},{"id":"ph30","subject":"pharmacology","topic":"Pharmacokinetics: Excretion","q":"Compare filtration and tubular secretion in renal excretion.","a":"Filtration accounts for ~20% and excretes only free (unbound) drug. Tubular secretion accounts for ~80% and excretes both free and protein-bound drug.","img":null,"pyq":false},{"id":"ph31","subject":"pharmacology","topic":"Pharmacokinetics: Excretion","q":"Write the formula for half-life (t½).","a":"t½ = 0.693 × VD / Clearance (CL), or equivalently t½ = 0.693 / Ke.","img":null,"pyq":true},{"id":"ph32","subject":"pharmacology","topic":"Zero- vs First-Order Kinetics","q":"What is the key difference between zero-order and first-order kinetics?","a":"Zero-order: a constant amount of drug is eliminated per unit time; clearance falls and half-life rises with increasing dose. First-order: a constant proportion is eliminated per unit time; clearance and half-life remain constant.","img":null,"pyq":false},{"id":"ph33","subject":"pharmacology","topic":"Zero- vs First-Order Kinetics","q":"Which common drugs follow zero-order kinetics?","a":"Alcohol, theophylline, tolbutamide, phenytoin, heparin, methanol, warfarin.","img":null,"pyq":false},{"id":"ph34","subject":"pharmacology","topic":"Pharmacodynamics","q":"Define affinity, efficacy, and potency.","a":"Affinity: tendency of a drug to bind its target (lower dose needed = higher affinity). Efficacy: maximum clinical effect a drug can produce. Potency: relative dose required to produce a given effect (potency ∝ 1/dose).","img":null,"pyq":false},{"id":"ph35","subject":"pharmacology","topic":"Pharmacodynamics","q":"In a graded DRC, drugs A, B and C reach the same x-axis position but different maximum heights. Which has greatest efficacy and which has greatest potency?","a":"Taller curve = greater efficacy. Leftmost curve (least dose required) = greatest potency.","img":null,"pyq":false},{"id":"ph36","subject":"pharmacology","topic":"Pharmacodynamics","q":"Define ED50, TD50 and Therapeutic Index.","a":"ED50: dose producing effect in 50% of a population (marker of potency). TD50: dose producing toxicity in 50% (marker of toxicity). TI = TD50/ED50 in humans (LD50/ED50 in animals) — measures safety range.","img":null,"pyq":false},{"id":"ph37","subject":"pharmacology","topic":"Pharmacodynamics","q":"How does a competitive antagonist differ from a non-competitive antagonist on a DRC?","a":"Competitive: shifts DRC to the right (higher dose needed) but maximal efficacy is unchanged. Non-competitive: decreases the height of the DRC (reduces maximal efficacy).","img":null,"pyq":false},{"id":"ph38","subject":"pharmacology","topic":"Pharmacodynamics","q":"List the four types of drug-receptor interactions in order of effect.","a":"Full agonist (+1, maximal), partial agonist (+1 to 0, submaximal), antagonist (0, no effect), inverse agonist (0 to −1, opposite effect).","img":null,"pyq":false},{"id":"ph39","subject":"pharmacology","topic":"Receptors","q":"Which receptors are ligand-gated ion channels?","a":"GABA-A, glutamate, nicotinic acetylcholine, and 5-HT3 receptors.","img":null,"pyq":false},{"id":"ph40","subject":"pharmacology","topic":"Receptors","q":"What second messenger does Gs-coupled receptor activation produce?","a":"Stimulates adenylate cyclase → increases cAMP → smooth-muscle relaxation (bronchodilation) and cardiac/skeletal muscle contraction.","img":null,"pyq":false},{"id":"ph41","subject":"pharmacology","topic":"Receptors","q":"Which G-protein is coupled to α1-adrenergic, angiotensin, oxytocin, M1 and M3 receptors?","a":"Gq → activates phospholipase C → PIP2 → IP3 → ↑Ca²⁺ → smooth-muscle contraction.","img":null,"pyq":false},{"id":"ph42","subject":"pharmacology","topic":"Receptors","q":"Give examples of tyrosine kinase receptors.","a":"EGFR, VEGFR, HER-2, insulin receptor, IGF-1, toll-like receptors.","img":null,"pyq":false},{"id":"ph43","subject":"pharmacology","topic":"Receptors","q":"Which steroid receptors are located in the cytoplasm vs. the nucleus?","a":"Cytoplasm: Vitamin D, androgen, mineralocorticoid, glucocorticoid. Nucleus: thyroid, oestrogen, progesterone.","img":null,"pyq":false},{"id":"ph44","subject":"pharmacology","topic":"Rho Kinase","q":"Name three Rho-kinase blockers and their clinical uses.","a":"Fasudil (vasodilator in stable angina), Netarsudil (glaucoma), Belumosudil (graft-vs-host reaction).","img":null,"pyq":false},{"id":"ph45","subject":"pharmacology","topic":"Clinical Trials","q":"What is the drug under study in a clinical trial called?","a":"Investigational new drug.","img":null,"pyq":true},{"id":"ph46","subject":"pharmacology","topic":"Clinical Trials","q":"Describe Phase I of a clinical trial.","a":"Human pharmacology and toxicity study in 20–100 healthy volunteers over 1–2 years; open-label; determines pharmacokinetics, pharmacodynamics, and maximum tolerable dose. Exception: anti-cancer and anti-HIV trials use patients, not healthy volunteers.","img":null,"pyq":true},{"id":"ph47","subject":"pharmacology","topic":"Clinical Trials","q":"What is the purpose of Phase II trials, and what is the design?","a":"Therapeutic exploratory trial in 100–500 patients (unicentric, 2–3 years, RCT) to determine dose range, safety, and initial efficacy.","img":null,"pyq":true},{"id":"ph48","subject":"pharmacology","topic":"Clinical Trials","q":"What happens in Phase III and when is a drug approved?","a":"Therapeutic confirmatory trial in 500–3000 patients (multicentric, 3–5 years, RCT/RUCT) to confirm efficacy and safety. Drug is approved by CDSCO/FDA after Phase III.","img":null,"pyq":true},{"id":"ph49","subject":"pharmacology","topic":"Clinical Trials","q":"What is Phase IV surveillance, and what are Phase 0 and Phase V?","a":"Phase IV: post-marketing surveillance — detects rare and long-term ADRs (open-label, no fixed duration). Phase 0: microdosing. Phase V: pharmacoepidemiology.","img":null,"pyq":true},{"id":"ph50","subject":"pharmacology","topic":"Adverse Drug Reactions","q":"Classify ADRs using the A–F mnemonic with one example each.","a":"A (Augmented, dose-dependent): antihypertensive causing hypotension. B (Bizarre, dose-independent): drug hypersensitivity. C (Chronic, dose+duration): steroids causing HPA suppression. D (Delayed): teratogenicity. E (End-of-use, withdrawal): opioid withdrawal. F (Failure): enzyme inducers causing OCP failure.","img":null,"pyq":false},{"id":"ph51","subject":"pharmacology","topic":"Adverse Drug Reactions","q":"Name the pharmacovigilance hierarchy in India.","a":"ADR reporting software: Vigiflow. National coordinator: IPC Ghaziabad (forms conclusive reports). Regulatory body that bans drugs: CDSCO Delhi. International centre: Uppsala Monitoring Centre, Sweden.","img":null,"pyq":false},{"id":"ph52","subject":"pharmacology","topic":"Therapeutic Drug Monitoring","q":"When is TDM indicated?","a":"When clinical effect cannot be easily quantified (e.g., antiepileptics), when the drug has a low therapeutic index, when variable metabolism exists (e.g., drugs acetylated), or to check compliance.","img":null,"pyq":false},{"id":"ph53","subject":"pharmacology","topic":"Therapeutic Drug Monitoring","q":"State the therapeutic ranges and toxicity levels for digoxin, lithium and theophylline.","a":"Digoxin: therapeutic 0.5–0.9 ng/mL, toxic >2 ng/mL. Lithium: prophylaxis 0.6–1.0, treatment 1.0–1.5, toxic >1.5, dialysis >4 mEq/L. Theophylline: therapeutic 5–15 mg/L, toxic >15 mg/L.","img":null,"pyq":true},{"id":"ph54","subject":"pharmacology","topic":"Pharmacogenetics","q":"Which enzyme polymorphism affects isoniazid metabolism?","a":"N-acetyltransferase (NAT-2 gene → slow acetylators; NAT-1 gene → fast acetylators).","img":null,"pyq":false},{"id":"ph55","subject":"pharmacology","topic":"Pharmacogenetics","q":"Which drugs cause haemolysis in G6PD deficiency (mnemonic Dr MANIS)?","a":"Dapsone, Methylene blue, Antimalarials (primaquine), Nalidixic acid/Nitrofurantoin, Isoniazid, Sulfonamides. Side effect of drugs causing haemolysis: drug-induced SLE.","img":null,"pyq":false},{"id":"ph56","subject":"pharmacology","topic":"Pharmacogenetics","q":"Drugs metabolised by acetylation include which agents (mnemonic HIPS Dance)?","a":"Hydralazine, Isoniazid, Procainamide, Sulfonamides, Dapsone.","img":null,"pyq":false},{"id":"ph57","subject":"pharmacology","topic":"Pregnancy Drug Categories","q":"What is Category D and Category X in pregnancy drug classification?","a":"Cat D: benefits outweigh risks — can be used with caution (e.g., valproate in juvenile myoclonic epilepsy). Cat X: risk > benefit — absolutely contraindicated (e.g., thalidomide).","img":null,"pyq":false},{"id":"ph58","subject":"pharmacology","topic":"Autonomic Nervous System","q":"What are the neurotransmitter and rate-limiting step for parasympathetic nerves?","a":"Neurotransmitter: acetylcholine. Rate-limiting step: choline re-uptake.","img":null,"pyq":false},{"id":"ph59","subject":"pharmacology","topic":"Autonomic Nervous System","q":"What is the rate-limiting step in sympathetic (NE) synthesis?","a":"Conversion of tyrosine to DOPA by tyrosine hydroxylase (blocked by metyrosine in phaeochromocytoma treatment).","img":null,"pyq":false},{"id":"ph60","subject":"pharmacology","topic":"Autonomic Nervous System","q":"What is the DOC for acute-angle glaucoma?","a":"Pilocarpine (muscarinic M3 agonist that increases trabecular outflow).","img":null,"pyq":false},{"id":"ph61","subject":"pharmacology","topic":"Autonomic Nervous System","q":"Name the drugs used for open-angle glaucoma in order: first-line to third-line.","a":"1st line: latanoprost (prostaglandin analogue). 2nd line: beta-blockers (e.g., timolol). 3rd line: alpha-2 agonists, miotics (pilocarpine), carbonic anhydrase inhibitors, or rho-kinase inhibitors.","img":null,"pyq":false},{"id":"ph62","subject":"pharmacology","topic":"Autonomic Nervous System","q":"Which drug is the DOC for Alzheimer's disease and why?","a":"Donepezil (acetylcholinesterase inhibitor) — parasympathomimetic action increases ACh in the brain, improving cognition.","img":null,"pyq":false},{"id":"ph63","subject":"pharmacology","topic":"Autonomic Nervous System","q":"What is the DOC for motion sickness?","a":"Scopolamine transdermal patch, applied at least 4–5 hours before travel to achieve steady-state concentration.","img":null,"pyq":false},{"id":"ph64","subject":"pharmacology","topic":"Autonomic Nervous System","q":"Compare cardioselective vs. non-selective beta-blockers — name the cardioselective ones (mnemonic Mr. BEAN Cardiologist).","a":"Metoprolol, Bisoprolol/Betaxolol, Esmolol, Atenolol/Acebutolol, Nebivolol (most cardioselective), Celiprolol.","img":null,"pyq":true},{"id":"ph65","subject":"pharmacology","topic":"Autonomic Nervous System","q":"What are 3rd-generation beta-blockers and their special properties?","a":"Betaxolol, Nebivolol, Celiprolol. Nebivolol releases NO; Carvedilol and Nebivolol have antioxidant effects; Carvedilol and Labetalol also block alpha receptors.","img":null,"pyq":true},{"id":"ph66","subject":"pharmacology","topic":"Autonomic Nervous System","q":"What is Dale's phenomenon?","a":"When epinephrine is given, it first causes a BP rise (α1 activation at high concentration) then a fall (β2 activation at lower concentration) — biphasic BP response.","img":null,"pyq":false},{"id":"ph67","subject":"pharmacology","topic":"Autonomic Nervous System","q":"What is the DOC for anaphylactic shock?","a":"Epinephrine (adrenaline) 0.5 mg IM at 1:1000 dilution, acting on β2 receptors.","img":null,"pyq":false},{"id":"ph68","subject":"pharmacology","topic":"Autonomic Nervous System","q":"State dopamine's dose-dependent receptor profile.","a":"0–2 mcg/kg/min: D1 → renal vasodilation/diuresis. 2–10: β1 → increased cardiac contraction. >10: α1 → vasoconstriction.","img":null,"pyq":false},{"id":"ph69","subject":"pharmacology","topic":"Autonomic Nervous System","q":"What is the DOC for overactive bladder/urge incontinence?","a":"M3 muscarinic blockers (e.g., oxybutynin, tolterodine, solifenacin) or β3 agonists (mirabegron, vibegron).","img":null,"pyq":true},{"id":"ph70","subject":"pharmacology","topic":"Autonomic Nervous System","q":"What is the DOC for stress incontinence?","a":"Duloxetine (SNRI) — increases NE, stimulating α1 receptors at the bladder sphincter.","img":null,"pyq":true},{"id":"ph71","subject":"pharmacology","topic":"Autonomic Nervous System","q":"Which drug is DOC for myasthenia gravis, and which is used for the tensilon test?","a":"Pyridostigmine is DOC for long-term MG. Edrophonium is used for the tensilon test (diagnosis) and to differentiate myasthenic from cholinergic crisis.","img":null,"pyq":false},{"id":"ph72","subject":"pharmacology","topic":"Autonomic Nervous System","q":"What are the features and treatment of organophosphate (OP) poisoning?","a":"Features: SLUDGE + bradycardia + miosis. DOC: atropine (increases pupil size, reduces secretions). Most specific drug: pralidoxime (acetyl esterase reactivator).","img":null,"pyq":true},{"id":"ph73","subject":"pharmacology","topic":"Anti-arrhythmic Drugs","q":"What is the DOC for an acute attack of SVT/PSVT?","a":"Adenosine IV (rapid bolus). Contraindicated in COPD, asthma, and AF (it induces AF).","img":null,"pyq":true},{"id":"ph74","subject":"pharmacology","topic":"Anti-arrhythmic Drugs","q":"For long-term SVT rate control, which oral drugs are used?","a":"Beta-blockers > CCB (verapamil/diltiazem) > digoxin.","img":null,"pyq":true},{"id":"ph75","subject":"pharmacology","topic":"Anti-arrhythmic Drugs","q":"What is the DOC for VT/VFib?","a":"Amiodarone (K+ channel blocker). Lidocaine (Na+ channel blocker) is DOC for VT/VFib due to MI, angina, or digoxin toxicity.","img":null,"pyq":true},{"id":"ph76","subject":"pharmacology","topic":"Anti-arrhythmic Drugs","q":"How is an acute attack of torsades de pointes managed?","a":"IV magnesium sulphate (MgSO₄).","img":null,"pyq":true},{"id":"ph77","subject":"pharmacology","topic":"Anti-arrhythmic Drugs","q":"List anti-arrhythmics that prolong the QT interval.","a":"Class Ia: quinidine, procainamide, disopyramide. Class III: sotalol, amiodarone, dronedarone, dofetilide, ibutilide, vernakalant.","img":null,"pyq":true},{"id":"ph78","subject":"pharmacology","topic":"Anti-arrhythmic Drugs","q":"What is the management of WPW syndrome?","a":"DOC: oral flecainide. TOC: radiofrequency ablation. DOC for AF in WPW: IV procainamide.","img":null,"pyq":true},{"id":"ph79","subject":"pharmacology","topic":"Anti-arrhythmic Drugs","q":"List the major adverse effects of amiodarone.","a":"Pulmonary fibrosis, corneal verticillata, ceruloderma (blue skin), myocarditis, liver toxicity, neurotoxicity, alpha-receptor blockade (hypotension), photosensitivity (brown skin), thyroid effects (hypothyroidism > hyperthyroidism).","img":null,"pyq":true},{"id":"ph80","subject":"pharmacology","topic":"Heart Failure","q":"What is the DOC for acute heart failure to increase contractility?","a":"Dobutamine. If no response: PDE-3 inhibitor milrinone (inodilator).","img":null,"pyq":false},{"id":"ph81","subject":"pharmacology","topic":"Heart Failure","q":"What is the acute management of cardiogenic pulmonary oedema?","a":"Furosemide → IV nitroglycerine (reduces preload) → IV nesiritide (BNP analogue, metabolised by neprilysin).","img":null,"pyq":false},{"id":"ph82","subject":"pharmacology","topic":"Heart Failure","q":"State the standard three-drug regimen for chronic heart failure.","a":"1. Furosemide (symptom relief). 2. ACE inhibitor/ARB or sacubitril + valsartan. 3. Beta-blocker.","img":null,"pyq":false},{"id":"ph83","subject":"pharmacology","topic":"Heart Failure","q":"What is omapatrilat?","a":"Combined neprilysin inhibitor + ACE inhibitor — used in chronic HF.","img":null,"pyq":true},{"id":"ph84","subject":"pharmacology","topic":"Heart Failure","q":"Name the additional drug classes in the SHIVA Beta regimen for CHF.","a":"Spironolactone, SGLT-2 inhibitors, Hydralazine + isosorbide dinitrate, Ivabradine, Vericiguat, ACE inhibitors/ARB, Beta-blockers.","img":null,"pyq":false},{"id":"ph85","subject":"pharmacology","topic":"Anti-hypertensive Drugs","q":"What are first-line antihypertensive drugs?","a":"ACE inhibitors/ARBs, calcium channel blockers (CCBs), and thiazide diuretics.","img":null,"pyq":true},{"id":"ph86","subject":"pharmacology","topic":"Anti-hypertensive Drugs","q":"How is hypertension approached based on patient age (no comorbidities)?","a":"Young age (high renin): DOC is ACEI/ARB, 2nd line beta-blocker. Old age (low renin): DOC is CCB, 2nd line thiazide.","img":null,"pyq":true},{"id":"ph87","subject":"pharmacology","topic":"Anti-hypertensive Drugs","q":"Which antihypertensive is DOC when combined with: DM/CKD, migraine/stable angina, osteoporosis, BPH, Raynaud's disease?","a":"DM/CKD: ACEI/ARB. Migraine/stable angina: beta-blocker. Osteoporosis/oedema: thiazide. BPH: alpha-blocker. Raynaud's/cyclosporine-induced HTN: CCB.","img":null,"pyq":true},{"id":"ph88","subject":"pharmacology","topic":"Anti-hypertensive Drugs","q":"How is resistant hypertension defined and managed?","a":"BP not controlled by at least 3 drugs (one must be a diuretic). Add spironolactone (aldosterone is elevated in resistant HTN).","img":null,"pyq":false},{"id":"ph89","subject":"pharmacology","topic":"Anti-hypertensive Drugs","q":"What is the DOC for hypertensive urgency and hypertensive emergency?","a":"Urgency (≥200/125 with no organ damage): oral clonidine (or captopril/nifedipine). Emergency (high BP + end-organ damage): IV nicardipine. In pregnancy: IV labetalol.","img":null,"pyq":false},{"id":"ph90","subject":"pharmacology","topic":"Anti-hypertensive Drugs","q":"State the side effects specific to verapamil and those common to all CCBs.","a":"All CCBs: headache, ankle oedema (prevented by ACEi/ARB). Verapamil only: constipation and AV block. Note: verapamil and diltiazem must not be combined with beta-blockers.","img":null,"pyq":false},{"id":"ph91","subject":"pharmacology","topic":"Anti-hypertensive Drugs","q":"What are the non-BP-related benefits of losartan?","a":"PPAR-γ agonism (reduces insulin resistance), increases uric-acid excretion (useful in HTN + gout), and blocks thromboxane A2 (anti-aggregant effect).","img":null,"pyq":true},{"id":"ph92","subject":"pharmacology","topic":"Anti-anginal Drugs","q":"What is the DOC for an acute attack of angina, and what is its mechanism?","a":"Sublingual nitroglycerine — reduces preload by venodilation.","img":null,"pyq":false},{"id":"ph93","subject":"pharmacology","topic":"Anti-anginal Drugs","q":"What is ivabradine's mechanism and its unique feature?","a":"Blocks the funny (If) channel in the SA node → slows HR while preserving normal contractility. Side effect: luminous phenomena (coloured halos).","img":null,"pyq":false},{"id":"ph94","subject":"pharmacology","topic":"Anti-anginal Drugs","q":"What is ranolazine's primary and secondary mechanism?","a":"Primary: blocks late inward Na+ channels. Secondary: PFOX inhibition/beta-blockade. Benefits: reduces AF risk and lowers HbA1c.","img":null,"pyq":false},{"id":"ph95","subject":"pharmacology","topic":"Anti-anginal Drugs","q":"Which drugs reduce mortality in stable angina?","a":"Statins, aspirin, and ACE inhibitors.","img":null,"pyq":false},{"id":"ph96","subject":"pharmacology","topic":"Hypolipidaemic Drugs","q":"What is the mechanism and main clinical use of statins?","a":"Inhibit HMG-CoA reductase → reduce LDL, VLDL and triglycerides; increase HDL. Pleiotropic effects: anti-aggregant, anti-inflammatory, antioxidant, NO-enhancing, plaque-stabilising. DOC: Type II hypercholesterolaemia.","img":null,"pyq":false},{"id":"ph97","subject":"pharmacology","topic":"Hypolipidaemic Drugs","q":"Name the most potent statin and the longest-acting statin.","a":"Most potent: pitavastatin > rosuvastatin (maximum LDL reduction). Longest-acting: rosuvastatin > atorvastatin.","img":null,"pyq":false},{"id":"ph98","subject":"pharmacology","topic":"Hypolipidaemic Drugs","q":"What is the DOC for hypertriglyceridaemia and chylomicronaemia?","a":"Fibrates (stimulate PPARα, increase LPL) — also cause cholethiasis and myopathy.","img":null,"pyq":false},{"id":"ph99","subject":"pharmacology","topic":"Hypolipidaemic Drugs","q":"What is the mechanism of PCSK-9 inhibitors and give two examples?","a":"Prevent degradation of LDL receptors → maximum reduction in LDL. Examples: evolocumab, alirocumab (add-on to statins).","img":null,"pyq":true},{"id":"ph100","subject":"pharmacology","topic":"Hypolipidaemic Drugs","q":"What is inclisiran's mechanism?","a":"siRNA that cleaves the mRNA of PCSK-9 → reduces LDL. Add-on to statins.","img":null,"pyq":false},{"id":"ph101","subject":"pharmacology","topic":"Hypolipidaemic Drugs","q":"What is niacin's unique effect and main side effect?","a":"Greatest increase in HDL (inhibits hormone-sensitive lipase). Main side effects: flushing, hepatotoxicity, and insulin resistance.","img":null,"pyq":false},{"id":"ph102","subject":"pharmacology","topic":"Hypolipidaemic Drugs","q":"How are bile-acid-binding resins (cholestyramine, colestipol, colesevelam) used?","a":"Inhibit enterohepatic circulation of bile acids → reduce LDL. Add-on to statins; preferred in pregnancy and children. Main side effects: hypertriglyceridaemia and reduced absorption of other drugs.","img":null,"pyq":false},{"id":"ph103","subject":"pharmacology","topic":"Diuretics","q":"What is the mechanism and DOC use of loop diuretics?","a":"Block Na/K/2Cl pump in the thick ascending limb of Henle → indirect vasodilation via prostaglandins. DOC for renal and cardiac oedema. Furosemide is DOC for cardiogenic pulmonary oedema.","img":null,"pyq":false},{"id":"ph104","subject":"pharmacology","topic":"Diuretics","q":"Compare the four loop diuretics: torsemide, bumetanide, ethacrynic acid and furosemide.","a":"Torsemide: longest-acting. Bumetanide: most potent. Ethacrynic acid: most ototoxic. Furosemide: DOC for pulmonary oedema.","img":null,"pyq":false},{"id":"ph105","subject":"pharmacology","topic":"Diuretics","q":"What is the mechanism of thiazide diuretics, and why are they effective antihypertensives?","a":"Block Na/Cl cotransporter in the DCT; also open K+ channels → direct vasodilation. Side effects: hypokalaemia, hyperglycaemia, hyperuricaemia, and reduced Ca²⁺.","img":null,"pyq":false},{"id":"ph106","subject":"pharmacology","topic":"Diuretics","q":"Which thiazide is longest-acting and preferred for hypertension?","a":"Chlorthalidone.","img":null,"pyq":false},{"id":"ph107","subject":"pharmacology","topic":"Diuretics","q":"What is the DOC for cirrhotic oedema and for resistant hypertension?","a":"Spironolactone (aldosterone antagonist — K+-sparing diuretic).","img":null,"pyq":false},{"id":"ph108","subject":"pharmacology","topic":"Diuretics","q":"What is amiloride's mechanism and when is it preferred?","a":"Blocks ENaC channels in the collecting duct. DOC for lithium-induced diabetes insipidus, Liddle syndrome, and cystic fibrosis.","img":null,"pyq":false},{"id":"ph109","subject":"pharmacology","topic":"Diuretics","q":"List the indications for mannitol (osmotic diuretic) (mnemonic ABCDE).","a":"A: Acute congestive glaucoma (DOC). B: Breaking diuretic resistance. C: Cerebral oedema (DOC). D: Dialysis disequilibrium. E: Expected (impending) renal failure — but contraindicated in established renal failure.","img":null,"pyq":false},{"id":"ph110","subject":"pharmacology","topic":"Diuretics","q":"How do carbonic anhydrase inhibitors affect electrolytes?","a":"Cause hypokalaemia and metabolic acidosis (unlike loop and thiazide diuretics which cause alkalosis). Acetazolamide is DOC for acute mountain sickness.","img":null,"pyq":false},{"id":"ph111","subject":"pharmacology","topic":"Antiepileptic Drugs","q":"What is the DOC for GTCS and for myoclonic (JME) seizures?","a":"Valproate.","img":null,"pyq":false},{"id":"ph112","subject":"pharmacology","topic":"Antiepileptic Drugs","q":"Distinguish the DOC for typical versus atypical absence seizures.","a":"Typical absence: ethosuximide. Atypical absence (with change in muscle tone): valproate.","img":null,"pyq":false},{"id":"ph113","subject":"pharmacology","topic":"Antiepileptic Drugs","q":"What is the DOC for partial seizures and Rolandic epilepsy?","a":"Carbamazepine.","img":null,"pyq":false},{"id":"ph114","subject":"pharmacology","topic":"Antiepileptic Drugs","q":"What is the DOC for status epilepticus?","a":"Lorazepam IV (also safe in liver dysfunction). Diazepam is used for alcohol-withdrawal seizures.","img":null,"pyq":false},{"id":"ph115","subject":"pharmacology","topic":"Antiepileptic Drugs","q":"What is the DOC for infantile spasms with tuberous sclerosis, and without TS?","a":"With TS: vigabatrin. Without TS (West syndrome/salaam spasms): ACTH.","img":null,"pyq":false},{"id":"ph116","subject":"pharmacology","topic":"Antiepileptic Drugs","q":"What are the major side effects of valproate (mnemonic T.VALPROIC Acid)?","a":"Tremor, Teratogenicity (maximum), Vomiting/nausea, Ammonia increased, Liver toxicity, Pancreatitis, Rash, Obesity, Infertility in females (PCOS), Carnitine deficiency, Alopecia.","img":null,"pyq":false},{"id":"ph117","subject":"pharmacology","topic":"Antiepileptic Drugs","q":"List phenytoin side effects (mnemonic HYDANTOIN).","a":"Hirsutism/hyperplasia of gums, lYmphadenopathy, Diplopia, Ataxia/Agranulocytosis, Nystagmus, Teratogenic (facial clefts), Osteomalacia, Increased bleeding in newborns.","img":null,"pyq":false},{"id":"ph118","subject":"pharmacology","topic":"Antiepileptic Drugs","q":"What gene mutation predisposes to carbamazepine-induced Stevens-Johnson syndrome?","a":"HLA-B*1502 gene.","img":null,"pyq":false},{"id":"ph119","subject":"pharmacology","topic":"Antiepileptic Drugs","q":"What is the DOC for epilepsy in pregnancy?","a":"Levetiracetam > lamotrigine. Valproate is the most teratogenic antiepileptic (avoid if possible).","img":null,"pyq":false},{"id":"ph120","subject":"pharmacology","topic":"Antiepileptic Drugs","q":"Which antiepileptic causes renal stones, acute-angle glaucoma, and metabolic acidosis?","a":"Topiramate (also used off-label for obesity).","img":null,"pyq":false},{"id":"ph121","subject":"pharmacology","topic":"Mood Disorders","q":"What is the DOC for acute mania and for mania prophylaxis/bipolar disorder?","a":"Acute mania: atypical antipsychotics (aripiprazole) > typical antipsychotics. Mania prophylaxis and bipolar disorder: lithium.","img":null,"pyq":false},{"id":"ph122","subject":"pharmacology","topic":"Mood Disorders","q":"What is the DOC for depression, and what are preferred agents when insomnia or erectile dysfunction coexist?","a":"DOC: SSRIs > SNRIs. Depression + insomnia or erectile dysfunction: mirtazapine or bupropion (neither causes ED).","img":null,"pyq":false},{"id":"ph123","subject":"pharmacology","topic":"Mood Disorders","q":"What are the 'life-saving' drugs for suicidal tendency (mnemonic Life Can End)?","a":"Lithium, Clozapine, ECT.","img":null,"pyq":false},{"id":"ph124","subject":"pharmacology","topic":"Mood Disorders","q":"What are the major side effects of SSRIs?","a":"Anxiety/insomnia (5-HT2, brain); erectile dysfunction/anorgasmia (5-HT2, spinal cord); nausea/vomiting (5-HT3); loose stools (5-HT4). Most common: nausea. Most common delayed: erectile dysfunction.","img":null,"pyq":false},{"id":"ph125","subject":"pharmacology","topic":"Mood Disorders","q":"Name the side effects unique to TCAs and the antidote for TCA toxicity.","a":"M-receptor block: constipation, dry mouth, mydriasis, urine retention. H1 block: sedation. α1 block: postural hypotension. SHT block: obesity. Toxicity treatment: sodium bicarbonate (high mortality from arrhythmias).","img":null,"pyq":false},{"id":"ph126","subject":"pharmacology","topic":"Mood Disorders","q":"What is the most concerning side effect of bupropion?","a":"Seizures (also causes maximum anxiety).","img":null,"pyq":false},{"id":"ph127","subject":"pharmacology","topic":"Parkinson's Disease","q":"What is the DOC for Parkinson's disease in patients under 65 with significant symptoms?","a":"D2 agonists (pramipexole, ropinirole). Side effects: fatigue, compulsive gambling/sexual activity.","img":null,"pyq":true},{"id":"ph128","subject":"pharmacology","topic":"Parkinson's Disease","q":"What is the DOC for Parkinson's in patients aged ≥65?","a":"Levodopa + carbidopa. Carbidopa is a peripheral decarboxylase inhibitor that reduces peripheral conversion of levodopa, allowing more to reach the brain.","img":null,"pyq":true},{"id":"ph129","subject":"pharmacology","topic":"Parkinson's Disease","q":"How is levodopa-induced dyskinesia managed?","a":"Amantadine (DOC).","img":null,"pyq":true},{"id":"ph130","subject":"pharmacology","topic":"Parkinson's Disease","q":"How is levodopa-induced on–off phenomenon managed?","a":"COMT inhibitors (e.g., entacapone).","img":null,"pyq":true},{"id":"ph131","subject":"pharmacology","topic":"Parkinson's Disease","q":"What are the treatment steps for neuroleptic malignant syndrome (NMS)?","a":"DOC: dantrolene. Most specific drug: bromocriptine. NMS features: muscle rigidity, hyperthermia, autonomic instability (also DOC for malignant hyperthermia).","img":null,"pyq":false},{"id":"ph132","subject":"pharmacology","topic":"Parkinson's Disease","q":"Which drugs cause tardive dyskinesia and what is the treatment?","a":"Cause: D2 upregulation from prolonged antipsychotic use. Treatment: VMAT-2 inhibitors — valbenazine or deutetrabenazine.","img":null,"pyq":false},{"id":"ph133","subject":"pharmacology","topic":"Neurodegenerative Disorders","q":"What is the DOC for ALS?","a":"Riluzole (glutamate blocker). If no response: edaravone. Newer agents: sodium phenylbutyrate-taurursodiol, tofersen.","img":null,"pyq":false},{"id":"ph134","subject":"pharmacology","topic":"Neurodegenerative Disorders","q":"How is Alzheimer's disease managed?","a":"1st line: cholinesterase inhibitors (donepezil, rivastigmine, galantamine). Add memantine (NMDA receptor blocker) for moderate-to-severe disease. Newer: β-amyloid blockers (aducanumab, lecanemab) for mild disease.","img":null,"pyq":false},{"id":"ph135","subject":"pharmacology","topic":"Migraine","q":"What is the DOC for an acute migraine attack?","a":"Triptans (5-HT1B/1D agonists). Fastest oral: rizatriptan. Fastest overall: sumatriptan SC. Prophylaxis: propranolol (DOC) or topiramate.","img":null,"pyq":false},{"id":"ph136","subject":"pharmacology","topic":"Migraine","q":"What are the new CGRP-targeted drugs for migraine?","a":"CGRP ligand blockers (SC, prophylaxis): eptinezumab, fremanezumab, galcanezumab. CGRP receptor blockers (oral, treatment and prophylaxis): erenumab (also SC), olcegepant, rimegepant, ubrogepant.","img":null,"pyq":false},{"id":"ph137","subject":"pharmacology","topic":"Migraine","q":"Why are triptans contraindicated in angina?","a":"Triptans cause vasoconstriction via 5-HT1B/1D receptors; this can precipitate or worsen ischaemia.","img":null,"pyq":false},{"id":"ph138","subject":"pharmacology","topic":"Opioid Agents","q":"List the side effects of mu-opioid receptor stimulation (mnemonic MUSCARINE).","a":"Miosis, Urine retention, Sedation, Constipation/Convulsions, Analgesia, Respiratory depression, Increased muscle rigidity, No bile flow (sphincter of Oddi contraction), Euphoria.","img":null,"pyq":true},{"id":"ph139","subject":"pharmacology","topic":"Opioid Agents","q":"What is the DOC for opioid toxicity, and how is opioid dependence managed?","a":"Toxicity: naloxone. Dependence — reduce withdrawal: methadone or buprenorphine; prevent relapse: naltrexone.","img":null,"pyq":true},{"id":"ph140","subject":"pharmacology","topic":"Opioid Agents","q":"What is buprenorphine's receptor profile?","a":"Partial agonist at mu receptors and antagonist at kappa receptors.","img":null,"pyq":true},{"id":"ph141","subject":"pharmacology","topic":"Opioid Agents","q":"What is tramadol's mechanism?","a":"Inhibits serotonin and NE reuptake (plus weak mu-opioid effect). Used for post-anaesthetic chills (also pethidine, via α2 agonism).","img":null,"pyq":false},{"id":"ph142","subject":"pharmacology","topic":"Alcohol Dependence","q":"How does disulfiram work?","a":"Blocks aldehyde dehydrogenase → accumulation of acetaldehyde → palpitations, tremors, sweating, chest pain (aversion reaction). Requires 12 hours of abstinence before starting.","img":null,"pyq":false},{"id":"ph143","subject":"pharmacology","topic":"Smoking Cessation","q":"What is the first-line pharmacotherapy for smoking cessation?","a":"Varenicline (partial agonist at α4β2 nicotinic receptors — most effective anti-smoking drug) or bupropion. Nicotine replacement is also first-line; nasal spray is most effective replacement route.","img":null,"pyq":false},{"id":"ph144","subject":"pharmacology","topic":"Antipsychotics","q":"Rank antipsychotics for hyperprolactinaemia and metabolic side effects.","a":"Hyperprolactinaemia: max = risperidone, min = clozapine, zero = pimavanserin. Metabolic/weight gain: max = clozapine > olanzapine, min = risperidone, zero (weight-neutral) = aripiprazole/cariprazine/ziprasidone.","img":null,"pyq":false},{"id":"ph145","subject":"pharmacology","topic":"Antipsychotics","q":"What is the DOC for akathisia?","a":"Beta-blockers (add-on: benzodiazepines).","img":null,"pyq":false},{"id":"ph146","subject":"pharmacology","topic":"Antipsychotics","q":"What is the DOC for acute drug-induced dystonia and drug-induced parkinsonism?","a":"Anticholinergics — benzhexol (trihexyphenidyl). Antihistamine promethazine is an alternative.","img":null,"pyq":false},{"id":"ph147","subject":"pharmacology","topic":"Lithium","q":"State lithium's side effects (mnemonic HOTHEAD).","a":"Hypothyroidism, Obesity, Tremor (fine at therapeutic, coarse at toxic), Hypercalcaemia, Ebstein's anomaly (C/I in 1st trimester), Acne, Diabetes insipidus.","img":null,"pyq":false},{"id":"ph148","subject":"pharmacology","topic":"Lithium","q":"Which conditions increase the risk of lithium toxicity?","a":"Hyponatraemia from any cause — thiazides (greatest risk) > K+-sparing > loop diuretics, diarrhoea/vomiting, and fasting — all reduce Na⁺ and cause lithium retention.","img":null,"pyq":false},{"id":"ph149","subject":"pharmacology","topic":"Antimicrobials: Classification","q":"Classify antibiotics by mechanism.","a":"Cell-wall synthesis inhibitors (cidal): beta-lactams, vancomycin, bacitracin, cycloserine, fosfomycin. Protein synthesis inhibitors: tetracyclines (static), aminoglycosides (cidal), macrolides, linezolid, clindamycin, streptogramins. Cell-membrane disruptors (cidal): daptomycin, polymyxins. Antifolates: sulfonamides (static), cotrimoxazole (cidal). Fluoroquinolones (cidal): inhibit DNA gyrase.","img":null,"pyq":false},{"id":"ph150","subject":"pharmacology","topic":"Antimicrobials: Specific Uses","q":"Which drug is DOC for: atypical pneumonia, Campylobacter, cholera in children, and chlamydia in pregnancy?","a":"Azithromycin.","img":null,"pyq":false},{"id":"ph151","subject":"pharmacology","topic":"Antimicrobials: Specific Uses","q":"Which drug is DOC for MRSA (IV) and pseudomembranous colitis (oral)?","a":"IV vancomycin for MRSA. Oral fidaxomicin (latest DOC) or oral vancomycin for pseudomembranous colitis.","img":null,"pyq":false},{"id":"ph152","subject":"pharmacology","topic":"Antimicrobials: Specific Uses","q":"For which infections is cotrimoxazole the DOC?","a":"Pneumocystis pneumonia, Nocardia, Cyclospora, Isospora, Sarcocystis, Burkholderia cepacia, and Stenotrophomonas (with piperacillin).","img":null,"pyq":false},{"id":"ph153","subject":"pharmacology","topic":"Antimicrobials: Side Effects","q":"List aminoglycoside toxicities.","a":"Nephrotoxicity, irreversible ototoxicity (amikacin → auditory; streptomycin → vestibular), neuromuscular toxicity. Contraindicated in pregnancy.","img":null,"pyq":false},{"id":"ph154","subject":"pharmacology","topic":"Antimicrobials: Side Effects","q":"What are the side effects of fluoroquinolones?","a":"Photosensitivity, QT prolongation, seizures, rash, tendinitis/tendon rupture (risk increased in elderly, renal failure, steroid users).","img":null,"pyq":true},{"id":"ph155","subject":"pharmacology","topic":"Antimicrobials: Side Effects","q":"What are the significant side effects of tetracyclines?","a":"Photosensitivity, acute renal failure (except doxycycline), impaired bone growth, diabetes insipidus, oesophagitis, yellowing of teeth, vestibular toxicity (minocycline). Contraindicated in pregnancy and children.","img":null,"pyq":false},{"id":"ph156","subject":"pharmacology","topic":"Antimicrobials: Side Effects","q":"What side effects are specific to linezolid?","a":"Bone marrow suppression, MAO inhibition, mitochondrial toxicity (optic neuritis, lactic acidosis).","img":null,"pyq":false},{"id":"ph157","subject":"pharmacology","topic":"Antiviral Drugs","q":"What is the DOC for HSV/VZV, and for CMV?","a":"HSV/VZV: oral valacyclovir > oral/topical acyclovir; IV acyclovir for HSV encephalitis. CMV: oral valganciclovir > oral ganciclovir; IV ganciclovir when there is a high risk of blindness.","img":null,"pyq":false},{"id":"ph158","subject":"pharmacology","topic":"Antiviral Drugs","q":"Name the anti-influenza neuraminidase inhibitors and their indications.","a":"Oral oseltamivir and inhaled zanamivir — used for influenza A & B and bird flu. Zanamivir is used in oseltamivir-resistant cases.","img":null,"pyq":false},{"id":"ph159","subject":"pharmacology","topic":"Antiviral Drugs","q":"What is the preferred antiretroviral regimen in India?","a":"Tenofovir + Lamivudine + Dolutegravir (TLD).","img":null,"pyq":true},{"id":"ph160","subject":"pharmacology","topic":"Antiviral Drugs","q":"What is the DOC for hepatitis C?","a":"Direct-acting antivirals: paritaprevir (protease blocker), sofosbuvir (NS5B blocker), velpatasvir (NS5A blocker).","img":null,"pyq":false},{"id":"ph161","subject":"pharmacology","topic":"Antiviral Drugs","q":"What are the entry inhibitors used in HIV and their targets?","a":"Ibalizumab (CD4, IV), fostemsavir (gp120), maraviroc (CCR5), enfuvirtide (gp41 fusion inhibitor, SC).","img":null,"pyq":true},{"id":"ph162","subject":"pharmacology","topic":"Antifungal Drugs","q":"What is amphotericin B's mechanism, carrier solution, and main toxicities?","a":"Sequesters ergosterol in fungal cell membrane. Given IV in 5% dextrose. Toxicities: hypokalaemia (give KCl) and nephrotoxicity (prevent by NaCl preloading or liposomal formulation).","img":null,"pyq":false},{"id":"ph163","subject":"pharmacology","topic":"Antifungal Drugs","q":"Which antifungal is DOC for mucormycosis?","a":"Amphotericin B (also for kala-azar and cryptococcal meningitis). Posaconazole and isavuconazole are alternatives.","img":null,"pyq":true},{"id":"ph164","subject":"pharmacology","topic":"Antifungal Drugs","q":"Which azole is DOC for invasive aspergillosis?","a":"Voriconazole.","img":null,"pyq":false},{"id":"ph165","subject":"pharmacology","topic":"Antifungal Drugs","q":"Which drug is DOC for tinea capitis?","a":"Griseofulvin (taken with fatty food to increase absorption).","img":null,"pyq":false},{"id":"ph166","subject":"pharmacology","topic":"Antihelminthic Drugs","q":"Which drug is DOC for intestinal nematodes (roundworm, whipworm, hookworm, Enterobius)?","a":"Albendazole.","img":null,"pyq":false},{"id":"ph167","subject":"pharmacology","topic":"Antihelminthic Drugs","q":"What is ivermectin's mechanism and which parasites does it treat?","a":"Produces tonic paralysis by stimulating glutamate-sensitive chloride channels. Treats Strongyloides and Onchocerca. Note: Ivermectin + DEC + Albendazole is used for filariasis.","img":null,"pyq":false},{"id":"ph168","subject":"pharmacology","topic":"Antihelminthic Drugs","q":"What is praziquantel's mechanism and which organisms does it cover?","a":"Produces spastic paralysis by stimulating calcium channels. Covers intestinal cestodes (Taenia solium/saginata, Hymenolepis nana, Diphyllobothrium latum), and trematodes except Fasciola.","img":null,"pyq":false},{"id":"ph169","subject":"pharmacology","topic":"Antiprotozoal Drugs","q":"What is the DOC for visceral leishmaniasis (kala-azar)?","a":"IV liposomal amphotericin B; oral DOC: miltefosine.","img":null,"pyq":false},{"id":"ph170","subject":"pharmacology","topic":"Antiprotozoal Drugs","q":"State the malaria treatment for uncomplicated vivax malaria.","a":"Chloroquine + primaquine for 14 days for radical cure (or tafenoquine as a single dose). Tafenoquine provides a single-dose radical cure.","img":null,"pyq":true},{"id":"ph171","subject":"pharmacology","topic":"Antiprotozoal Drugs","q":"What is the DOC for severe falciparum malaria?","a":"IV artesunate — most potent and fastest-acting schizontocidal drug.","img":null,"pyq":true},{"id":"ph172","subject":"pharmacology","topic":"Antiprotozoal Drugs","q":"How is malaria managed in the 1st trimester of pregnancy?","a":"Quinine + clindamycin. In 2nd and 3rd trimesters: artemisinin combination therapy (ACT).","img":null,"pyq":true},{"id":"ph173","subject":"pharmacology","topic":"Anti-Tubercular Drugs","q":"What is the mechanism of isoniazid (INH) and its side effects?","a":"Activated by catalase-peroxidase, blocks mycolic acid synthesis. Side effects (due to vitamin B6 depletion): pyridoxine-dependent anaemia, neuropathy, psychosis, seizures (treated with vitamin B6).","img":null,"pyq":true},{"id":"ph174","subject":"pharmacology","topic":"Anti-Tubercular Drugs","q":"What is the mechanism and key toxicity of rifampicin?","a":"Blocks bacterial RNA polymerase (RPO-b gene mutation = resistance). Side effects: red/orange urine, flu-like symptoms, thrombocytopenic purpura and pulmonary syndrome (both are indications to stop rifampicin permanently), hepatotoxicity.","img":null,"pyq":true},{"id":"ph175","subject":"pharmacology","topic":"Anti-Tubercular Drugs","q":"What is the order of hepatotoxicity among first-line anti-TB drugs?","a":"Pyrazinamide > isoniazid > rifampicin.","img":null,"pyq":false},{"id":"ph176","subject":"pharmacology","topic":"Anti-Tubercular Drugs","q":"What is the visual side effect of ethambutol?","a":"Optic neuritis causing red-green colour blindness (green lost before red). It is the only static first-line TB drug and acts on replicating extracellular bacteria.","img":null,"pyq":false},{"id":"ph177","subject":"pharmacology","topic":"Anti-Tubercular Drugs","q":"Define MDR-TB and XDR-TB.","a":"MDR-TB: resistant to isoniazid + rifampicin. XDR-TB: resistant to isoniazid + rifampicin + all fluoroquinolones + at least one injectable aminoglycoside.","img":null,"pyq":false},{"id":"ph178","subject":"pharmacology","topic":"Anti-Tubercular Drugs","q":"What is bedaquiline's mechanism and key side effect?","a":"Blocks ATP synthase. Key side effect: QT prolongation — contraindicated in arrhythmia. Safe in pregnancy.","img":null,"pyq":false},{"id":"ph179","subject":"pharmacology","topic":"Anti-Leprosy Drugs","q":"Name the first-line anti-leprosy drugs and their activity.","a":"Rifampicin (cidal, maximum activity), dapsone (static — causes haemolysis in G6PD deficiency), clofazimine (static — causes ichthyosis).","img":null,"pyq":false},{"id":"ph180","subject":"pharmacology","topic":"Anti-cancer Drugs","q":"State the DOC/treatment regimen for colorectal cancer and for testicular cancer.","a":"Colorectal: 5-fluorouracil; TOC = FOLFOX/FOLFIRI (5-FU + oxaliplatin/irinotecan + leucovorin). Testicular: BEP regimen (bleomycin + etoposide + cisplatin).","img":null,"pyq":false},{"id":"ph181","subject":"pharmacology","topic":"Anti-cancer Drugs","q":"What is the treatment of ER+ve breast cancer in pre- vs. post-menopausal women?","a":"Pre-menopausal: tamoxifen (SERM). Post-menopausal: letrozole (aromatase inhibitor). Side effects of tamoxifen: uterine cancer, thrombosis, hot flashes.","img":null,"pyq":false},{"id":"ph182","subject":"pharmacology","topic":"Anti-cancer Drugs","q":"What anti-cancer drug causes haemorrhagic cystitis, and how is it prevented?","a":"Ifosfamide (> cyclophosphamide) due to acrolein metabolite. Prevention: MESNA.","img":null,"pyq":false},{"id":"ph183","subject":"pharmacology","topic":"Anti-cancer Drugs","q":"What side effect is unique to bleomycin?","a":"Pulmonary fibrosis and flagellate dermatitis (long streaks of hyperpigmentation). Side effects in skin and lungs because hydrolases are deficient there.","img":null,"pyq":false},{"id":"ph184","subject":"pharmacology","topic":"Anti-cancer Drugs","q":"Which anti-cancer drugs cause cardiotoxicity?","a":"Trastuzumab, doxorubicin, and daunorubicin.","img":null,"pyq":false},{"id":"ph185","subject":"pharmacology","topic":"Anti-cancer Drugs","q":"What is imatinib's mechanism and use?","a":"BCR-ABL tyrosine kinase inhibitor (blocks enzymatic site). DOC for CML (1st generation). Also used in GIST.","img":null,"pyq":false},{"id":"ph186","subject":"pharmacology","topic":"Anti-cancer Drugs","q":"What is the mechanism of immune checkpoint inhibitors — PD-1, PD-L1, and CTLA-4 blockers?","a":"PD-1 blockers (nivolumab, pembrolizumab): block the PD-1 receptor on T cells. PD-L1 blockers (durvalumab, atezolizumab, avelumab): block ligand on tumour cells. CTLA-4 blocker (ipilimumab): releases the 'brake' on T-cell activation. All unleash anti-tumour immunity.","img":null,"pyq":false},{"id":"ph187","subject":"pharmacology","topic":"Anti-cancer Drugs","q":"What is methotrexate's mechanism in rheumatoid arthritis?","a":"Increases adenosine (anti-inflammatory pathway), unlike its cancer MOA of DHFR inhibition. Prevention of MTX toxicity: folinic acid (leucovorin) > folic acid.","img":null,"pyq":true},{"id":"ph188","subject":"pharmacology","topic":"Anti-cancer Drugs","q":"What is olaparib and when is it used?","a":"A PARP blocker (poly ADP-ribose polymerase inhibitor) used in breast cancer with BRCA mutations.","img":null,"pyq":false},{"id":"ph189","subject":"pharmacology","topic":"Antidiabetic Drugs","q":"What is the MOA of metformin, and what are its contraindications?","a":"Stimulates AMPK → blocks hepatic gluconeogenesis. DOC for type 2 DM, metabolic syndrome, PCOS. Contraindicated in elderly, renal/hepatic failure, chronic alcoholism, CHF, and severe respiratory distress.","img":null,"pyq":true},{"id":"ph190","subject":"pharmacology","topic":"Antidiabetic Drugs","q":"What is the mechanism of sulfonylureas and what are their main side effects?","a":"Inhibit ATP-sensitive K+ channels in beta cells → insulin release. Main side effects: hypoglycaemia and weight gain.","img":null,"pyq":false},{"id":"ph191","subject":"pharmacology","topic":"Antidiabetic Drugs","q":"What are DPP-4 inhibitors and which one is safe in renal failure?","a":"Inhibit DPP-4 → increase GLP-1 → increase insulin release. Weight-neutral. All are contraindicated in renal failure except linagliptin (hepatic excretion).","img":null,"pyq":false},{"id":"ph192","subject":"pharmacology","topic":"Antidiabetic Drugs","q":"What is the DOC for obesity among antidiabetic agents?","a":"Semaglutide (GLP-1 agonist) > liraglutide. GLP-1 agonists also delay gastric emptying.","img":null,"pyq":false},{"id":"ph193","subject":"pharmacology","topic":"Antidiabetic Drugs","q":"What are SGLT-2 inhibitors' mechanisms and main benefits beyond glucose?","a":"Promote urinary glucose excretion. Benefits: weight loss, reduce cardiovascular events and HF hospitalisations (used in CHF regimen).","img":null,"pyq":false},{"id":"ph194","subject":"pharmacology","topic":"Antidiabetic Drugs","q":"What are the side effects of thiazolidinediones (glitazones)?","a":"Oedema, CHF, macular oedema, bone fractures in females, hepatotoxicity. Mechanism: PPAR-γ stimulation → reduces insulin resistance.","img":null,"pyq":false},{"id":"ph195","subject":"pharmacology","topic":"Thyroid Drugs","q":"What is the universal DOC for hyperthyroidism, and what is the DOC in each trimester of pregnancy?","a":"Universal DOC: carbimazole/methimazole (both are long-acting, once-daily). 1st trimester: propylthiouracil (PTU). 2nd–3rd trimester: carbimazole/methimazole.","img":null,"pyq":false},{"id":"ph196","subject":"pharmacology","topic":"Thyroid Drugs","q":"What are the side effects of carbimazole/methimazole?","a":"Agranulocytosis and teratogenicity (choanal atresia, oesophageal atresia, cutis aplasia). PTU is hepatotoxic.","img":null,"pyq":false},{"id":"ph197","subject":"pharmacology","topic":"Thyroid Drugs","q":"What is the fastest-acting antithyroid drug?","a":"Lugol's iodine (potassium iodide) — inhibits thiol endopeptidase, blocking T3/T4 release and reducing thyroid size and vascularity (used pre-operatively).","img":null,"pyq":false},{"id":"ph198","subject":"pharmacology","topic":"Thyroid Drugs","q":"What is the DOC for hypothyroidism and myxoedema coma?","a":"Levothyroxine (T4 salt) for oral replacement; IV levothyroxine or T3 salt (liothyronine) for myxoedema coma. Take orally on an empty stomach.","img":null,"pyq":false},{"id":"ph199","subject":"pharmacology","topic":"Steroids","q":"Rank steroids from shortest- to longest-acting.","a":"Shortest/least potent: hydrocortisone (8–12 h). Intermediate: prednisolone/methylprednisolone (12–36 h). Longest/most potent: dexamethasone/betamethasone (36–72 h). Dexamethasone and betamethasone are also called pure glucocorticoids.","img":null,"pyq":false},{"id":"ph200","subject":"pharmacology","topic":"Steroids","q":"What is the DOC for thyroid storm?","a":"Propylthiouracil. First drug to start: propranolol. In asthma/COPD: verapamil/diltiazem instead of propranolol.","img":null,"pyq":false},{"id":"ph201","subject":"pharmacology","topic":"Osteoporosis Drugs","q":"What is the mechanism and major side effects of bisphosphonates?","a":"Inhibit farnesyl pyrophosphate synthase; block osteoclast ruffled-border synthesis. DOC for Paget's disease and osteoporosis. Side effects: hypocalcaemia, oesophagitis, osteonecrosis of jaw, femoral chalk-stick fracture.","img":null,"pyq":false},{"id":"ph202","subject":"pharmacology","topic":"Osteoporosis Drugs","q":"What is denosumab and when is it preferred over bisphosphonates?","a":"RANK ligand blocker. Used in post-menopausal osteoporosis when bisphosphonate is not tolerated and fracture risk is high.","img":null,"pyq":false},{"id":"ph203","subject":"pharmacology","topic":"Osteoporosis Drugs","q":"What is teriparatide and what is its key contraindication?","a":"PTH analogue — stimulates osteoblasts. Used for post-menopausal osteoporosis and bisphosphonate-induced fractures. Contraindicated in Paget's disease (risk factor for osteosarcoma). Max use: 2 years.","img":null,"pyq":false},{"id":"ph204","subject":"pharmacology","topic":"NSAIDs","q":"What is the mechanism of paracetamol toxicity, and what is its antidote?","a":"NAPQI metabolite depletes glutathione, causing centrilobular necrosis. Toxic at >150–250 mg/kg or ≥10 g. Antidote: N-acetylcysteine (replenishes glutathione). Rumack–Matthew nomogram predicts toxicity.","img":null,"pyq":false},{"id":"ph205","subject":"pharmacology","topic":"NSAIDs","q":"State the dose-dependent effects of aspirin.","a":"Low dose (50–325 mg OD): anti-aggregant. Moderate dose (325–650 mg SOS): antipyretic and analgesic. High dose (3–4 g/day): anti-inflammatory.","img":null,"pyq":false},{"id":"ph206","subject":"pharmacology","topic":"NSAIDs","q":"What is the DOC for an acute attack of gout?","a":"Indomethacin > colchicine. Colchicine blocks microtubules → blocks leucocyte chemotaxis.","img":null,"pyq":true},{"id":"ph207","subject":"pharmacology","topic":"NSAIDs","q":"What is the DOC for NSAID-induced gastric ulcer?","a":"Misoprostol (PGE1 analogue).","img":null,"pyq":false},{"id":"ph208","subject":"pharmacology","topic":"NSAIDs","q":"What are the key side effects and contraindications of selective COX-2 inhibitors?","a":"Cardiotoxicity (MI). Valdecoxib and rofecoxib were banned for causing MI. Lumiracoxib was banned for hepatotoxicity.","img":null,"pyq":false},{"id":"ph209","subject":"pharmacology","topic":"Prostaglandins","q":"What are the uses of misoprostol (PGE1)?","a":"Medical abortion, NSAID-induced gastric ulcer treatment, maintenance of patent ductus arteriosus, and management of PPH.","img":null,"pyq":true},{"id":"ph210","subject":"pharmacology","topic":"Prostaglandins","q":"What is carboprost used for?","a":"PPH management and abortion (PGF2α analogue).","img":null,"pyq":true},{"id":"ph211","subject":"pharmacology","topic":"DMARDs","q":"What is the anchor drug for rheumatoid arthritis and how does it work in RA?","a":"Methotrexate — in RA, works by increasing adenosine (anti-inflammatory), not primarily by DHFR inhibition.","img":null,"pyq":true},{"id":"ph212","subject":"pharmacology","topic":"DMARDs","q":"Name the TNF-α inhibitors used in RA (mnemonic ICAGe).","a":"Infliximab, Certolizumab, Adalimumab, Golimumab, Etanercept. Side effect: increased infection risk. Contraindicated in hepatitis B and CHF.","img":null,"pyq":false},{"id":"ph213","subject":"pharmacology","topic":"DMARDs","q":"What are JAK inhibitors used in RA, and what is their main risk?","a":"Tofacitinib, baricitinib, upadacitinib — increased infection risk.","img":null,"pyq":false},{"id":"ph214","subject":"pharmacology","topic":"Anti-asthmatic Drugs","q":"What is the DOC for persistent asthma, and what is the TOC for an acute asthma attack?","a":"DOC: inhaled corticosteroids (ICS), e.g., fluticasone. TOC for acute attack: ICS + formoterol.","img":null,"pyq":true},{"id":"ph215","subject":"pharmacology","topic":"Anti-asthmatic Drugs","q":"What is the DOC for COPD (long-acting bronchodilator)?","a":"Tiotropium (LAMA — long-acting muscarinic antagonist, once daily). Short-acting: ipratropium (SAMA, four times daily).","img":null,"pyq":true},{"id":"ph216","subject":"pharmacology","topic":"Anti-asthmatic Drugs","q":"What are the side effects of inhaled beta-2 agonists?","a":"Palpitations and tremors due to hyperkalaemia and hypoglycaemia. Note: olodaterol, vilanterol, and carmoterol (VLABAs) are only used in COPD, not in asthma.","img":null,"pyq":false},{"id":"ph217","subject":"pharmacology","topic":"Anti-asthmatic Drugs","q":"What are the side effects of inhaled corticosteroids?","a":"Hoarseness of voice (most common) and oropharyngeal candidiasis. Systemic steroids increase the β2-agonist effect in acute exacerbations.","img":null,"pyq":true},{"id":"ph218","subject":"pharmacology","topic":"Anti-asthmatic Drugs","q":"What is the mechanism of theophylline in asthma?","a":"Adenosine A1 receptor antagonism → bronchodilation; PDE3/4 inhibition → anti-inflammatory effect via PDE4 block and histone deacetylase stimulation. Side effects: seizures, arrhythmias (adenosine A1 block), GI upset (PDE4 block).","img":null,"pyq":true},{"id":"ph219","subject":"pharmacology","topic":"Gastrointestinal Drugs","q":"What is the DOC for IBS-associated constipation?","a":"Polyethylene glycol (PEG — osmotic laxative). Lubiprostone (type II chloride channel activator) and linaclotide (guanylate cyclase stimulator) are also used.","img":null,"pyq":true},{"id":"ph220","subject":"pharmacology","topic":"Gastrointestinal Drugs","q":"Compare metoclopramide and domperidone as prokinetics.","a":"Both are D2 antagonists. Metoclopramide crosses the BBB → causes EPS and hyperprolactinaemia. Domperidone does not cross the BBB → no EPS.","img":null,"pyq":true},{"id":"ph221","subject":"pharmacology","topic":"Anticoagulants","q":"What is the DOC for DVT prophylaxis, and what reverses DOACs?","a":"DOACs (apixaban, rivaroxaban, edoxaban for Xa; dabigatran for IIa). Reversal: dabigatran → idarucizumab; oral Xa inhibitors → andexanet alfa.","img":null,"pyq":false},{"id":"ph222","subject":"pharmacology","topic":"Anticoagulants","q":"Compare UFH, LMWH, and fondaparinux in terms of dosing, monitoring, and HIT risk.","a":"UFH: IV for treatment (poor SC bioavailability), monitored by aPTT, highest HIT risk, can be used in renal failure, antidote = protamine sulphate. LMWH: SC for both Rx and prophylaxis, no monitoring, less HIT risk, contraindicated in renal failure, partial protamine reversal. Fondaparinux: SC, no monitoring, no HIT, contraindicated in renal failure, protamine ineffective.","img":null,"pyq":false},{"id":"ph223","subject":"pharmacology","topic":"Anticoagulants","q":"What are the distinctive side effects and antidotes of warfarin?","a":"Side effects: skin necrosis (proteins C and S fall first), purple toe syndrome, teratogenicity (mid-facial hypoplasia, stippled epiphyses). Antidote: vitamin K + 4-factor prothrombin complex > FFP.","img":null,"pyq":true},{"id":"ph224","subject":"pharmacology","topic":"Anticoagulants","q":"What is the DOC for heparin-induced thrombocytopenia (HIT)?","a":"Argatroban (parenteral DTI, monitor aPTT). Alternative: fondaparinux.","img":null,"pyq":false},{"id":"ph225","subject":"pharmacology","topic":"Fibrinolytics","q":"Name the t-PA analogues and their main indication.","a":"Alteplase, reteplase, tenecteplase (most clot-specific). IV route. Main use: STEMI. Main side effect: bleeding. Treatment of fibrinolytic-induced bleeding: tranexamic acid > epsilon-aminocaproic acid.","img":null,"pyq":true},{"id":"ph226","subject":"pharmacology","topic":"Anti-aggregants","q":"Compare clopidogrel and ticagrelor.","a":"Clopidogrel: irreversible P2Y12 blocker; primary prophylaxis of MI and stroke. Ticagrelor: reversible oral P2Y12 blocker; used in acute coronary syndrome and prophylaxis of MI/stroke.","img":null,"pyq":false},{"id":"ph227","subject":"pharmacology","topic":"Anti-aggregants","q":"What is the indication for prasugrel and its key contraindication?","a":"Used in PCI for MI. Contraindicated in stroke/TIA (causes intracranial bleed).","img":null,"pyq":false},{"id":"ph228","subject":"pharmacology","topic":"Immunosuppressants","q":"What is the mechanism of cyclosporine and tacrolimus?","a":"Both are calcineurin inhibitors → reduce IL-2 transcription → suppress T-cell activation. First-line for GVHD. Common side effects: nephrotoxicity, hepatotoxicity, hypertension, hyperkalaemia. Cyclosporine adds: hirsutism, gum hyperplasia, hyperlipidaemia.","img":null,"pyq":false},{"id":"ph229","subject":"pharmacology","topic":"Immunosuppressants","q":"What is mycophenolate mofetil's mechanism?","a":"Blocks IMP dehydrogenase → blocks purine synthesis → selectively suppresses lymphocyte proliferation.","img":null,"pyq":false},{"id":"ph230","subject":"pharmacology","topic":"GnRH-Related Drugs","q":"Explain the paradox of GnRH agonist use in prostate cancer.","a":"Continuous (not pulsatile) GnRH agonist suppresses LH and FSH (receptor downregulation) → reduces testosterone → useful in hormone-sensitive prostate cancer and endometriosis.","img":null,"pyq":false},{"id":"ph231","subject":"pharmacology","topic":"GnRH-Related Drugs","q":"Name the GHRH analogues and their use.","a":"Sermorelin, macimorelin, and tesamorelin — used in the diagnosis of dwarfism (stimulation test). Tesamorelin is also used for HIV-associated lipodystrophy.","img":null,"pyq":true},{"id":"ph232","subject":"pharmacology","topic":"GnRH-Related Drugs","q":"What are somatostatin analogues, their DOC uses, and side effects?","a":"Octreotide, lanreotide, pasireotide. DOC: acromegaly, secretory diarrhoea, glucagonoma, somatostatinoma, VIPoma. Side effects: gallstones, hypothyroidism.","img":null,"pyq":true},{"id":"ph233","subject":"pharmacology","topic":"Emergency Contraception","q":"Compare the three emergency contraceptive agents.","a":"Levonorgestrel (DOC): 1.5 mg single dose within 3 days. Ulipristal (SPRM): 30 mg within 5 days. Mifepristone: 600 mg within 3 days.","img":null,"pyq":false},{"id":"ph234","subject":"pharmacology","topic":"Bisphosphonates","q":"What is the correct way to take oral bisphosphonates to prevent oesophagitis?","a":"Take with a full glass of water on an empty stomach; remain upright for 30 minutes afterwards.","img":null,"pyq":false},{"id":"ph235","subject":"pharmacology","topic":"Vasopressin Analogues","q":"What are desmopressin's main uses?","a":"DOC for central diabetes insipidus and nocturnal enuresis. Also used in von Willebrand disease type 1 and haemophilia A.","img":null,"pyq":false},{"id":"ph236","subject":"pharmacology","topic":"Vasopressin Analogues","q":"What is the DOC for acute variceal bleeding?","a":"Terlipressin (vasopressin analogue). Also: octreotide.","img":null,"pyq":false},{"id":"ph237","subject":"pharmacology","topic":"H1 Blockers","q":"Distinguish first- and second-generation antihistamines.","a":"1st generation: cross BBB (sedative) — used in non-allergic rhinitis, motion sickness, Meniere's disease, and EPS. 2nd generation: non-sedating — DOC for urticaria; treat allergic rhinitis. DOC for allergic rhinitis: intranasal fluticasone (steroid).","img":null,"pyq":false},{"id":"ph238","subject":"pharmacology","topic":"H1 Blockers","q":"What is the DOC for morning sickness in pregnancy?","a":"Doxylamine + vitamin B6.","img":null,"pyq":false},{"id":"ph239","subject":"pharmacology","topic":"H1 Blockers","q":"What is cyproheptadine's special use?","a":"DOC for serotonin syndrome (5-HT2 blocker).","img":null,"pyq":false},{"id":"ph240","subject":"pharmacology","topic":"Antiepileptic Drugs","q":"What is the DOC for Lennox-Gastaut syndrome?","a":"Valproate (DOC). Add-ons: topiramate, lamotrigine, rufinamide.","img":null,"pyq":false},{"id":"ph241","subject":"pharmacology","topic":"Multiple Myeloma Treatment","q":"Which drugs are used to treat multiple myeloma?","a":"Bortezomib (proteasome inhibitor), thalidomide/lenalidomide (immunomodulatory), melphalan + prednisolone; daratumumab (anti-CD38) for refractory disease. Autologous stem-cell transplant is the definitive treatment.","img":null,"pyq":true},{"id":"ph242","subject":"pharmacology","topic":"Aspirin-Induced Asthma","q":"What is the mechanism of aspirin-induced asthma?","a":"Aspirin inhibits COX, blocking prostaglandin E2 synthesis. This diverts arachidonic acid to the lipoxygenase pathway, producing excess leukotrienes (LTC4, LTD4) that cause bronchoconstriction. Management: avoid NSAIDs; use paracetamol for analgesia; montelukast (leukotriene blocker) is particularly useful.","img":null,"pyq":true},{"id":"ph243","subject":"pharmacology","topic":"Chemotherapy for ALL","q":"What is the treatment regimen for Acute Lymphoblastic Leukaemia (ALL)?","a":"Vincristine + prednisolone + asparaginase + daunorubicin (VPAD). Induction achieves remission; maintenance with methotrexate and 6-mercaptopurine. CNS prophylaxis with intrathecal methotrexate.","img":null,"pyq":true},{"id":"ph244","subject":"pharmacology","topic":"Post-operative Nausea & Vomiting","q":"What drugs are used to prevent and treat post-operative nausea and vomiting (PONV)?","a":"First choice: ondansetron (5-HT3 antagonist) ± dexamethasone. Also: metoclopramide, droperidol, scopolamine patch. H2 blockers (e.g., ranitidine) are DOC for prophylaxis of aspiration pneumonitis in post-operative patients.","img":null,"pyq":true},{"id":"ph245","subject":"pharmacology","topic":"Irritable Bowel Syndrome","q":"What are the drug treatments for IBS based on the predominant symptom?","a":"IBS-C (constipation): polyethylene glycol, linaclotide, lubiprostone. IBS-D (diarrhoea): loperamide, alosetron (females), rifaximin. IBS with pain/spasm: antispasmodics (dicyclomine, hyoscine). Antidepressants (TCAs, SSRIs) are used for global IBS symptoms.","img":null,"pyq":true},{"id":"ph246","subject":"pharmacology","topic":"TB Preventive Therapy","q":"What is tuberculosis preventive therapy (TPT)?","a":"Isoniazid (INH) 300 mg daily for 6 months is the standard regimen. Alternatives: INH + rifapentine once weekly for 3 months (3HP), or INH + rifampicin daily for 3 months. Pyridoxine (vitamin B6) is co-administered to prevent INH-induced neuropathy.","img":null,"pyq":true},{"id":"ph247","subject":"pharmacology","topic":"Raised Intracranial Pressure","q":"What are the drugs used to lower raised intracranial pressure (ICP)?","a":"DOC: mannitol (osmotic diuretic, 20% IV). Also: hypertonic saline, acetazolamide (for benign intracranial hypertension). Dexamethasone for oedema around tumours or abscess. Furosemide as adjunct. Glycerol (oral) for mild cases.","img":null,"pyq":true},{"id":"ph248","subject":"pharmacology","topic":"Vitamin B3 (Niacin)","q":"What is niacin's mechanism as a lipid-lowering drug, and what is its major side effect?","a":"Inhibits hormone-sensitive lipase in adipose tissue → reduces FFA delivery to liver → lowers VLDL and triglycerides and maximally raises HDL. Major side effect: cutaneous flushing (prostaglandin-mediated — reduced by aspirin pretreatment). Also causes hepatotoxicity and insulin resistance.","img":null,"pyq":true},{"id":"ph249","subject":"pharmacology","topic":"Atropine Uses","q":"Describe the uses of atropine.","a":"Bradycardia (DOC at doses >0.5 mg), AV block (digoxin toxicity), pre-anaesthetic (reduces secretions), reversal of organophosphate poisoning (with pralidoxime), cycloplegia (dilates pupil for fundal examination). Also used in PSVT-related sinus bradycardia.","img":null,"pyq":true},{"id":"ph250","subject":"pharmacology","topic":"Clotrimazole","q":"What are the uses and route of administration of clotrimazole?","a":"Topical azole antifungal used for: oral candidiasis (lozenge/troche), vaginal candidiasis (pessary/cream), and tinea infections (topical cream). MOA: inhibits 14-α sterol demethylase → disrupts fungal cell-membrane ergosterol synthesis.","img":null,"pyq":true},{"id":"ph251","subject":"pharmacology","topic":"PPH Management","q":"What is the drug management of postpartum haemorrhage (PPH)?","a":"First line: oxytocin IV infusion (uterotonic). Second line: ergometrine (ergot alkaloid), carboprost (PGF2α — contraindicated in asthma), misoprostol (PGE1, oral/rectal). Tranexamic acid reduces mortality. For refractory PPH: balloon tamponade or surgical intervention.","img":null,"pyq":true},{"id":"ph252","subject":"pharmacology","topic":"Aspirin Toxicity","q":"What is the presentation and management of aspirin (salicylate) toxicity?","a":"Clinical features: tinnitus, hyperventilation → respiratory alkalosis → metabolic acidosis (mixed acid-base), hyperpyrexia. Management: urine alkalinisation with IV sodium bicarbonate (traps ionised salicylate in urine → increases excretion). Haemodialysis for severe toxicity (salicylate >700 mg/L).","img":null,"pyq":true},{"id":"ph253","subject":"pharmacology","topic":"Rebound Hypertension","q":"What causes rebound hypertension and how is it managed?","a":"Most classically caused by abrupt clonidine withdrawal (α2-receptor downregulation → surge in noradrenaline). Management: phentolamine (DOC for clonidine-withdrawal HTN and hypertensive crisis in phaeochromocytoma). Reinstate clonidine then taper slowly to prevent.","img":null,"pyq":true},{"id":"ph254","subject":"pharmacology","topic":"Allopurinol","q":"What is allopurinol's mechanism, uses, and important side effects?","a":"Inhibits xanthine oxidase → reduces uric acid synthesis. DOC for chronic gout and hyperuricaemia in solid tumours. Side effects: Stevens-Johnson syndrome (associated with HLA-B*5801), xanthine stones. Drug interaction: potentiates azathioprine/6-MP toxicity (both metabolised by xanthine oxidase) — reduce their doses by 75%.","img":null,"pyq":true},{"id":"ph255","subject":"pharmacology","topic":"Chemotherapy-Induced Thrombocytopenia","q":"How is chemotherapy-induced thrombocytopenia managed?","a":"Platelet transfusion for acute bleeding. Thrombopoietin receptor agonists for ITP: eltrombopag and romiplostim. IL-11 analogue oprelvekin is specifically used for chemotherapy-induced thrombocytopenia. Avatrombopag and lusutrombopag are used to reduce bleeding risk before invasive procedures in liver cirrhosis.","img":null,"pyq":true},{"id":"ph256","subject":"pharmacology","topic":"Atropine Toxicity","q":"What are the features and management of atropine (anticholinergic) toxicity?","a":"Features (mnemonic: Dry as a bone, blind as a bat, red as a beet, hot as a hare, mad as a hatter): dry mouth, urinary retention, constipation, tachycardia, mydriasis, hyperthermia, dry skin, hallucinations/delirium. Management: physostigmine (DOC — reverses central and peripheral anticholinergic effects by inhibiting acetylcholinesterase).","img":null,"pyq":true},{"id":"ph257","subject":"pharmacology","topic":"Vitamin K Deficiency","q":"What factors and clotting studies are affected by vitamin K deficiency?","a":"Vitamin K is required for gamma-carboxylation of factors II, VII, IX, X, and proteins C and S. Deficiency → prolonged PT/INR (factor VII has shortest half-life, affected first) and prolonged aPTT. Causes: neonates (DOC for prophylaxis: IM vitamin K at birth), malabsorption, long-term antibiotics, warfarin therapy.","img":null,"pyq":true},{"id":"ph258","subject":"pharmacology","topic":"Digibind / Digoxin Toxicity","q":"What is digibind and when is it used?","a":"Digibind (digoxin-specific antibody fragments) is the antidote for life-threatening digoxin toxicity. Conditions that increase digoxin toxicity risk (mnemonic KMC in Manipal Rocks): Hypokalaemia, Hypomagnesaemia, Hypercalcaemia, MI, Renal failure. Most common arrhythmia in toxicity: ventricular bigeminy; most characteristic: atrial tachycardia with AV block.","img":null,"pyq":true},{"id":"ph259","subject":"pharmacology","topic":"Hyperkalaemia","q":"Which drugs are used to treat acute hyperkalaemia?","a":"1. Calcium gluconate IV (membrane stabiliser — acts within minutes). 2. Insulin + glucose (shifts K⁺ into cells). 3. Sodium bicarbonate (shifts K⁺ intracellularly). 4. Salbutamol nebulisation (β2 → K⁺ uptake). 5. Ion-exchange resins (patiromer, sodium zirconium cyclosilicate) for long-term. 6. Dialysis for severe/refractory cases.","img":null,"pyq":true},{"id":"ph260","subject":"pharmacology","topic":"Acromegaly Treatment","q":"How is acromegaly managed pharmacologically?","a":"First line: somatostatin analogues (octreotide, lanreotide, pasireotide) — DOC for acromegaly. Second line: GH receptor antagonist pegvisomant for resistant cases. Dopamine agonists (bromocriptine, cabergoline) can also reduce GH. Definitive treatment: transsphenoidal surgery.","img":null,"pyq":true},{"id":"ph261","subject":"pharmacology","topic":"Vitamin B6 (Pyridoxine)","q":"What is vitamin B6 used for in pharmacology?","a":"1. Antidote for isoniazid toxicity (replenishes pyridoxine depleted by INH → prevents neuropathy and seizures). 2. Prevention of hand-foot syndrome from capecitabine/5-FU. 3. Treatment of morning sickness (combined with doxylamine as DOC). 4. Sideroblastic anaemia treatment. 5. Pyridoxine-dependent epilepsy.","img":null,"pyq":true},{"id":"ph262","subject":"pharmacology","topic":"Botulinum Toxin","q":"What is botulinum toxin's mechanism and its medical uses?","a":"Blocks presynaptic release of acetylcholine at the neuromuscular junction (cleaves SNARE proteins). Causes flaccid paralysis. Medical uses: cervical dystonia, blepharospasm, spasticity (cerebral palsy), hyperhidrosis, cosmetic (wrinkles), overactive bladder, chronic migraine prevention, achalasia. Also used for strabismus. Note: aminoglycosides also block presynaptic Ca²⁺ channels → reduce ACh release — additive effect.","img":null,"pyq":true}]};